INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (19, 'OPERATION', '邻接矩阵表示法', '用二维数组表示图中顶点之间的关系。\n对于无向图，若顶点 i 和 j 之间有边，则 matrix[i][j] = matrix[j][i] = 1，否则为 0。\n对于有向图，若从 i 到 j 有弧，则 matrix[i][j] = 1。\n适合存储稠密图，空间复杂度 O(n²)，判断两顶点间是否有边的时间复杂度为 O(1)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (19, 'OPERATION', '邻接表表示法', '对每个顶点建立一个单链表，存储与该顶点相邻接的所有顶点。\n无向图中，顶点 v 的链表包含所有与 v 相连的顶点；有向图中，链表包含从 v 出发能到达的顶点。\n适合存储稀疏图，空间复杂度 O(n+e)，其中 n 为顶点数，e 为边数。\n查找某顶点的邻接点效率高，但判断两顶点间是否有边需遍历链表。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (19, 'COMPLEXITY', '存储结构复杂度对比', '邻接矩阵:\n- 空间复杂度:O(n²)，与边数无关\n- 判断边是否存在:O(1)\n- 获取顶点的度:O(n)\n- 适合稠密图\n\n邻接表:\n- 空间复杂度:O(n+e)\n- 判断边是否存在:O(degree)\n- 获取顶点的度:O(1)（若维护度计数器）\n- 适合稀疏图', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (20, 'OPERATION', '深度优先搜索（DFS）', '从起始顶点出发，沿一条路径一直访问下去，直到无法继续，然后回溯到上一个顶点，继续访问其他未访问的邻接点。\n递归实现:访问当前顶点，标记为已访问，然后递归访问所有未访问的邻接点。\n非递归实现:使用栈，将起始顶点入栈，每次取出栈顶顶点，若未访问则访问并入栈其邻接点。\n遍历序列不唯一，取决于访问邻接点的顺序。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (20, 'OPERATION', '广度优先搜索（BFS）', '从起始顶点出发，先访问所有邻接点，然后再依次访问这些邻接点的邻接点，层次式扩展。\n使用队列实现:起始顶点入队，每次取出队首顶点并访问，将其未访问的邻接点入队。\n适合求解最短路径问题（无权图），遍历序列不唯一。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (20, 'COMPLEXITY', '遍历算法复杂度', 'DFS 和 BFS 的时间复杂度相同:\n- 邻接矩阵存储:O(n²)，需要遍历矩阵的行\n- 邻接表存储:O(n+e)，每个顶点和每条边各访问一次\n\n空间复杂度:\n- DFS:O(n)，递归栈深度或显式栈空间\n- BFS:O(n)，队列空间\n\n两者都能遍历图中所有可达顶点，时间复杂度相同，但应用场景不同。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (21, 'OPERATION', 'Dijkstra 算法', '用于求解单源最短路径，即从源点到图中所有其他顶点的最短路径。\n贪心策略:每次选择距离源点最近且未访问过的顶点，更新其邻接点的距离。\n要求图中边的权值非负。\n使用优先队列优化后，时间复杂度为 O((n+e)log n)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (21, 'OPERATION', 'Floyd 算法', '用于求解所有顶点对之间的最短路径。\n动态规划思想:逐步考虑每个中间顶点，更新任意两点间的最短距离。\n三重循环，时间复杂度 O(n³)，适合小规模图或稠密图。\n可以处理负权边，但不能处理负权回路。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (21, 'COMPLEXITY', '最短路径算法复杂度', 'Dijkstra 算法:\n- 时间复杂度:O(n²)（朴素实现）或 O((n+e)log n)（优先队列优化）\n- 空间复杂度:O(n)\n- 适用:单源最短路径，边权非负\n\nFloyd 算法:\n- 时间复杂度:O(n³)\n- 空间复杂度:O(n²)\n- 适用:所有顶点对最短路径，可处理负权边', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (22, 'OPERATION', 'Prim 算法', '贪心策略:从任意顶点开始，每次选择连接已选顶点集和未选顶点集的最小权值边，将该边连接的未选顶点加入已选集。\n适合稠密图，使用邻接矩阵存储时时间复杂度为 O(n²)。\n使用优先队列优化后，时间复杂度为 O((n+e)log n)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (22, 'OPERATION', 'Kruskal 算法', '贪心策略:将所有边按权值从小到大排序，依次选择最小边，若该边连接的两个顶点不在同一连通分量中，则加入生成树。\n使用并查集判断顶点是否在同一连通分量。\n适合稀疏图，时间复杂度 O(e log e)。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (22, 'COMPLEXITY', '最小生成树算法复杂度', 'Prim 算法:\n- 时间复杂度:O(n²)（朴素实现）或 O((n+e)log n)（优先队列优化）\n- 空间复杂度:O(n)\n- 适合稠密图\n\nKruskal 算法:\n- 时间复杂度:O(e log e)，主要消耗在边排序\n- 空间复杂度:O(n)，并查集空间\n- 适合稀疏图\n\n两种算法都能得到相同的最小生成树权值和，但树的形态可能不同。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (27, 'OPERATION', '直接插入排序', '将序列划分为已排序区和未排序区。\n每次从无序区取一个元素，在有序区从后向前扫描并插入合适位置。\n最好情况:序列已有序，仅需比较 n-1 次。\n最坏情况:序列逆序，每个元素都需移动。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (27, 'COMPLEXITY', '复杂度分析', '- 最好时间复杂度:O(n)\n- 最坏时间复杂度:O(n²)\n- 平均时间复杂度:O(n²)\n- 空间复杂度:O(1)\n- 稳定性:稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (27, 'OPERATION', '折半插入排序', '在直接插入排序的基础上，使用二分查找确定插入位置。\n减少了关键字比较次数，但元素移动次数不变。\n比较次数约为 O(n log n)，移动次数仍为 O(n²)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (27, 'COMPLEXITY', '复杂度分析', '- 时间复杂度:O(n²)\n- 比较次数:O(n log n)\n- 移动次数:O(n²)\n- 空间复杂度:O(1)\n- 稳定性:稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (27, 'OPERATION', '链表插入排序', '对单链表进行插入排序。\n每次从原链表取一个结点，插入到已排序链表的合适位置。\n不需要移动元素，只修改指针。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (27, 'COMPLEXITY', '复杂度分析', '- 时间复杂度:O(n²)\n- 空间复杂度:O(1)\n- 稳定性:稳定排序\n- 适合链式存储', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (27, 'OPERATION', '希尔排序', '是插入排序的改进版。\n引入增量序列，先远距离分组排序。\n逐步缩小增量，最终增量为 1 时进行直接插入排序。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (27, 'COMPLEXITY', '复杂度分析', '- 最好时间复杂度:O(n^1.3)\n- 最坏时间复杂度:O(n²)\n- 平均时间复杂度:O(n log² n)\n- 空间复杂度:O(1)\n- 稳定性:不稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (28, 'OPERATION', '冒泡排序', '反复比较相邻元素，顺序错误则交换。\n每趟将最大元素“冒泡”到末尾。\n可加入交换标志提前结束。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (28, 'COMPLEXITY', '复杂度分析', '- 最好时间复杂度:O(n)\n- 最坏时间复杂度:O(n²)\n- 平均时间复杂度:O(n²)\n- 空间复杂度:O(1)\n- 稳定性:稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (28, 'OPERATION', '快速排序', '选基准元素 pivot。\n通过划分将小于 pivot 的放左边，大于的放右边。\n递归处理左右子序列。\n划分方式影响性能。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (28, 'COMPLEXITY', '复杂度分析', '- 最好时间复杂度:O(n log n)\n- 最坏时间复杂度:O(n²)\n- 平均时间复杂度:O(n log n)\n- 空间复杂度:递归栈 O(log n) ～ O(n)\n- 稳定性:不稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (28, 'OPERATION', '三数取中快速排序', '选择左、中、右三个元素的中值作为枢轴。\n避免对已排序序列产生最坏情况。\n划分采用双向扫描，减少交换次数。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (28, 'COMPLEXITY', '复杂度分析', '- 最坏时间复杂度:O(n²)（概率极低）\n- 平均时间复杂度:O(n log n)\n- 空间复杂度:递归栈 O(log n)\n- 稳定性:不稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (28, 'OPERATION', '计数排序', '统计每个值出现次数。\n计算前缀和得到元素位置。\n反向填充结果数组。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (28, 'COMPLEXITY', '复杂度分析', '- 时间复杂度:O(n + k)\n- 空间复杂度:O(k)\n- 稳定性:稳定排序\n- 适用:整数、范围小', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (29, 'OPERATION', '简单选择排序', '每趟从未排序区选最小元素，与未排序区首元素交换。\n比较次数固定，与初始序列无关。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (29, 'COMPLEXITY', '复杂度分析', '- 时间复杂度:O(n²)\n- 空间复杂度:O(1)\n- 稳定性:不稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (29, 'OPERATION', '堆排序', '将序列建成大顶堆。\n每次取堆顶（最大值）放到末尾。\n调整剩余元素为新的堆。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (29, 'COMPLEXITY', '复杂度分析', '- 建堆时间复杂度:O(n)\n- 排序时间复杂度:O(n log n)\n- 空间复杂度:O(1)\n- 稳定性:不稳定排序\n- 适合嵌入式 / 实时系统', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (29, 'OPERATION', '桶排序', '将数据分到有限个桶中。\n每个桶内单独排序（常用插入排序）。\n再按桶顺序合并。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (29, 'COMPLEXITY', '复杂度分析', '- 平均时间复杂度:O(n)\n- 最坏时间复杂度:O(n²)\n- 空间复杂度:O(n)\n- 稳定性:取决于桶内排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (30, 'OPERATION', '二路归并排序', '采用分治法，将序列不断二分。\n递归排序左右子序列。\n合并两个有序序列。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (30, 'COMPLEXITY', '复杂度分析', '- 时间复杂度:O(n log n)\n- 空间复杂度:O(n)\n- 稳定性:稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (30, 'OPERATION', '多路归并排序', '用于外部排序。\n同时归并多个有序段。\n减少 I/O 次数。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (30, 'COMPLEXITY', '复杂度分析', '- 时间复杂度:O(n log_k n)\n- 空间复杂度:O(k)\n- 稳定性:稳定排序\n- 适合海量数据', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (30, 'OPERATION', '基数排序', '按个位、十位、百位……依次排序。\n低位优先（LSD）最常用。\n每一轮使用稳定排序。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (30, 'COMPLEXITY', '复杂度分析', '- 时间复杂度:O(d · (n + k))\n- 空间复杂度:O(n + k)\n- 稳定性:稳定排序', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (23, 'OPERATION', '查找的基本概念', '查找（Search）是在数据集合中定位满足条件的数据元素的过程，核心问题是:给定关键字 key，判断其是否存在，或返回其位置。\n查找结果分为两类:查找成功（找到目标，返回下标或指针）；查找失败（未找到，常返回 -1 或特殊标记）。\n按数据是否变化分为:静态查找（只查不改，如字典检索）；动态查找（查找同时伴随插入、删除，如通讯录维护）。\n查找是检索、索引、推荐、登录校验等功能的共同基础。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (23, 'OPERATION', '平均查找长度 ASL', '平均查找长度（Average Search Length, ASL）是衡量查找算法效率的重要指标，表示查找过程中关键字比较次数的期望值。\n对成功查找:ASL_success = Σ P_i × C_i，其中 P_i 为第 i 个元素被查找的概率，C_i 为找到该元素所需的比较次数。\n对失败查找:需统计查找不命中时的比较次数期望。\nASL 越小，平均性能越好；分析时应区分成功与失败两种情形。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (23, 'OPERATION', '顺序查找基本思想', '顺序查找（Sequential Search）从表的一端开始，将当前元素的关键字与目标关键字逐个比较。\n若相等则查找成功并返回位置；若当前元素不相等，则继续检查下一个元素。\n若扫描到表尾仍未命中，则查找失败。\n该算法对存储结构要求低，数组、链表均可；对数据是否有序没有硬性要求，实现最直观。\n示例:在花名册上从上到下点名找人。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (23, 'OPERATION', '哨兵优化', '在数组实现中，可在表尾设置哨兵:将目标值复制到数组末尾额外位置（或利用原表最后一格），循环中只需比较元素是否等于目标，无需每次判断下标是否越界。\n当目标存在于表中时，比较会在命中处结束；当目标不存在时，比较会在哨兵处结束。\n哨兵法减少分支判断次数，常数因子更小，但需额外一个存储单元。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (23, 'OPERATION', '有序表上的提前终止', '若顺序表按关键字有序，当当前元素已大于目标值时，后续元素更大，不可能再命中，可提前结束查找。\n这是顺序查找在有序数据上的一种小优化，但仍不如二分查找高效。\n链表因不支持随机访问，通常只能从头结点逐个后移，天然适配顺序扫描。', 4);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (23, 'COMPLEXITY', '各类查找算法复杂度对比', '| 方法 | 平均时间 | 最坏时间 | 空间 | 前提条件 |\n|------|----------|----------|------|----------|\n| 顺序查找 | O(n) | O(n) | O(1) | 几乎无 |\n| 二分查找 | O(log n) | O(log n) | O(1) | 有序或单调 |\n| 哈希查找 | O(1)* | O(n) | O(n) | 哈希函数、冲突处理 |\n| BST 查找 | O(log n) | O(n) | O(n) | 树结构 |\n| AVL 查找 | O(log n) | O(log n) | O(n) | 平衡维护 |\n*哈希为平均复杂度，冲突严重时退化。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (23, 'COMPLEXITY', '顺序查找性能分析', '设表长为 n:\n最好情况:目标在第一个位置，比较 1 次，O(1)。\n最坏情况:目标不存在或位于末尾，比较 n 次，O(n)。\n平均情况:等概率假设下，成功查找平均约 n/2 次比较；失败需 n 次或 n+1 次。\n空间复杂度:O(1)，仅需常数个辅助变量。\n适用场景:数据量小、数据无序、只偶尔查一次、实现成本优先。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (23, 'COMPLEXITY', '顺序查找复杂度', '查找成功时，若每个元素被查到的概率相同，平均查找长度 ASL_success = (n + 1) / 2。\n查找失败时，需要比较全部 n 个元素；若采用哨兵从尾向前查找，通常还会比较到 0 号哨兵。\n时间复杂度为 O(n)，空间复杂度为 O(1)。\n顺序查找简单、适用面广，但在大规模数据中效率较低。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (24, 'OPERATION', '二分查找基本思想', '二分查找（Binary Search）要求查找区间内的数据按关键字有序（或满足单调性）。\n每次取区间中点元素 mid 与目标比较:若相等则成功；若目标更小，则在左半区间继续；若更大，则在右半区间继续。\n每轮比较后区间长度约减半，最多约 log₂n 轮即可确定结果。\n示例:在按学号排序的名单中查找某学号。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (24, 'OPERATION', '区间与边界', '实现前需统一区间含义，常见两种:\n左闭右闭 [left, right]:循环条件 left <= right，mid = left + (right - left) / 2。\n左闭右开 [left, right):循环条件 left < right。\nmid 建议用 left + (right - left) / 2，避免 (left + right) 整数溢出。\n未命中时，可返回 -1，或返回“应插入位置”以维护有序表。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (24, 'OPERATION', '二分查找变体', '在重复元素中常需找边界而非任意一次命中:\n首个等于 target:找最左可行位置（lower_bound 思想）。\n最后等于 target:找最右可行位置。\n首个大于等于 target / 最后小于等于 target:用于分段、分数线、排名等场景。\n“二分答案”:当问题具有单调可行性时，对答案空间二分而非对下标二分。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (24, 'COMPLEXITY', '二分查找性能与常见错误', '时间复杂度:O(log n)；空间复杂度:迭代实现 O(1)，递归实现 O(log n) 栈空间。\n常见错误:数据未排序仍使用二分；left/right 更新遗漏导致死循环；边界 off-by-one；mid 溢出。\n调试时可打印每轮的 left、right、mid 验证区间收缩是否正确。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (24, 'COMPLEXITY', '二分查找复杂度', '每次比较后查找区间约缩小一半，因此最坏比较次数约为 floor(log2 n) + 1。\n时间复杂度为 O(log n)。\n迭代版本空间复杂度为 O(1)，递归版本空间复杂度为 O(log n)。\n二分查找适用于有序数组，不适合普通链表，因为链表无法 O(1) 访问中间元素。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (25, 'OPERATION', '哈希查找基本思想', '哈希查找通过哈希函数 H(key) 将关键字映射到存储地址，理想情况下可直接定位，无需逐个比较。\n核心步骤:计算地址 → 访问槽位 → 若冲突则按策略继续探测。\n平均时间接近 O(1)，属于“空间换时间”的典型方案。\n示例:用户名查账户、缓存 key 查 value、单词查释义。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (25, 'OPERATION', '哈希函数与冲突', '好的哈希函数应计算快、分布尽量均匀。常用方法:除留余数法（key mod m）、乘法散列、字符串滚动哈希等。\n冲突（Collision）指不同关键字映射到同一槽位，必须处理否则无法正确查找。\n开放定址法:在表内按探测序列找下一个空位（线性探测、二次探测、双重散列）。\n链地址法:每个槽位挂链表存放所有冲突元素，删除较方便。\n再哈希法:冲突时用第二个哈希函数重新计算地址。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (25, 'OPERATION', '装填因子与扩容', '装填因子 α = 元素个数 / 表长，α 越大冲突越多，查找越慢。\n开放定址法在 α 接近 1 时性能急剧下降，常设阈值（如 0.7~0.75）触发扩容。\n扩容需重新计算所有元素位置（重哈希），一次性成本高，但均摊后仍高效。\n开放定址删除常用“墓碑”标记，避免探测链断裂。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (25, 'COMPLEXITY', '哈希查找性能分析', '平均情况:冲突较少时，查找、插入、删除均可视为 O(1)。\n最坏情况:大量冲突或恶意构造数据时退化为 O(n)。\n链地址法删除友好；开放定址法节省指针但删除与聚集问题更复杂。\n与树表对比:哈希不保证关键字有序，不适合范围遍历；树表支持有序遍历与区间查询。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (25, 'COMPLEXITY', '哈希表复杂度', '在哈希函数设计合理、负载因子适当的情况下，插入、删除和查找的平均时间复杂度为 O(1)。\n若大量关键字集中到少数桶中，最坏时间复杂度可能退化为 O(n)。\n空间复杂度为 O(m + n)，其中 m 是哈希表桶数，n 是元素个数。\n哈希表适合等值查找，不适合天然支持有序遍历和范围查询。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (26, 'OPERATION', '二叉排序树查找', '二叉排序树（BST）满足:左子树所有关键字 < 根 < 右子树所有关键字。\n查找从根开始:若目标等于根，成功；若更小进入左子树，否则进入右子树，直到命中或走到空指针。\n插入、删除后仍需保持 BST 性质；按有序序列依次插入可能使树退化为链表，最坏查找 O(n)。\n树高越低，查找路径越短，平均性能越好。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (26, 'OPERATION', '平衡二叉树（AVL）查找', 'AVL 树在 BST 基础上要求任意节点左右子树高度差（平衡因子）的绝对值不超过 1。\n插入或删除后若失衡，通过旋转恢复平衡:LL、RR 单旋；LR、RL 双旋。\n平衡后树高为 O(log n)，查找、插入、删除的最坏时间均为 O(log n)，性能更稳定。\n适用于频繁增删且仍需高效查找的场景，如动态有序索引。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (26, 'OPERATION', 'B 树与 B+ 树查找', 'B 树是多路平衡查找树，结点可包含多个关键字，适合磁盘等块存储:减少 I/O 次数。\nB+ 树非叶结点仅作索引，数据记录集中在叶结点，叶结点常链成有序链表，便于范围扫描。\n数据库索引（如 InnoDB）广泛采用 B+ 树，在大量数据下保持 O(log n) 级查找。\n与内存中的 BST/AVL 相比，B+ 树针对“块读”优化，是外存查找的典型结构。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (26, 'OPERATION', '选型口诀与决策因素', '实用选型可参考:\n无序、数据量小、偶尔查一次 → 顺序查找；\n有序、静态、少改动 → 二分查找；\n高频精确键查询、不要求有序 → 哈希查找；\n频繁增删且需有序遍历或区间查询 → BST / AVL / B+ 树等树表。\n决策因素包括:数据规模 n、是否有序、更新频率、内存限制、是否需要范围查询、实现与维护成本。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (26, 'OPERATION', '典型业务场景', '顺序查找:短待办列表、小规模日志片段关键字扫描。\n二分查找:排序词典、成绩达标线、静态排行榜名次。\n哈希查找:登录用户名查账户、缓存、字典映射。\n树表查找:动态价格索引、订单按时间/金额区间检索；数据库主键索引常用 B+ 树。\n实际系统常组合多种结构:如先哈希定位用户，再在有序子集上二分筛范围。', 4);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (26, 'COMPLEXITY', '树表查找复杂度', 'BST 平均查找长度与树高 h 相关，比较次数约为 h；AVL 保证 h = O(log n)。\n查找复杂度与树高线性相关，与结点总数 n 的关系通过 h 体现:平衡时 O(log n)，退化时 O(n)。\nB 树/B+ 树通过增大结点扇出降低树高，磁盘场景下以 I/O 次数衡量效率。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (26, 'COMPLEXITY', '综合对比与权衡', '没有“绝对最优”的查找算法，只有“最适合当前数据特征”的选择。\n哈希平均最快但无序且依赖冲突处理质量；二分实现简单但要求有序；树表兼顾动态与有序但实现复杂。\n评估时除渐近复杂度外，还应考虑常数因子、缓存友好性、工程可维护性与最坏情况是否可接受。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (26, 'COMPLEXITY', 'B树与B+树复杂度', '设每个结点最多有 m 个孩子，元素总数为 n，则树高约为 O(log_m n)。\n查找、插入、删除通常都需要沿根到叶的一条路径进行，时间复杂度为 O(log_m n)。\n由于一个结点可以对应一个磁盘页，B树和B+树能显著减少外存访问次数。\nB+树在范围查询中更有优势，因为叶子结点顺序相连。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (15, 'OPERATION', '二叉树的链式存储结构', '二叉树每个结点包含数据域、左孩子指针、右孩子指针。\nn个结点的二叉链表中，共有2n个指针域，其中n-1个指向孩子结点，n+1个为空指针域。\n利用这些空指针域可构造线索二叉树，加速遍历。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (15, 'OPERATION', '先序遍历（根左右）', '访问根结点→先序遍历左子树→先序遍历右子树。\n递归实现最直观；非递归实现借助栈，先将根入栈，每次出栈访问后依次将右孩子、左孩子入栈（确保左孩子先出栈）。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (15, 'OPERATION', '中序遍历（左根右）', '中序遍历左子树→访问根结点→中序遍历右子树。\n对二叉搜索树进行中序遍历，得到有序序列。\n非递归实现:沿左链一路到底并入栈，出栈访问后转向右子树，重复此过程。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (15, 'OPERATION', '后序遍历（左根右）', '后序遍历左子树→后序遍历右子树→访问根结点。\n应用场景:计算目录大小（先算子目录再算父目录）、表达式树求值。\n非递归实现较复杂，常用双栈法或标记法。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (15, 'OPERATION', '层序遍历', '从上到下、从左到右逐层访问结点。\n借助队列实现:根入队，每次出队访问后将左右孩子入队。\n常用于求二叉树宽度、判断完全二叉树等场景。', 4);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (15, 'COMPLEXITY', '时间复杂度与空间复杂度', '四种遍历均访问每个结点恰好一次，时间复杂度均为O(n)。\n递归遍历空间复杂度O(h)，h为树高，最坏情况单支树退化为O(n)。\n层序遍历空间复杂度O(w)，w为树的最大宽度，最坏情况满二叉树最后一层约n/2个结点，O(n)。\n链式存储空间复杂度O(n)，每个结点占用常量空间。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (16, 'OPERATION', '查找操作', '从根结点开始，若目标值等于当前结点值，查找成功；若目标值小于当前结点值，递归查找左子树；若大于，递归查找右子树。\n查找过程形成一条从根到目标结点的路径，比较次数不超过树的高度。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (16, 'OPERATION', '插入操作', '先执行查找，若关键字已存在则插入失败（或根据需求更新）。\n若不存在，查找失败的位置即为新结点的插入位置。\n新结点一定作为叶子结点插入，不会破坏已有结构。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (16, 'OPERATION', '删除操作', '分三种情况:(1)被删结点为叶子，直接删除；(2)被删结点只有左子树或只有右子树，用其孩子替代；(3)被删结点有左右子树，用其直接前驱（左子树最大结点）或直接后继（右子树最小结点）替换，再删除该前驱/后继。\n第三种情况转化为前两种情况之一。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (16, 'COMPLEXITY', '时间复杂度与空间复杂度', '查找、插入、删除的平均时间复杂度为O(log n)，但最坏情况（插入有序序列形成单支树）退化为O(n)。\n查找、插入的递归实现空间复杂度O(h)，最坏O(n)。\n中序遍历可得到有序序列，时间复杂度O(n)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (17, 'OPERATION', '平衡因子与旋转', '平衡因子 = 左子树高度 - 右子树高度。AVL树要求所有结点平衡因子绝对值不超过1。\n插入或删除后，从被修改结点向上回溯，找到第一个失衡结点，对其进行旋转调整。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (17, 'OPERATION', 'LL旋转（右单旋）', '失衡结点A的平衡因子为2，其左孩子B的平衡因子为1。\n将B提升为子树根，A变为B的右孩子，B的原右子树变为A的左子树。\n旋转后A和B的平衡因子均归0。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (17, 'OPERATION', 'RR旋转（左单旋）', '失衡结点A的平衡因子为-2，其右孩子B的平衡因子为-1。\n将B提升为子树根，A变为B的左孩子，B的原左子树变为A的右子树。\n旋转后A和B的平衡因子均归0。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (17, 'OPERATION', 'LR旋转（先左后右双旋）', '失衡结点A的平衡因子为2，其左孩子B的平衡因子为-1。\n先在B处做左旋（变为LL型），再在A处做右旋。\n新根为B的右孩子C，C的左子树变为B的右子树，C的右子树变为A的左子树。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (17, 'OPERATION', 'RL旋转（先右后左双旋）', '失衡结点A的平衡因子为-2，其右孩子B的平衡因子为1。\n先在B处做右旋（变为RR型），再在A处做左旋。\n新根为B的左孩子C，C的左子树变为A的右子树，C的右子树变为B的左子树。', 4);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (17, 'COMPLEXITY', '时间复杂度与空间复杂度', '含有n个结点的AVL树，最大高度约为1.44×log₂(n+1)，最坏高度仍为O(log n)级别。\n查找、插入、删除时间复杂度均为O(log n)，旋转操作只需修改少量指针，时间O(1)。\n空间复杂度O(log n)（递归调用栈），每个结点额外存储高度或平衡因子，O(1)空间开销。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (18, 'OPERATION', '哈夫曼树构建', '给定n个带权叶子结点，构建最优二叉树（WPL最小）。\n(1)将每个结点视为一棵单结点树，全部放入最小堆；(2)每次从堆中取出两棵根权值最小的树，合并为一棵新树（新根权值为两子树根权值之和）；(3)将新树放回堆中；(4)重复直到堆中只剩一棵树，即哈夫曼树。\n构建过程共需n-1次合并。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (18, 'OPERATION', '哈夫曼编码', '从根到叶子，左分支标记为0，右分支标记为1（或反过来），路径上的标记序列即为该叶子的哈夫曼编码。\n哈夫曼编码是前缀编码——任何字符的编码都不是另一个字符编码的前缀，保证解码唯一确定。\n权值越大的字符编码越短，实现最优压缩。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (18, 'OPERATION', '加权路径长度（WPL）', 'WPL = Σ(叶子权值 × 根到叶子的路径长度)。\n哈夫曼树在所有带权二叉树中WPL最小。\nn个叶子结点的哈夫曼树共有2n-1个结点，没有度为1的结点（正则二叉树）。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (18, 'COMPLEXITY', '时间复杂度与空间复杂度', '构建哈夫曼树使用最小堆，共进行n-1次合并，每次合并涉及两次删除最小值和一次插入，时间复杂度O(n log n)。\n编码过程对每个叶子做一次路径遍历，总时间O(n)，编码总长度不超过O(n²)。\n空间复杂度O(n)用于存储哈夫曼树（2n-1个结点）和编码表。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (11, 'OPERATION', '顺序表插入操作', '顺序表使用一段连续的存储单元依次存储数据元素，通常用数组实现。\n在第 i 个位置（1 ≤ i ≤ n+1）插入新元素时:\n第一步:判断表是否已满，若已满则无法插入。\n第二步:检查插入位置是否合法，i 的有效范围为 1 到 n+1。\n第三步:将第 i 个位置及之后的所有元素统一向后移动一个位置。\n第四步:将新元素放入第 i 个位置，表长加一。\n\n时间分析:\n- 最好情况:在表尾插入（i = n+1），无需移动任何元素，O(1)。\n- 最坏情况:在表头插入（i = 1），需要移动全部 n 个元素，O(n)。\n- 平均情况:在等概率假设下，平均移动 n/2 个元素，O(n)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (11, 'OPERATION', '顺序表删除操作', '删除第 i 个位置的元素（1 ≤ i ≤ n）:\n第一步:判断表是否为空，若为空则无法删除。\n第二步:检查位置合法性。\n第三步:将第 i+1 个位置及之后的所有元素向前移动一个位置，覆盖被删元素。\n第四步:表长减一。\n\n时间分析:\n- 最好情况:删除表尾元素（i = n），无需移动，O(1)。\n- 最坏情况:删除表头元素（i = 1），移动 n-1 个元素，O(n)。\n- 平均情况:等概率下平均移动 (n-1)/2 个元素，O(n)。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (11, 'OPERATION', '顺序表按值查找', '在顺序表中查找第一个值为 target 的元素的位置:\n从表头开始逐个比较，找到则返回其位序；遍历完未找到则返回查找失败。\n可设置哨兵:将目标值存入 0 号位置（或数组末尾多留一位），省去每次循环中的越界判断，\n使循环条件简化为"未匹配到就继续"，减少约一半的比较次数。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (11, 'COMPLEXITY', '顺序表各操作复杂度总结', '| 操作 | 时间复杂度 | 说明 |\n|------|-----------|------|\n| 按位查找（随机访问） | O(1) | 数组下标直接定位 |\n| 按值查找 | O(n) | 需要逐个比较 |\n| 插入（指定位置） | O(n) 均值 | 需要移动元素 |\n| 删除（指定位置） | O(n) 均值 | 需要移动元素 |\n| 表尾追加 | O(1) 均摊 | 动态扩容时偶发 O(n) |\n\n空间复杂度:O(n)，其中 n 为当前元素个数。\n动态数组的容量管理:当元素个数达到容量上限时，通常按 2 倍策略扩容，\n均摊每次插入的时间复杂度为 O(1)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (12, 'OPERATION', '单链表基本概念与结构', '单链表通过指针将一组离散的内存块串联起来，每个节点包含数据域和指针域。\n节点结构:[数据 | next → 下一个节点的地址]\n头节点:第一个数据节点之前的辅助节点，不存储实际数据，用于简化边界操作。\n头指针:指向头节点（或首元节点）的指针，是链表的唯一入口。\n尾节点:最后一个数据节点，其 next 指针为 NULL（或 nullptr）。\n特点:不需要连续内存空间，插入和删除只需修改指针，但无法随机访问（必须从头遍历）。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (12, 'OPERATION', '单链表头插法', '头插法将新节点插入到链表头部（头节点之后、原首元节点之前）。\n步骤:\n1. 创建新节点 s，填入数据。\n2. 将 s->next 指向头节点的后继（即原来的首元节点）。\n3. 将头节点的 next 指向 s。\n特点:每插入一个元素都在头部，最终链表中元素的顺序与输入顺序**相反**。\n时间复杂度:O(1)，仅需修改两个指针。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (12, 'OPERATION', '单链表尾插法', '尾插法将新节点追加到链表尾部。\n步骤:\n1. 创建新节点 s，填入数据。\n2. 若链表为空（仅头节点），将头节点的 next 指向 s。\n3. 否则，将尾指针 r->next 指向 s，然后更新 r = s。\n4. 最后令 s->next = NULL。\n特点:保持元素的原始输入顺序。需要维护一个尾指针以避免每次都遍历到末尾（否则退化为 O(n)）。\n时间复杂度:有尾指针时 O(1)，无尾指针需遍历至末尾则为 O(n)。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (12, 'OPERATION', '单链表按位删除', '删除第 i 个位置的节点（1 ≤ i ≤ length）:\n步骤:\n1. 从头节点出发，工作指针 p 移动到第 i-1 个节点（待删节点的前驱）。\n2. 若 p->next 为空（超出长度），删除失败。\n3. 用临时指针 q 记录待删节点:q = p->next。\n4. 将 p->next 绕过 q，指向 q->next（p->next = q->next）。\n5. 释放 q 节点的内存:delete q。\n关键:必须先找到前驱节点才能修改指针完成删除，因此需要从头遍历到第 i-1 个节点。\n时间复杂度:O(n)（查找前驱需 O(n)，删除操作本身 O(1)）。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (12, 'COMPLEXITY', '链表各操作复杂度总结', '| 操作 | 单链表 | 双向链表 | 循环单链表 |\n|------|--------|---------|-----------|\n| 按位查找 | O(n) | O(n) | O(n) |\n| 按值查找 | O(n) | O(n) | O(n) |\n| 头部插入/删除 | O(1) | O(1) | O(1) |\n| 尾部插入（有尾指针） | O(1) | O(1) | O(1) |\n| 尾部删除 | O(n) | O(1)* | O(n) |\n| 已知节点后插入 | O(1) | O(1) | O(1) |\n| 已知节点删除 | O(n)** | O(1) | O(n)** |\n| 空间开销 | 每节点额外1个指针 | 每节点额外2个指针 | 同单链表 |\n\n*双向链表已知尾节点可直接操作前驱指针。\n**单向链表删除已知节点仍需找前驱，除非用"复制后继法"变通处理。\n\n空间复杂度:O(n)，每个节点额外占用一个指针域的空间（双向链表为两个）。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (13, 'OPERATION', '栈的基本概念', '栈是一种限定仅在**表尾**进行插入和删除操作的线性表。\n允许操作的一端称为**栈顶**（top），另一端称为**栈底**（bottom）。\n不含任何元素的栈称为**空栈**。\n栈的操作特性是 **LIFO**（Last In First Out，后进先出）:\n最后压入栈的元素最先被弹出。\n类比:一摞盘子，只能从最上面取放。\n\n基本操作:\n- Push（进栈/压栈）:在栈顶插入元素。\n- Pop（出栈/弹栈）:删除并返回栈顶元素。\n- Peek / Top（取栈顶）:查看栈顶元素但不删除。\n- IsEmpty（判空）:判断栈是否为空。\n- IsFull（判满）:针对顺序栈，判断是否已满。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (13, 'OPERATION', '顺序栈的实现', '顺序栈用数组实现，用一个整型变量 top 记录栈顶位置。\n两种常见约定:\n方式一:top 初始为 -1，表示空栈。Push 时 top++ 再赋值，Pop 先取值再 top--。\n方式二:top 初始为 0，表示空栈。Push 直接赋值再 top++，Pop 先 top-- 再取值。\n\n栈满条件（方式一）:top == maxSize - 1\n栈空条件（方式一）:top == -1\n入栈:data[++top] = x\n出栈:x = data[top--]', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (13, 'OPERATION', '链式栈的实现', '链式栈用单链表实现，栈顶设在链表头部（头节点之后的首元节点）。\n优点:不存在栈满的问题（只要内存够），不需要预先分配固定大小。\n入栈:新建节点 s，s->next = top->next，top->next = s —— O(1)\n出栈:s = top->next，top->next = s->next，释放 s —— O(1)', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (13, 'OPERATION', '栈的应用——表达式求值', '利用栈可以方便地计算中缀表达式，经典算法是双栈法:\n一个操作数栈（operand stack）和一个运算符栈（operator stack）。\n扫描表达式:\n- 遇到数字:压入操作数栈。\n- 遇到运算符:与运算符栈顶元素比较优先级。\n  - 当前运算符优先级更高:压入运算符栈。\n  - 当前运算符优先级更低或相等:弹出栈顶运算符和两个操作数进行计算，结果压回操作数栈，重复比较。\n- 遇到左括号\'(\':压入运算符栈。\n- 遇到右括号\')\':不断弹出运算符计算，直到遇到左括号为止。\n最后运算符栈中剩余的运算符依次弹出计算，操作数栈中剩下的唯一结果即为答案。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (13, 'COMPLEXITY', '栈各操作复杂度', '| 操作 | 顺序栈 | 链式栈 |\n|------|--------|--------|\n| Push（入栈） | O(1) 均摊 | O(1) |\n| Pop（出栈） | O(1) | O(1) |\n| Peek（取栈顶） | O(1) | O(1) |\n| 判空 | O(1) | O(1) |\n| 判满 | O(1) | 不适用 |\n| 空间复杂度 | O(n) 固定容量 | O(n) 按需分配 |\n\n表达式求值:每个操作数和运算符最多进出栈一次，总时间复杂度 O(n)，n 为表达式中符号总数。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (14, 'OPERATION', '队列的基本概念', '队列是一种限定仅在**表尾插入**、**表头删除**的线性表。\n允许插入的一端称为**队尾**（rear），允许删除的一端称为**队头**（front）。\n队列的操作特性是 **FIFO**（First In First Out，先进先出）:\n最先进入队列的元素最先离开。\n类比:排队买票，先来的人先买到票离开。\n\n基本操作:\n- EnQueue（入队）:在队尾插入元素。\n- DeQueue（出队）:删除并返回队头元素。\n- GetFront（取队头）:查看队头元素但不删除。\n- IsEmpty（判空）、IsFull（判满）。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (14, 'OPERATION', '顺序队列与假溢出问题', '用数组实现的顺序队列存在"假溢出"问题:\n即使数组前端有空闲位置，但 rear 已到达数组末尾，仍无法继续入队。\n例如:数组大小为 5，经过几次出队后 front=3，rear=5（已满），\n但实际上 0~2 这三个位置是空闲的——这就是假溢出。\n\n解决方案:**循环队列**。\n将数组看作首尾相接的环形结构，rear 到达末尾后回到开头继续使用。\n取模运算:(rear + 1) % maxSize', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (14, 'OPERATION', '循环队列的实现细节', '循环队列的关键在于如何区分"空"和"满":\n\n方案一:牺牲一个存储单元\n- 初始状态:front = 0, rear = 0\n- 入队:data[rear] = x; rear = (rear + 1) % maxSize\n- 出队:x = data[front]; front = (front + 1) % maxSize\n- 队空条件:front == rear\n- 队满条件:(rear + 1) % maxSize == front\n- 有效元素个数:(rear - front + maxSize) % maxSize\n\n方案二:增加 size 变量记录当前元素个数\n- 队空条件:size == 0\n- 队满条件:size == maxSize\n- 无需牺牲存储单元', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (14, 'OPERATION', '链式队列', '链式队列用带头结点的单链表实现，队头在链表头部，队尾在链表尾部。\n需要维护 front 和 rear 两个指针。\n入队:新建节点接到 rear 之后，更新 rear 指针 —— O(1)\n出队:删除 front 后的第一个节点，更新 front 指针 —— O(1)\n优点:不存在假溢出和队满问题，空间按需分配。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (14, 'COMPLEXITY', '队列各操作复杂度', '| 操作 | 顺序队列（非循环） | 循环队列 | 链式队列 |\n|------|-------------------|---------|---------|\n| EnQueue（入队） | O(1) 但可能假溢出 | O(1) | O(1) |\n| DeQueue（出队） | O(1) | O(1) | O(1) |\n| GetFront（取队头） | O(1) | O(1) | O(1) |\n| 判空 | O(1) | O(1) | O(1) |\n| 空间利用率 | 低（假溢出浪费） | 高（循环利用） | 高（按需分配） |\n\nBFS（广度优先搜索）中使用队列，每个节点入队一次出队一次，总时间复杂度 O(V+E)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (7, 'OPERATION', '列举法表示集合', '列举法（枚举法）是将集合中的所有元素一一列出，写在大括号内，元素之间用逗号分隔。\n例如:A = {1, 2, 3, 4, 5} 表示由1到5这五个正整数组成的集合。\n列举法适用于元素个数有限且较少的集合，优点是直观、一目了然。\n注意:集合中元素不重复，{1, 2, 2, 3} 等价于 {1, 2, 3}；元素无序，{1, 2, 3} 与 {3, 1, 2} 表示同一集合。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (7, 'OPERATION', '描述法表示集合', '描述法（特征性质法）是用集合中元素的公共特征来描述集合，一般形式为 {x | P(x)}，其中 P(x) 是元素 x 满足的条件。\n例如:B = {x | x 是正偶数} 表示所有正偶数的集合。\n描述法适用于元素个数无限或不宜逐一列举的集合，表达更简洁。\n描述法的关键在于谓词 P(x) 必须是明确的判定条件，即对任意对象都能判断其是否属于该集合。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (7, 'OPERATION', '文氏图表示集合', '文氏图（Venn Diagram）用封闭曲线（通常是圆或矩形）来直观表示集合及其关系。\n矩形表示全集 U，圆表示各个子集，圆的重叠部分表示集合的交集。\n文氏图不是严格的数学表示，但有助于理解集合之间的包含、相交、互斥等关系，常用于集合运算的可视化分析。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (7, 'COMPLEXITY', '集合表示法的比较分析', '列举法:适合有限小集合，存储空间 O(n)，查找需要遍历 O(n)。\n描述法:适合无限集或大集合，不直接存储元素，无法直接枚举，需要通过判定条件逐个验证。\n文氏图:仅用于可视化辅助理解，不作为程序存储结构。\n在计算机中实现集合时，需要选择合适的数据结构（数组、链表、哈希表、位图等）来高效支持集合操作。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (8, 'OPERATION', '属于与不属于', '若元素 a 是集合 A 中的成员，则记作 a ∈ A，读作"a 属于 A"。\n若元素 a 不是集合 A 中的成员，则记作 a ∉ A，读作"a 不属于 A"。\n隶属关系是集合论中最基本的关系，是定义集合运算和推导集合性质的基础。\n在程序中，隶属关系对应"查找"操作——判断某个值是否在集合中存在。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (8, 'OPERATION', '集合的包含关系', '若集合 A 的每个元素都属于集合 B，则称 A 是 B 的子集，记作 A ⊆ B。\n若 A ⊆ B 且 B 中至少有一个元素不属于 A，则称 A 是 B 的真子集，记作 A ⊂ B。\n空集 ∅ 是任何集合的子集，是任何非空集合的真子集。\n任何集合是其自身的子集（自反性），包含关系具有传递性。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (8, 'OPERATION', '集合的相等', '若 A ⊆ B 且 B ⊆ A，则 A = B，即两个集合包含完全相同的元素。\n集合相等只取决于元素本身，与元素的排列顺序无关。\n判断两个集合相等的方法:逐一验证 A 中每个元素都属于 B，且 B 中每个元素都属于 A。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (8, 'COMPLEXITY', '隶属判断的复杂度', '基于数组的无序集合:判断 a ∈ A 需要遍历，时间复杂度 O(n)。\n基于有序数组:可用二分查找，时间复杂度 O(log n)。\n基于哈希表:平均时间复杂度 O(1)，最坏 O(n)（哈希冲突严重时）。\n基于位图（元素为小整数）:O(1)，直接按位判断。\n子集判断 A ⊆ B:朴素方法对 A 中每个元素在 B 中查找，O(|A|·|B|)；使用哈希集合可优化到 O(|A|+|B|)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (9, 'OPERATION', '并集运算', '集合 A 与 B 的并集记作 A ∪ B = {x | x ∈ A 或 x ∈ B}，即由属于 A 或属于 B 的所有元素组成的集合。\n并集的性质:A ∪ A = A（幂等律），A ∪ ∅ = A（同一律），A ∪ U = U（U 为全集，零律）。\n在程序中，并集操作对应合并两个集合并去重。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (9, 'OPERATION', '交集运算', '集合 A 与 B 的交集记作 A ∩ B = {x | x ∈ A 且 x ∈ B}，即由同时属于 A 和 B 的所有元素组成的集合。\n交集的性质:A ∩ A = A（幂等律），A ∩ ∅ = ∅（零律），A ∩ U = A（同一律）。\n若 A ∩ B = ∅，则称 A 与 B 互不相交（互斥）。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (9, 'OPERATION', '差集运算', '集合 A 与 B 的差集记作 A - B = {x | x ∈ A 且 x ∉ B}，即由属于 A 但不属于 B 的元素组成的集合。\n差集不满足交换律:A - B ≠ B - A（一般情况下）。\n补集是差集的特殊情况:A 的补集 Ā = U - A，其中 U 是全集。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (9, 'OPERATION', '对称差运算', '集合 A 与 B 的对称差记作 A △ B = (A - B) ∪ (B - A) = (A ∪ B) - (A ∩ B)，即属于 A 或 B 但不同时属于两者的元素。\n对称差满足交换律:A △ B = B △ A，满足结合律:(A △ B) △ C = A △ (B △ C)。\n对称差在集合论中的地位类似于整数加法。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (9, 'OPERATION', '笛卡尔积运算', '集合 A 与 B 的笛卡尔积记作 A × B = {(a, b) | a ∈ A, b ∈ B}，即所有有序对组成的集合。\n|A × B| = |A| × |B|，笛卡尔积的基数等于两个集合基数的乘积。\n笛卡尔积不满足交换律:A × B ≠ B × A（除非 A = B 或其中之一为空集）。', 4);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (9, 'COMPLEXITY', '集合运算的复杂度分析', '设 |A| = m，|B| = n，使用哈希集合实现:\n并集 A ∪ B:遍历 A 和 B 所有元素插入结果集，O(m + n)。\n交集 A ∩ B:遍历较小集合，在较大集合中查找，O(min(m, n)) 平均。\n差集 A - B:遍历 A，对每个元素在 B 中查找，O(m) 平均。\n对称差:等价于并集减去交集，O(m + n)。\n笛卡尔积:必须枚举所有有序对，O(m × n)，结果集大小为 m × n。\n使用有序数组实现时，并集和交集可用归并思想，O(m + n)。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (10, 'OPERATION', '顺序存储实现', '用数组（顺序表）存储集合元素，元素在连续内存空间中依次存放。\n无序数组:插入 O(1)（尾部追加），查找 O(n)，删除 O(n)（需移动元素）。\n有序数组:插入 O(n)（需移动），查找 O(log n)（二分查找），删除 O(n)。\n顺序存储适合元素个数已知且变化不大的场景，支持随机访问，但不便于动态扩容。', 0);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (10, 'OPERATION', '链式存储实现', '用链表存储集合元素，每个节点包含数据域和指针域。\n无序链表:插入 O(1)（头部插入），查找 O(n)，删除 O(n)（需先查找）。\n有序链表:插入 O(n)（需找位置），查找 O(n)，删除 O(n)。\n链式存储适合元素个数变化频繁的场景，动态分配内存，但不支持随机访问。', 1);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (10, 'OPERATION', '哈希表存储实现', '用哈希表存储集合元素，通过哈希函数将元素映射到桶（bucket）中。\n插入:计算哈希值，放入对应桶，平均 O(1)。\n查找:计算哈希值，在对应桶中查找，平均 O(1)。\n删除:查找后删除，平均 O(1)。\n冲突处理方法:开放寻址法（线性探测、二次探测）和链地址法（拉链法）。\n哈希表是集合操作最高效的实现方式，但不支持有序遍历，且最坏情况退化为 O(n)。', 2);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (10, 'OPERATION', '位图存储实现', '当集合元素为有限范围内的小整数时，可用位图（bitmap）存储。\n每个整数对应一个比特位，1 表示属于集合，0 表示不属于。\n插入/查找/删除:直接操作对应比特位，O(1)。\n空间复杂度:O(U/8) 字节，U 为元素取值范围上限。\n位图适合稠密小整数集合，内存效率极高，但不适合稀疏集合或非整数元素。', 3);
INSERT INTO knowledge_content (knowledge_point_id, content_type, title, content, sort_order) VALUES (10, 'COMPLEXITY', '集合存储实现的复杂度比较', '| 操作 | 无序数组 | 有序数组 | 链表 | 哈希表 | 位图 |\n|------|---------|---------|------|--------|------|\n| 插入 | O(1) | O(n) | O(1) | O(1)* | O(1) |\n| 查找 | O(n) | O(log n) | O(n) | O(1)* | O(1) |\n| 删除 | O(n) | O(n) | O(n) | O(1)* | O(1) |\n| 空间 | O(n) | O(n) | O(n) | O(n) | O(U) |\n*哈希表为平均复杂度，最坏 O(n)\n选择建议:频繁查找选哈希表，需要有序选有序数组/平衡树，小整数集合选位图，频繁插入删除选链表。', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (19, '邻接矩阵实现', '用二维数组存储无向图', '#include <bits/stdc++.h>\nusing namespace std;\n\nclass Graph {\n    int n;\n    vector<vector<int>> matrix;\npublic:\n    Graph(int n) : n(n), matrix(n, vector<int>(n, 0)) {}\n    \n    void addEdge(int i, int j) {\n        if (i >= 0 && i < n && j >= 0 && j < n) {\n            matrix[i][j] = matrix[j][i] = 1;\n        }\n    }\n    \n    bool hasEdge(int i, int j) {\n        return i >= 0 && i < n && j >= 0 && j < n && matrix[i][j] == 1;\n    }\n    \n    void print() {\n        for (int i = 0; i < n; i++) {\n            for (int j = 0; j < n; j++) {\n                cout << matrix[i][j] << " ";\n            }\n            cout << endl;\n        }\n    }\n};\n\nint main() {\n    Graph g(4);\n    g.addEdge(0, 1);\n    g.addEdge(0, 2);\n    g.addEdge(1, 3);\n    g.addEdge(2, 3);\n    cout << "邻接矩阵:" << endl;\n    g.print();\n    cout << "0 和 2 之间有边吗？" << (g.hasEdge(0, 2) ? "是" : "否") << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (20, 'DFS 和 BFS 遍历实现', '分别用递归 DFS 和队列 BFS 遍历图', '#include <bits/stdc++.h>\nusing namespace std;\n\nclass Graph {\n    int n;\n    vector<vector<int>> adj;\n    vector<bool> visited;\npublic:\n    Graph(int n) : n(n), adj(n), visited(n, false) {}\n    \n    void addEdge(int i, int j) {\n        adj[i].push_back(j);\n        adj[j].push_back(i);\n    }\n    \n    void dfs(int v) {\n        visited[v] = true;\n        cout << v << " ";\n        for (int neighbor : adj[v]) {\n            if (!visited[neighbor]) {\n                dfs(neighbor);\n            }\n        }\n    }\n    \n    void bfs(int start) {\n        fill(visited.begin(), visited.end(), false);\n        queue<int> q;\n        q.push(start);\n        visited[start] = true;\n        \n        while (!q.empty()) {\n            int v = q.front();\n            q.pop();\n            cout << v << " ";\n            \n            for (int neighbor : adj[v]) {\n                if (!visited[neighbor]) {\n                    visited[neighbor] = true;\n                    q.push(neighbor);\n                }\n            }\n        }\n    }\n};\n\nint main() {\n    Graph g(5);\n    g.addEdge(0, 1);\n    g.addEdge(0, 2);\n    g.addEdge(1, 3);\n    g.addEdge(2, 3);\n    g.addEdge(3, 4);\n    \n    cout << "DFS 从 0 开始:";\n    g.dfs(0);\n    cout << endl;\n    \n    cout << "BFS 从 0 开始:";\n    g.bfs(0);\n    cout << endl;\n    \n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (21, 'Dijkstra 算法实现', '用优先队列优化求单源最短路径', '#include <bits/stdc++.h>\nusing namespace std;\n\nconst int INF = 1e9;\n\nclass Graph {\n    int n;\n    vector<vector<pair<int, int>>> adj;\npublic:\n    Graph(int n) : n(n), adj(n) {}\n    \n    void addEdge(int u, int v, int w) {\n        adj[u].push_back({v, w});\n        adj[v].push_back({u, w});\n    }\n    \n    vector<int> dijkstra(int start) {\n        vector<int> dist(n, INF);\n        dist[start] = 0;\n        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;\n        pq.push({0, start});\n        \n        while (!pq.empty()) {\n            int d = pq.top().first;\n            int u = pq.top().second;\n            pq.pop();\n            \n            if (d > dist[u]) continue;\n            \n            for (auto& edge : adj[u]) {\n                int v = edge.first;\n                int w = edge.second;\n                if (dist[u] + w < dist[v]) {\n                    dist[v] = dist[u] + w;\n                    pq.push({dist[v], v});\n                }\n            }\n        }\n        return dist;\n    }\n};\n\nint main() {\n    Graph g(5);\n    g.addEdge(0, 1, 4);\n    g.addEdge(0, 2, 1);\n    g.addEdge(1, 3, 1);\n    g.addEdge(2, 1, 2);\n    g.addEdge(2, 3, 5);\n    g.addEdge(3, 4, 3);\n    \n    vector<int> dist = g.dijkstra(0);\n    \n    cout << "从顶点 0 到各点的最短距离:" << endl;\n    for (int i = 0; i < 5; i++) {\n        if (dist[i] == INF)\n            cout << "到 " << i << " : 不可达" << endl;\n        else\n            cout << "到 " << i << " : " << dist[i] << endl;\n    }\n    \n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (22, 'Kruskal 算法实现', '用并查集求最小生成树', '#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Edge {\n    int u, v, w;\n    bool operator<(const Edge& other) const {\n        return w < other.w;\n    }\n};\n\nclass UnionFind {\n    vector<int> parent;\npublic:\n    UnionFind(int n) {\n        parent.resize(n);\n        for (int i = 0; i < n; i++)\n            parent[i] = i;\n    }\n    \n    int find(int x) {\n        if (parent[x] != x)\n            parent[x] = find(parent[x]);\n        return parent[x];\n    }\n    \n    bool unite(int x, int y) {\n        int rootX = find(x);\n        int rootY = find(y);\n        if (rootX != rootY) {\n            parent[rootX] = rootY;\n            return true;\n        }\n        return false;\n    }\n};\n\nclass Graph {\n    int n;\n    vector<Edge> edges;\npublic:\n    Graph(int n) : n(n) {}\n    \n    void addEdge(int u, int v, int w) {\n        edges.push_back({u, v, w});\n    }\n    \n    int kruskal() {\n        sort(edges.begin(), edges.end());\n        UnionFind uf(n);\n        int mstWeight = 0;\n        int edgesCount = 0;\n        \n        for (const auto& edge : edges) {\n            if (uf.unite(edge.u, edge.v)) {\n                mstWeight += edge.w;\n                edgesCount++;\n                if (edgesCount == n - 1)\n                    break;\n            }\n        }\n        \n        return edgesCount == n - 1 ? mstWeight : -1;\n    }\n};\n\nint main() {\n    Graph g(5);\n    g.addEdge(0, 1, 2);\n    g.addEdge(0, 2, 3);\n    g.addEdge(1, 2, 1);\n    g.addEdge(1, 3, 4);\n    g.addEdge(2, 3, 5);\n    g.addEdge(3, 4, 6);\n    \n    int mst = g.kruskal();\n    cout << "最小生成树的权值和:" << (mst != -1 ? to_string(mst) : "无法生成") << endl;\n    \n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (27, '直接插入排序实现', '对数组进行升序排列', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid insertionSort(vector<int>& a) {\n    for (int i = 1; i < a.size(); i++) {\n        int key = a[i], j = i - 1;\n        while (j >= 0 && a[j] > key) {\n            a[j + 1] = a[j];\n            j--;\n        }\n        a[j + 1] = key;\n    }\n}\n\nint main() {\n    vector<int> a = {5, 2, 9, 1, 3};\n    insertionSort(a);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (27, '折半插入排序实现', '使用二分查找优化插入位置', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid binaryInsertionSort(vector<int>& a) {\n    int n = a.size();\n    for (int i = 1; i < n; i++) {\n        int key = a[i];\n        int l = 0, r = i - 1;\n        while (l <= r) {\n            int mid = l + (r - l) / 2;\n            if (a[mid] > key) r = mid - 1;\n            else l = mid + 1;\n        }\n        for (int j = i - 1; j >= l; j--)\n            a[j + 1] = a[j];\n        a[l] = key;\n    }\n}\n\nint main() {\n    vector<int> a = {5, 2, 9, 1, 3};\n    binaryInsertionSort(a);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (27, '链表插入排序实现', '对单链表进行升序排序', '#include <bits/stdc++.h>\nusing namespace std;\n\nstruct ListNode {\n    int val;\n    ListNode* next;\n    ListNode(int x) : val(x), next(nullptr) {}\n};\n\nListNode* insertionSortList(ListNode* head) {\n    ListNode dummy(0);\n    while (head) {\n        ListNode* cur = head;\n        head = head->next;\n        ListNode* prev = &dummy;\n        while (prev->next && prev->next->val < cur->val)\n            prev = prev->next;\n        cur->next = prev->next;\n        prev->next = cur;\n    }\n    return dummy.next;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (27, '希尔排序实现', '使用 Shell 增量', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid shellSort(vector<int>& a) {\n    int n = a.size();\n    for (int gap = n / 2; gap > 0; gap /= 2) {\n        for (int i = gap; i < n; i++) {\n            int t = a[i], j = i;\n            while (j >= gap && a[j - gap] > t) {\n                a[j] = a[j - gap];\n                j -= gap;\n            }\n            a[j] = t;\n        }\n    }\n}\n\nint main() {\n    vector<int> a = {9, 1, 5, 8, 3, 7, 4, 6, 2};\n    shellSort(a);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (28, '冒泡排序实现', '带提前终止优化的冒泡排序', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid bubbleSort(vector<int>& a) {\n    int n = a.size();\n    bool swapped;\n    for (int i = 0; i < n - 1; i++) {\n        swapped = false;\n        for (int j = 0; j < n - i - 1; j++) {\n            if (a[j] > a[j + 1]) {\n                swap(a[j], a[j + 1]);\n                swapped = true;\n            }\n        }\n        if (!swapped) break;\n    }\n}\n\nint main() {\n    vector<int> a = {64, 34, 25, 12, 22};\n    bubbleSort(a);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (28, '快速排序实现', '递归版快速排序', '#include <bits/stdc++.h>\nusing namespace std;\n\nint partition(vector<int>& a, int l, int r) {\n    int pivot = a[l], i = l;\n    for (int j = l + 1; j <= r; j++) {\n        if (a[j] < pivot)\n            swap(a[++i], a[j]);\n    }\n    swap(a[l], a[i]);\n    return i;\n}\n\nvoid quickSort(vector<int>& a, int l, int r) {\n    if (l >= r) return;\n    int p = partition(a, l, r);\n    quickSort(a, l, p - 1);\n    quickSort(a, p + 1, r);\n}\n\nint main() {\n    vector<int> a = {6, 3, 8, 2, 7};\n    quickSort(a, 0, a.size() - 1);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (28, '三数取中快速排序实现', '降低退化概率', '#include <bits/stdc++.h>\nusing namespace std;\n\nint medianPivot(vector<int>& a, int l, int r) {\n    int m = l + (r - l) / 2;\n    if (a[l] > a[m]) swap(a[l], a[m]);\n    if (a[l] > a[r]) swap(a[l], a[r]);\n    if (a[m] > a[r]) swap(a[m], a[r]);\n    return a[m];\n}\n\nint partition(vector<int>& a, int l, int r) {\n    int pivot = medianPivot(a, l, r);\n    int i = l, j = r;\n    while (true) {\n        while (a[i] < pivot) i++;\n        while (a[j] > pivot) j--;\n        if (i >= j) return j;\n        swap(a[i++], a[j--]);\n    }\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (28, '计数排序实现', '非负整数排序', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid countingSort(vector<int>& a) {\n    int mx = *max_element(a.begin(), a.end());\n    vector<int> cnt(mx + 1, 0);\n    for (int x : a) cnt[x]++;\n    for (int i = 1; i <= mx; i++) cnt[i] += cnt[i - 1];\n    vector<int> res(a.size());\n    for (int i = a.size() - 1; i >= 0; i--)\n        res[--cnt[a[i]]] = a[i];\n    a = res;\n}\n\nint main() {\n    vector<int> a = {4, 2, 2, 8, 3, 3, 1};\n    countingSort(a);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (29, '简单选择排序实现', '每次选择最小值放到前面', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid selectionSort(vector<int>& a) {\n    int n = a.size();\n    for (int i = 0; i < n - 1; i++) {\n        int minIdx = i;\n        for (int j = i + 1; j < n; j++) {\n            if (a[j] < a[minIdx])\n                minIdx = j;\n        }\n        swap(a[i], a[minIdx]);\n    }\n}\n\nint main() {\n    vector<int> a = {29, 10, 14, 37, 13};\n    selectionSort(a);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (29, '堆排序实现', '大顶堆排序', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid heapify(vector<int>& a, int n, int i) {\n    int largest = i, l = 2 * i + 1, r = 2 * i + 2;\n    if (l < n && a[l] > a[largest]) largest = l;\n    if (r < n && a[r] > a[largest]) largest = r;\n    if (largest != i) {\n        swap(a[i], a[largest]);\n        heapify(a, n, largest);\n    }\n}\n\nvoid heapSort(vector<int>& a) {\n    int n = a.size();\n    for (int i = n / 2 - 1; i >= 0; i--)\n        heapify(a, n, i);\n    for (int i = n - 1; i > 0; i--) {\n        swap(a[0], a[i]);\n        heapify(a, i, 0);\n    }\n}\n\nint main() {\n    vector<int> a = {4, 10, 3, 5, 1};\n    heapSort(a);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (29, '桶排序示意', '桶内使用插入排序', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid bucketSort(vector<float>& a) {\n    int n = a.size();\n    vector<vector<float>> b(n);\n    for (int i = 0; i < n; i++)\n        b[(int)(n * a[i])].push_back(a[i]);\n    for (int i = 0; i < n; i++)\n        sort(b[i].begin(), b[i].end());\n    int idx = 0;\n    for (int i = 0; i < n; i++)\n        for (float x : b[i])\n            a[idx++] = x;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (30, '归并排序实现', '递归二路归并', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid merge(vector<int>& a, int l, int m, int r) {\n    vector<int> t;\n    int i = l, j = m + 1;\n    while (i <= m && j <= r) {\n        if (a[i] <= a[j]) t.push_back(a[i++]);\n        else t.push_back(a[j++]);\n    }\n    while (i <= m) t.push_back(a[i++]);\n    while (j <= r) t.push_back(a[j++]);\n    for (int k = 0; k < t.size(); k++)\n        a[l + k] = t[k];\n}\n\nvoid mergeSort(vector<int>& a, int l, int r) {\n    if (l >= r) return;\n    int m = l + (r - l) / 2;\n    mergeSort(a, l, m);\n    mergeSort(a, m + 1, r);\n    merge(a, l, m, r);\n}\n\nint main() {\n    vector<int> a = {5, 2, 4, 6, 1, 3};\n    mergeSort(a, 0, a.size() - 1);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (30, '多路归并排序示意', '二路归并作为特例', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid merge(vector<int>& a, int l, int m, int r) {\n    vector<int> t;\n    int i = l, j = m + 1;\n    while (i <= m && j <= r)\n        t.push_back(a[i] <= a[j] ? a[i++] : a[j++]);\n    while (i <= m) t.push_back(a[i++]);\n    while (j <= r) t.push_back(a[j++]);\n    for (int k = 0; k < t.size(); k++)\n        a[l + k] = t[k];\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (30, '基数排序实现', 'LSD 基数排序', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid radixSort(vector<int>& a) {\n    int mx = *max_element(a.begin(), a.end());\n    for (int exp = 1; mx / exp > 0; exp *= 10) {\n        vector<int> output(a.size()), cnt(10, 0);\n        for (int x : a) cnt[(x / exp) % 10]++;\n        for (int i = 1; i < 10; i++) cnt[i] += cnt[i - 1];\n        for (int i = a.size() - 1; i >= 0; i--)\n            output[--cnt[(a[i] / exp) % 10]] = a[i];\n        a = output;\n    }\n}\n\nint main() {\n    vector<int> a = {170, 45, 75, 90, 802, 24, 2, 66};\n    radixSort(a);\n    for (int x : a) cout << x << " ";\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (23, '带哨兵的顺序查找', 'data[0] 作为哨兵，返回目标在 1 到 n 范围内的位置，返回 0 表示未找到', '#include <bits/stdc++.h>\nusing namespace std;\n\n// 返回首个等于 target 的下标，失败返回 -1\nint findFirst(const vector<int>& a, int target) {\n    for (size_t i = 0; i < a.size(); ++i)\n        if (a[i] == target) return (int)i;\n    return -1;\n}\n\nint main() {\n    vector<int> data = {3, 1, 4, 1, 5};\n    int idx = findFirst(data, 4);\n    if (idx >= 0)\n        cout << "找到，下标=" << idx << endl;\n    else\n        cout << "未找到" << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (23, '顺序查找（数组与哨兵）', '基本实现及哨兵写法', '#include <bits/stdc++.h>\nusing namespace std;\n\nint sequentialSearch(const vector<int>& a, int target) {\n    for (size_t i = 0; i < a.size(); ++i)\n        if (a[i] == target) return (int)i;\n    return -1;\n}\n\nint sequentialSearchSentinel(vector<int> a, int target) {\n    a.push_back(target);  // 哨兵\n    int i = 0;\n    while (a[i] != target) ++i;\n    if (i == (int)a.size() - 1) return -1;  // 仅命中哨兵\nint sequentialSearch(vector<int>& data, int key) {\n    data[0] = key;\n    int i = (int)data.size() - 1;\n    while (data[i] != key) {\n        i--;\n    }\n    return i;\n}\n\nint main() {\n    vector<int> arr = {5, 2, 8, 1, 9};\n    cout << sequentialSearch(arr, 8) << endl;\n    cout << sequentialSearchSentinel(arr, 3) << endl;\n    vector<int> data = {0, 18, 27, 9, 45, 36};\n    int key = 45;\n    int pos = sequentialSearch(data, key);\n    if (pos == 0) {\n        cout << "Not Found" << endl;\n    } else {\n        cout << "Found at position " << pos << endl;\n    }\n    return 0;\n}', 'C++', 1);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (24, '迭代二分查找', '在升序数组中查找目标值，返回下标，找不到返回 -1', '#include <bits/stdc++.h>\nusing namespace std;\n\nint binarySearch(const vector<int>& a, int target) {\n    int left = 0, right = (int)a.size() - 1;\n    while (left <= right) {\n        int mid = left + (right - left) / 2;\n        if (a[mid] == target) return mid;\n        if (a[mid] < target) left = mid + 1;\n        else right = mid - 1;\nint binarySearch(const vector<int>& a, int key) {\n    int left = 0, right = (int)a.size() - 1;\n    while (left <= right) {\n        int mid = left + (right - left) / 2;\n        if (a[mid] == key) return mid;\n        if (a[mid] < key) {\n            left = mid + 1;\n        } else {\n            right = mid - 1;\n        }\n    }\n    return -1;\n}\n\nint main() {\n    vector<int> sorted = {1, 3, 5, 7, 9, 11};\n    cout << binarySearch(sorted, 7) << endl;  // 3\n    cout << binarySearch(sorted, 4) << endl;  // -1\n    vector<int> a = {3, 8, 15, 22, 37, 49, 60};\n    int key = 37;\n    cout << binarySearch(a, key) << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (25, '链地址法哈希表', '用 vector<list<int>> 实现整数集合的插入与查找', '#include <bits/stdc++.h>\nusing namespace std;\n\nclass HashMap {\n    vector<list<pair<int, string>>> table;\n    int capacity;\n    size_t hashKey(int key) const {\n        return ((size_t)key * 2654435761u) % capacity;\n    }\npublic:\n    explicit HashMap(int cap = 101) : capacity(cap), table(cap) {}\n\n    bool insert(int key, const string& val) {\n        auto& bucket = table[hashKey(key)];\n        for (auto& p : bucket)\n            if (p.first == key) { p.second = val; return true; }\n        bucket.emplace_back(key, val);\n        return true;\n    }\n\n    string* find(int key) {\n        for (auto& p : table[hashKey(key)])\n            if (p.first == key) return &p.second;\n        return nullptr;\nclass HashTable {\nprivate:\n    vector<list<int>> table;\n\n    int hashValue(int key) const {\n        return ((key % (int)table.size()) + (int)table.size()) % (int)table.size();\n    }\n\npublic:\n    explicit HashTable(int size = 11) : table(size) {}\n\n    void insert(int key) {\n        int index = hashValue(key);\n        for (int value : table[index]) {\n            if (value == key) return;\n        }\n        table[index].push_back(key);\n    }\n\n    bool contains(int key) const {\n        int index = hashValue(key);\n        for (int value : table[index]) {\n            if (value == key) return true;\n        }\n        return false;\n    }\n};\n\nint main() {\n    HashMap mp;\n    mp.insert(1001, "Alice");\n    if (auto* p = mp.find(1001)) cout << *p << endl;\n    HashTable ht;\n    ht.insert(15);\n    ht.insert(26);\n    ht.insert(37);\n    cout << (ht.contains(26) ? "Found" : "Not Found") << endl;\n    cout << (ht.contains(99) ? "Found" : "Not Found") << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (26, 'B+树叶子层范围扫描示意', '用链式叶子结点模拟 B+树适合范围查询的特点', '#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Node {\n    int key;\n    Node *left, *right;\n    explicit Node(int k) : key(k), left(nullptr), right(nullptr) {}\n};\n\nNode* bstSearch(Node* root, int target) {\n    if (!root) return nullptr;\n    if (target == root->key) return root;\n    if (target < root->key) return bstSearch(root->left, target);\n    return bstSearch(root->right, target);\n}\n\nint main() {\n    Node* root = new Node(8);\n    root->left = new Node(3);\n    root->right = new Node(10);\n    root->left->right = new Node(6);\n    Node* hit = bstSearch(root, 6);\n    cout << (hit ? "找到" : "未找到") << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (26, '按场景选择查找方式（示意）', '根据数据是否有序与规模选择不同策略', '#include <bits/stdc++.h>\nusing namespace std;\n\nint searchSmallUnsorted(const vector<int>& a, int x) {\n    for (size_t i = 0; i < a.size(); ++i)\n        if (a[i] == x) return (int)i;\n    return -1;\n}\n\nint searchSorted(const vector<int>& a, int x) {\n    auto it = lower_bound(a.begin(), a.end(), x);\n    if (it != a.end() && *it == x) return (int)(it - a.begin());\n    return -1;\n}\n\nint main() {\n    vector<int> small = {9, 2, 7};\n    vector<int> bigSorted = {1, 2, 3, 5, 8, 13, 21};\n    cout << searchSmallUnsorted(small, 7) << endl;\n    cout << searchSorted(bigSorted, 8) << endl;\nstruct LeafNode {\n    vector<int> keys;\n    LeafNode* next;\n    LeafNode(vector<int> values) : keys(values), next(nullptr) {}\n};\n\nvoid rangeQuery(LeafNode* head, int left, int right) {\n    bool first = true;\n    for (LeafNode* cur = head; cur != nullptr; cur = cur->next) {\n        for (int key : cur->keys) {\n            if (key >= left && key <= right) {\n                if (!first) cout << " ";\n                cout << key;\n                first = false;\n            }\n            if (key > right) return;\n        }\n    }\n}\n\nint main() {\n    LeafNode a({3, 8, 12});\n    LeafNode b({18, 21, 29});\n    LeafNode c({35, 40, 48});\n    a.next = &b;\n    b.next = &c;\n    rangeQuery(&a, 10, 40);\n    cout << endl;\n    return 0;\n}', 'C++', 1);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (15, '二叉树链式存储与四种遍历', '构建二叉树并进行先序、中序、后序（递归+非递归）和层序遍历', '#include <bits/stdc++.h>\nusing namespace std;\n\nstruct TreeNode {\n    int val;\n    TreeNode *left, *right;\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n};\n\nvoid preOrder(TreeNode* root) {\n    if (!root) return;\n    cout << root->val << " ";\n    preOrder(root->left);\n    preOrder(root->right);\n}\n\nvoid inOrder(TreeNode* root) {\n    if (!root) return;\n    inOrder(root->left);\n    cout << root->val << " ";\n    inOrder(root->right);\n}\n\nvoid postOrder(TreeNode* root) {\n    if (!root) return;\n    postOrder(root->left);\n    postOrder(root->right);\n    cout << root->val << " ";\n}\n\nvoid preOrderNR(TreeNode* root) {\n    if (!root) return;\n    stack<TreeNode*> s;\n    s.push(root);\n    while (!s.empty()) {\n        TreeNode* p = s.top(); s.pop();\n        cout << p->val << " ";\n        if (p->right) s.push(p->right);\n        if (p->left) s.push(p->left);\n    }\n}\n\nvoid inOrderNR(TreeNode* root) {\n    stack<TreeNode*> s;\n    TreeNode* p = root;\n    while (p || !s.empty()) {\n        while (p) { s.push(p); p = p->left; }\n        p = s.top(); s.pop();\n        cout << p->val << " ";\n        p = p->right;\n    }\n}\n\nvoid levelOrder(TreeNode* root) {\n    if (!root) return;\n    queue<TreeNode*> q;\n    q.push(root);\n    while (!q.empty()) {\n        TreeNode* p = q.front(); q.pop();\n        cout << p->val << " ";\n        if (p->left) q.push(p->left);\n        if (p->right) q.push(p->right);\n    }\n}\n\nint main() {\n    TreeNode* root = new TreeNode(1);\n    root->left = new TreeNode(2);\n    root->right = new TreeNode(3);\n    root->left->left = new TreeNode(4);\n    root->left->right = new TreeNode(5);\n    root->right->left = new TreeNode(6);\n\n    cout << "先序: "; preOrder(root); cout << endl;\n    cout << "中序: "; inOrder(root); cout << endl;\n    cout << "后序: "; postOrder(root); cout << endl;\n    cout << "先序(非递归): "; preOrderNR(root); cout << endl;\n    cout << "中序(非递归): "; inOrderNR(root); cout << endl;\n    cout << "层序: "; levelOrder(root); cout << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (16, 'BST插入与查找', '构建二叉搜索树，实现递归/迭代查找和插入，中序遍历验证有序性', '#include <bits/stdc++.h>\nusing namespace std;\n\nstruct BSTNode {\n    int val;\n    BSTNode *left, *right;\n    BSTNode(int x) : val(x), left(nullptr), right(nullptr) {}\n};\n\nBSTNode* insert(BSTNode* root, int val) {\n    if (!root) return new BSTNode(val);\n    if (val < root->val)\n        root->left = insert(root->left, val);\n    else if (val > root->val)\n        root->right = insert(root->right, val);\n    return root;\n}\n\nBSTNode* search(BSTNode* root, int key) {\n    if (!root || root->val == key) return root;\n    return key < root->val ? search(root->left, key) : search(root->right, key);\n}\n\nBSTNode* searchNR(BSTNode* root, int key) {\n    while (root && root->val != key)\n        root = key < root->val ? root->left : root->right;\n    return root;\n}\n\nBSTNode* findMin(BSTNode* root) {\n    while (root && root->left) root = root->left;\n    return root;\n}\n\nBSTNode* remove(BSTNode* root, int key) {\n    if (!root) return nullptr;\n    if (key < root->val)\n        root->left = remove(root->left, key);\n    else if (key > root->val)\n        root->right = remove(root->right, key);\n    else {\n        if (!root->left) { BSTNode* t = root->right; delete root; return t; }\n        if (!root->right) { BSTNode* t = root->left; delete root; return t; }\n        BSTNode* succ = findMin(root->right);\n        root->val = succ->val;\n        root->right = remove(root->right, succ->val);\n    }\n    return root;\n}\n\nvoid inOrder(BSTNode* root) {\n    if (!root) return;\n    inOrder(root->left);\n    cout << root->val << " ";\n    inOrder(root->right);\n}\n\nint main() {\n    BSTNode* root = nullptr;\n    int arr[] = {5, 3, 7, 2, 4, 6, 8};\n    for (int x : arr) root = insert(root, x);\n\n    cout << "中序遍历: "; inOrder(root); cout << endl;\n    cout << "查找4: " << (search(root, 4) ? "找到" : "未找到") << endl;\n    cout << "查找9: " << (searchNR(root, 9) ? "找到" : "未找到") << endl;\n\n    root = remove(root, 3);\n    cout << "删除3后: "; inOrder(root); cout << endl;\n\n    root = remove(root, 5);\n    cout << "删除5后: "; inOrder(root); cout << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (17, 'AVL树插入与旋转', '含高度维护的AVL树插入实现，支持LL/RR/LR/RL四种旋转', '#include <bits/stdc++.h>\nusing namespace std;\n\nstruct AVLNode {\n    int val, height;\n    AVLNode *left, *right;\n    AVLNode(int x) : val(x), height(1), left(nullptr), right(nullptr) {}\n};\n\nint getHeight(AVLNode* n) { return n ? n->height : 0; }\nvoid updateHeight(AVLNode* n) {\n    n->height = 1 + max(getHeight(n->left), getHeight(n->right));\n}\n\nAVLNode* rotateRight(AVLNode* y) {\n    AVLNode* x = y->left;\n    AVLNode* T = x->right;\n    x->right = y;\n    y->left = T;\n    updateHeight(y);\n    updateHeight(x);\n    return x;\n}\n\nAVLNode* rotateLeft(AVLNode* x) {\n    AVLNode* y = x->right;\n    AVLNode* T = y->left;\n    y->left = x;\n    x->right = T;\n    updateHeight(x);\n    updateHeight(y);\n    return y;\n}\n\nint getBalance(AVLNode* n) {\n    return n ? getHeight(n->left) - getHeight(n->right) : 0;\n}\n\nAVLNode* insert(AVLNode* node, int val) {\n    if (!node) return new AVLNode(val);\n    if (val < node->val)\n        node->left = insert(node->left, val);\n    else if (val > node->val)\n        node->right = insert(node->right, val);\n    else return node;\n\n    updateHeight(node);\n    int bal = getBalance(node);\n\n    if (bal > 1 && val < node->left->val)   // LL\n        return rotateRight(node);\n    if (bal < -1 && val > node->right->val) // RR\n        return rotateLeft(node);\n    if (bal > 1 && val > node->left->val) { // LR\n        node->left = rotateLeft(node->left);\n        return rotateRight(node);\n    }\n    if (bal < -1 && val < node->right->val) { // RL\n        node->right = rotateRight(node->right);\n        return rotateLeft(node);\n    }\n    return node;\n}\n\nvoid inOrder(AVLNode* root) {\n    if (!root) return;\n    inOrder(root->left);\n    cout << root->val << "(" << getBalance(root) << ") ";\n    inOrder(root->right);\n}\n\nint main() {\n    AVLNode* root = nullptr;\n    int arr[] = {10, 20, 30, 40, 50, 25};\n    for (int x : arr) root = insert(root, x);\n\n    cout << "中序遍历(值(平衡因子)): "; inOrder(root); cout << endl;\n    cout << "根结点: " << root->val << endl;\n    cout << "树高: " << getHeight(root) << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (18, '哈夫曼树构建与编码', '给定字符频次，构建哈夫曼树并生成前缀编码表', '#include <bits/stdc++.h>\nusing namespace std;\n\nunordered_map<char, string> huffmanCode;\n\nstruct HuffNode {\n    char ch;\n    int freq;\n    HuffNode *left, *right;\n    HuffNode(char c, int f) : ch(c), freq(f), left(nullptr), right(nullptr) {}\n};\n\nstruct Cmp {\n    bool operator()(HuffNode* a, HuffNode* b) { return a->freq > b->freq; }\n};\n\nvoid encode(HuffNode* root, string code) {\n    if (!root) return;\n    if (!root->left && !root->right)\n        huffmanCode[root->ch] = code;\n    encode(root->left, code + "0");\n    encode(root->right, code + "1");\n}\n\nHuffNode* buildHuffman(unordered_map<char, int>& freq) {\n    priority_queue<HuffNode*, vector<HuffNode*>, Cmp> pq;\n    for (auto& p : freq)\n        pq.push(new HuffNode(p.first, p.second));\n\n    while (pq.size() > 1) {\n        HuffNode* left = pq.top(); pq.pop();\n        HuffNode* right = pq.top(); pq.pop();\n        HuffNode* parent = new HuffNode(\'\\0\', left->freq + right->freq);\n        parent->left = left;\n        parent->right = right;\n        pq.push(parent);\n    }\n    return pq.top();\n}\n\nint main() {\n    unordered_map<char, int> freq = {\n        {\'a\', 5}, {\'b\', 9}, {\'c\', 12}, {\'d\', 13}, {\'e\', 16}, {\'f\', 45}\n    };\n\n    HuffNode* root = buildHuffman(freq);\n    encode(root, "");\n\n    int wpl = 0;\n    for (auto& p : huffmanCode) {\n        cout << p.first << ": " << p.second << endl;\n        wpl += freq[p.first] * p.second.length();\n    }\n    cout << "WPL = " << wpl << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (11, '动态顺序表完整实现', '包含插入、删除、查找、扩容等核心操作的动态数组实现', '#include <bits/stdc++.h>\nusing namespace std;\n\nclass SeqList {\nprivate:\n    int* data;\n    int capacity;\n    int size;\n\n    void resize(int newCap) {\n        int* newData = new int[newCap];\n        for (int i = 0; i < size; i++)\n            newData[i] = data[i];\n        delete[] data;\n        data = newData;\n        capacity = newCap;\n    }\n\npublic:\n    SeqList(int initCap = 4) : size(0), capacity(initCap) {\n        data = new int[capacity];\n    }\n\n    ~SeqList() { delete[] data; }\n\n    bool insert(int pos, int val) {\n        if (pos < 1 || pos > size + 1) return false;\n        if (size >= capacity) resize(capacity * 2);\n        for (int i = size; i >= pos; i--)\n            data[i] = data[i - 1];\n        data[pos - 1] = val;\n        size++;\n        return true;\n    }\n\n    bool remove(int pos, int& removedVal) {\n        if (pos < 1 || pos > size || size == 0) return false;\n        removedVal = data[pos - 1];\n        for (int i = pos; i < size; i++)\n            data[i - 1] = data[i];\n        size--;\n        return true;\n    }\n\n    int find(int target) const {\n        for (int i = 0; i < size; i++)\n            if (data[i] == target)\n                return i + 1;\n        return 0;\n    }\n\n    int get(int pos) const {\n        if (pos < 1 || pos > size) throw out_of_range("Index out of range");\n        return data[pos - 1];\n    }\n\n    int length() const { return size; }\n    bool empty() const { return size == 0; }\n\n    void print() const {\n        cout << "[";\n        for (int i = 0; i < size; i++) {\n            cout << data[i];\n            if (i < size - 1) cout << ", ";\n        }\n        cout << "]" << endl;\n    }\n};\n\nint main() {\n    SeqList list(4);\n    list.insert(1, 10);\n    list.insert(2, 20);\n    list.insert(3, 30);\n    list.print();\n\n    list.insert(2, 15);\n    cout << "插入15后: ";\n    list.print();\n\n    int removed;\n    list.remove(3, removed);\n    cout << "删除了 " << removed << ": ";\n    list.print();\n\n    cout << "查找20的位置: " << list.find(20) << endl;\n    cout << "当前长度: " << list.length() << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (12, '完整单链表类实现', '含头节点、尾插法、按位插入/删除、按值查找、遍历输出', '#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Node {\n    int data;\n    Node* next;\n    Node(int val) : data(val), next(nullptr) {}\n};\n\nclass LinkedList {\nprivate:\n    Node* head;\n    int len;\n\npublic:\n    LinkedList() : len(0) {\n        head = new Node(0);   // 头节点\n    }\n\n    ~LinkedList() {\n        Node* p = head;\n        while (p) {\n            Node* tmp = p->next;\n            delete p;\n            p = tmp;\n        }\n    }\n\n    // 尾插法\n    void pushBack(int val) {\n        Node* newNode = new Node(val);\n        Node* tail = head;\n        while (tail->next) tail = tail->next;\n        tail->next = newNode;\n        len++;\n    }\n\n    // 头插法\n    void pushFront(int val) {\n        Node* newNode = new Node(val);\n        newNode->next = head->next;\n        head->next = newNode;\n        len++;\n    }\n\n    // 按位插入（pos从1开始）\n    bool insert(int pos, int val) {\n        if (pos < 1 || pos > len + 1) return false;\n        Node* p = head;\n        for (int i = 0; i < pos - 1; i++)\n            p = p->next;\n        Node* newNode = new Node(val);\n        newNode->next = p->next;\n        p->next = newNode;\n        len++;\n        return true;\n    }\n\n    // 按位删除\n    bool removeAt(int pos, int& removedVal) {\n        if (pos < 1 || pos > len) return false;\n        Node* p = head;\n        for (int i = 0; i < pos - 1; i++)\n            p = p->next;\n        Node* q = p->next;\n        removedVal = q->data;\n        p->next = q->next;\n        delete q;\n        len--;\n        return true;\n    }\n\n    // 按值查找，返回位序（从1开始），找不到返回0\n    int find(int target) const {\n        Node* p = head->next;\n        int idx = 1;\n        while (p) {\n            if (p->data == target) return idx;\n            p = p->next;\n            idx++;\n        }\n        return 0;\n    }\n\n    int length() const { return len; }\n\n    void print() const {\n        Node* p = head->next;\n        cout << "List(" << len << "): ";\n        while (p) {\n            cout << p->data;\n            if (p->next) cout << " -> ";\n            p = p->next;\n        }\n        cout << " -> NULL" << endl;\n    }\n};\n\nint main() {\n    LinkedList list;\n    list.pushBack(10);\n    list.pushBack(20);\n    list.pushBack(30);\n    list.print();\n\n    list.pushFront(5);\n    cout << "头插5后: ";\n    list.print();\n\n    list.insert(3, 15);\n    cout << "在第3位插入15后: ";\n    list.print();\n\n    int removed;\n    list.removeAt(2, removed);\n    cout << "删除第2位的元素(" << removed << ")后: ";\n    list.print();\n\n    cout << "查找20的位置: " << list.find(20) << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (13, '顺序栈完整实现与应用', '实现顺序栈，并用栈检测括号匹配', '#include <bits/stdc++.h>\nusing namespace std;\n\ntemplate<typename T, int MAX_SIZE = 100>\nclass Stack {\nprivate:\n    T data[MAX_SIZE];\n    int top;\npublic:\n    Stack() : top(-1) {}\n\n    bool isEmpty() const { return top == -1; }\n    bool isFull() const { return top == MAX_SIZE - 1; }\n    int size() const { return top + 1; }\n\n    bool push(const T& x) {\n        if (isFull()) return false;\n        data[++top] = x;\n        return true;\n    }\n\n    bool pop(T& x) {\n        if (isEmpty()) return false;\n        x = data[top--];\n        return true;\n    }\n\n    bool peek(T& x) const {\n        if (isEmpty()) return false;\n        x = data[top];\n        return true;\n    }\n};\n\n// 应用:括号匹配检测\nbool isBalanced(const string& expr) {\n    Stack<char> st;\n    unordered_map<char, char> match = {{\')\', \'(\'}, {\']\', \'[\'}, {\'}\', \'{\'}};\n    set<char> open = {\'(\', \'[\', \'{\'};\n    set<char> close = {\')\', \']\', \'}\'};\n\n    for (char c : expr) {\n        if (open.count(c)) {\n            st.push(c);\n        } else if (close.count(c)) {\n            char topChar;\n            if (!st.peek(topChar) || topChar != match[c])\n                return false;\n            st.pop(topChar);\n        }\n    }\n    return st.isEmpty();\n}\n\n// 应用:十进制转任意进制\nstring toBase(int num, int base) {\n    if (num == 0) return "0";\n    Stack<int> st;\n    string digits = "0123456789ABCDEF";\n    while (num > 0) {\n        st.push(num % base);\n        num /= base;\n    }\n    string result;\n    char c;\n    while (st.pop(c))\n        result += digits[c];\n    return result;\n}\n\nint main() {\n    // 括号匹配测试\n    cout << boolalpha;\n    cout << "{[()]}" << " 匹配? " << isBalanced("{[()]}") << endl;\n    cout << "{[(])}" << " 匹配? " << isBalanced("{[(])}") << endl;\n    cout << "(()" << " 匹配? " << isBalanced("(()") << endl;\n\n    // 进制转换测试\n    cout << "255 转16进制 = " << toBase(255, 16) << endl;\n    cout << "100 转8进制 = " << toBase(100, 8) << endl;\n    cout << "42 转2进制 = " << toBase(42, 2) << endl;\n\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (14, '循环队列完整实现', '采用牺牲一个单元的方案，支持入队、出队、判空、判满、获取长度', '#include <bits/stdc++.h>\nusing namespace std;\n\ntemplate<typename T, int MAX_SIZE = 10>\nclass CircularQueue {\nprivate:\n    T data[MAX_SIZE];\n    int front, rear;\n\npublic:\n    CircularQueue() : front(0), rear(0) {}\n\n    bool isEmpty() const { return front == rear; }\n    bool isFull() const { return (rear + 1) % MAX_SIZE == front; }\n    int size() const { return (rear - front + MAX_SIZE) % MAX_SIZE; }\n\n    bool enQueue(const T& x) {\n        if (isFull()) return false;\n        data[rear] = x;\n        rear = (rear + 1) % MAX_SIZE;\n        return true;\n    }\n\n    bool deQueue(T& x) {\n        if (isEmpty()) return false;\n        x = data[front];\n        front = (front + 1) % MAX_SIZE;\n        return true;\n    }\n\n    bool getFront(T& x) const {\n        if (isEmpty()) return false;\n        x = data[front];\n        return true;\n    }\n\n    void print() const {\n        cout << "Queue[" << size() << "/" << MAX_SIZE - 1 << "]: front=";\n        int f = front;\n        while (f != rear) {\n            cout << data[f];\n            f = (f + 1) % MAX_SIZE;\n            if (f != rear) cout << " <- ";\n        }\n        cout << "= rear" << endl;\n    }\n};\n\nint main() {\n    CircularQueue<int> q;\n\n    cout << "--- 入队 1~7 ---" << endl;\n    for (int i = 1; i <= 7; i++) {\n        q.enQueue(i);\n        cout << "enQueue(" << i << ") -> ";\n        q.print();\n    }\n\n    cout << "\\n--- 出队 3 次 ---" << endl;\n    int val;\n    for (int i = 0; i < 3; i++) {\n        q.deQueue(val);\n        cout << "deQueue() = " << val << " -> ";\n        q.print();\n    }\n\n    cout << "\\n--- 再入队 8~9 ---" << endl;\n    for (int i = 8; i <= 9; i++) {\n        q.enQueue(i);\n        cout << "enQueue(" << i << ") -> ";\n        q.print();\n    }\n\n    cout << "\\n队空? " << (q.isEmpty() ? "是" : "否") << endl;\n    cout << "队满? " << (q.isFull() ? "是" : "否") << endl;\n    cout << "当前长度: " << q.size() << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (7, '列举法与描述法的程序表示', '用数组和谓词函数分别模拟列举法和描述法', '#include <bits/stdc++.h>\nusing namespace std;\n\nvoid enumerateSet(const vector<int>& A) {\n    cout << "列举法: A = {";\n    for (size_t i = 0; i < A.size(); i++) {\n        cout << A[i];\n        if (i + 1 < A.size()) cout << ", ";\n    }\n    cout << "}" << endl;\n}\n\nvoid descriptiveSet(int n) {\n    cout << "描述法: B = {x | x 是1到" << n << "的正偶数} = {";\n    bool first = true;\n    for (int x = 2; x <= n; x += 2) {\n        if (!first) cout << ", ";\n        cout << x;\n        first = false;\n    }\n    cout << "}" << endl;\n}\n\nint main() {\n    vector<int> A = {1, 2, 3, 4, 5};\n    enumerateSet(A);\n    descriptiveSet(10);\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (8, '隶属关系与子集判断', '判断元素是否属于集合，以及判断子集关系', '#include <bits/stdc++.h>\nusing namespace std;\n\nbool isMember(const set<int>& S, int x) {\n    return S.count(x) > 0;\n}\n\nbool isSubset(const set<int>& A, const set<int>& B) {\n    for (int x : A) {\n        if (!B.count(x)) return false;\n    }\n    return true;\n}\n\nint main() {\n    set<int> A = {1, 2, 3};\n    set<int> B = {1, 2, 3, 4, 5};\n\n    cout << "3 ∈ A: " << (isMember(A, 3) ? "true" : "false") << endl;\n    cout << "4 ∈ A: " << (isMember(A, 4) ? "true" : "false") << endl;\n    cout << "A ⊆ B: " << (isSubset(A, B) ? "true" : "false") << endl;\n    cout << "B ⊆ A: " << (isSubset(B, A) ? "true" : "false") << endl;\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (9, '集合基本运算实现', '实现并集、交集、差集、对称差', '#include <bits/stdc++.h>\nusing namespace std;\n\nset<int> setUnion(const set<int>& A, const set<int>& B) {\n    set<int> result = A;\n    result.insert(B.begin(), B.end());\n    return result;\n}\n\nset<int> setIntersection(const set<int>& A, const set<int>& B) {\n    set<int> result;\n    for (int x : A) {\n        if (B.count(x)) result.insert(x);\n    }\n    return result;\n}\n\nset<int> setDifference(const set<int>& A, const set<int>& B) {\n    set<int> result;\n    for (int x : A) {\n        if (!B.count(x)) result.insert(x);\n    }\n    return result;\n}\n\nset<int> setSymmetricDiff(const set<int>& A, const set<int>& B) {\n    auto diff1 = setDifference(A, B);\n    auto diff2 = setDifference(B, A);\n    return setUnion(diff1, diff2);\n}\n\nvoid printSet(const string& name, const set<int>& S) {\n    cout << name << " = {";\n    bool first = true;\n    for (int x : S) {\n        if (!first) cout << ", ";\n        cout << x;\n        first = false;\n    }\n    cout << "}" << endl;\n}\n\nint main() {\n    set<int> A = {1, 2, 3, 4};\n    set<int> B = {3, 4, 5, 6};\n    printSet("A", A);\n    printSet("B", B);\n    printSet("A ∪ B", setUnion(A, B));\n    printSet("A ∩ B", setIntersection(A, B));\n    printSet("A - B", setDifference(A, B));\n    printSet("A △ B", setSymmetricDiff(A, B));\n    return 0;\n}', 'C++', 0);
INSERT INTO code_example (knowledge_point_id, title, description, code, language, sort_order) VALUES (10, '哈希集合实现', '用哈希表实现集合的插入、查找、删除操作', '#include <bits/stdc++.h>\nusing namespace std;\n\nclass HashSet {\n    vector<list<int>> table;\n    int capacity;\n    size_t hash(int x) { return ((size_t)x * 2654435761u) % capacity; }\npublic:\n    HashSet(int cap = 1009) : capacity(cap), table(cap) {}\n    bool insert(int x) {\n        size_t idx = hash(x);\n        for (int v : table[idx]) if (v == x) return false;\n        table[idx].push_back(x);\n        return true;\n    }\n    bool contains(int x) {\n        size_t idx = hash(x);\n        for (int v : table[idx]) if (v == x) return true;\n        return false;\n    }\n    bool remove(int x) {\n        size_t idx = hash(x);\n        auto& bucket = table[idx];\n        for (auto it = bucket.begin(); it != bucket.end(); ++it) {\n            if (*it == x) { bucket.erase(it); return true; }\n        }\n        return false;\n    }\n    void printAll() {\n        cout << "{";\n        bool first = true;\n        for (auto& bucket : table)\n            for (int v : bucket) {\n                if (!first) cout << ", ";\n                cout << v;\n                first = false;\n            }\n        cout << "}" << endl;\n    }\n};\n\nint main() {\n    HashSet s;\n    s.insert(10); s.insert(20); s.insert(30);\n    cout << "contains(20): " << (s.contains(20) ? "true" : "false") << endl;\n    cout << "contains(99): " << (s.contains(99) ? "true" : "false") << endl;\n    s.remove(20);\n    cout << "after remove(20): "; s.printAll();\n    return 0;\n}', 'C++', 0);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (19, '邻接表的构建与输出', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n\nint adj[1000][1000];\nint deg[1000];\n\nint cmp(const void* a, const void* b) {\n    return *(int*)a - *(int*)b;\n}\n\nint main() {\n    int n, m;\n    scanf("%d %d", &n, &m);\n    for (int i = 0; i < m; i++) {\n        int u, v;\n        scanf("%d %d", &u, &v);\n        adj[u][deg[u]++] = v;\n        adj[v][deg[v]++] = u;\n    }\n    for (int i = 0; i < n; i++) {\n        qsort(adj[i], deg[i], sizeof(int), cmp);\n        printf("%d: %d", i, deg[i]);\n        for (int j = 0; j < deg[i]; j++)\n            printf(" %d", adj[i][j]);\n        printf("\\n");\n    }\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n, m;\n    cin >> n >> m;\n    vector<vector<int>> adj(n);\n    for (int i = 0; i < m; i++) {\n        int u, v;\n        cin >> u >> v;\n        adj[u].push_back(v);\n        adj[v].push_back(u);\n    }\n    for (int i = 0; i < n; i++) {\n        sort(adj[i].begin(), adj[i].end());\n        cout << i << ": " << adj[i].size();\n        for (int v : adj[i])\n            cout << " " << v;\n        cout << endl;\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\nn, m = map(int, input().split())\nadj = [[] for _ in range(n)]\nfor _ in range(m):\n    u, v = map(int, input().split())\n    adj[u].append(v)\n    adj[v].append(u)\n\nfor i in range(n):\n    adj[i].sort()\n    print(f"{i}: {len(adj[i])}", *adj[i])\n```', '邻接表是图的常用存储方式，为每个顶点维护一个列表存储其邻接点。无向图中每条边需要在两个顶点的列表中各添加一次。输出前对邻接点排序可保证结果唯一性。', 3600, 1, '给定 n 个顶点（编号 0 至 n-1）和 m 条无向边，请构建邻接表并输出每个顶点的邻接点列表（按升序排列）。\n\n输入说明:\n第一行输入两个整数 n 和 m，分别表示顶点个数和边的条数。\n接下来 m 行，每行两个整数 u v，表示顶点 u 和 v 之间的一条无向边。\n\n输出说明:\n输出 n 行，第 i 行先输出顶点 i 及其邻接点的个数，再按升序输出所有邻接点。\n格式为 "i: cnt adj1 adj2 ..."，具体见样例。\n\n样例输入:\n4 4\n0 1\n0 2\n1 3\n2 3\n\n样例输出:\n0: 2 1 2\n1: 2 0 3\n2: 2 0 3\n3: 2 1 2\n\n备注:\n1 ≤ n ≤ 1000，0 ≤ m ≤ 10000。', '[{"input":"4 4\\n0 1\\n0 2\\n1 3\\n2 3","expectedOutput":"0: 2 1 2\\n1: 2 0 3\\n2: 2 0 3\\n3: 2 1 2"},{"input":"3 0","expectedOutput":"0: 0\\n1: 0\\n2: 0"},{"input":"2 1\\n0 1","expectedOutput":"0: 1 1\\n1: 1 0"},{"input":"5 3\\n0 1\\n2 3\\n3 4","expectedOutput":"0: 1 1\\n1: 1 0\\n2: 1 3\\n3: 2 2 4\\n4: 1 3"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (20, '连通分量个数', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <string.h>\n\nint adj[1000][1000];\nint deg[1000];\nint visited[1000];\nint n;\n\nvoid dfs(int v) {\n    visited[v] = 1;\n    for (int i = 0; i < deg[v]; i++) {\n        int u = adj[v][i];\n        if (!visited[u])\n            dfs(u);\n    }\n}\n\nint main() {\n    int m;\n    scanf("%d %d", &n, &m);\n    memset(deg, 0, sizeof(deg));\n    memset(visited, 0, sizeof(visited));\n    for (int i = 0; i < m; i++) {\n        int u, v;\n        scanf("%d %d", &u, &v);\n        adj[u][deg[u]++] = v;\n        adj[v][deg[v]++] = u;\n    }\n    int cnt = 0;\n    for (int i = 0; i < n; i++) {\n        if (!visited[i]) {\n            dfs(i);\n            cnt++;\n        }\n    }\n    printf("%d\\n", cnt);\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n, m;\n    cin >> n >> m;\n    vector<vector<int>> adj(n);\n    for (int i = 0; i < m; i++) {\n        int u, v;\n        cin >> u >> v;\n        adj[u].push_back(v);\n        adj[v].push_back(u);\n    }\n    vector<bool> visited(n, false);\n    int cnt = 0;\n    for (int i = 0; i < n; i++) {\n        if (!visited[i]) {\n            cnt++;\n            queue<int> q;\n            q.push(i);\n            visited[i] = true;\n            while (!q.empty()) {\n                int v = q.front(); q.pop();\n                for (int u : adj[v]) {\n                    if (!visited[u]) {\n                        visited[u] = true;\n                        q.push(u);\n                    }\n                }\n            }\n        }\n    }\n    cout << cnt << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nfrom collections import deque\n\nn, m = map(int, input().split())\nadj = [[] for _ in range(n)]\nfor _ in range(m):\n    u, v = map(int, input().split())\n    adj[u].append(v)\n    adj[v].append(u)\n\nvisited = [False] * n\ncnt = 0\nfor i in range(n):\n    if not visited[i]:\n        cnt += 1\n        q = deque([i])\n        visited[i] = True\n        while q:\n            v = q.popleft()\n            for u in adj[v]:\n                if not visited[u]:\n                    visited[u] = True\n                    q.append(u)\nprint(cnt)\n```', '从每个未访问的顶点出发执行一次 BFS 或 DFS，可遍历到该顶点所在连通分量的所有顶点。遍历的次数即为连通分量的个数。本题使用 BFS 实现（也可用 DFS），体现了图的遍历思想。', 3600, 2, '给定一个无向图，请统计图中连通分量的个数。连通分量是指图中极大连通子图。\n\n输入说明:\n第一行输入两个整数 n 和 m，分别表示顶点个数和边的条数。\n接下来 m 行，每行两个整数 u v，表示顶点 u 和 v 之间的一条无向边。\n\n输出说明:\n输出一个整数，表示连通分量的个数。\n\n样例输入:\n6 3\n0 1\n1 2\n3 4\n\n样例输出:\n3\n\n备注:\n1 ≤ n ≤ 1000，0 ≤ m ≤ 10000。顶点编号为 0 至 n-1。', '[{"input":"6 3\\n0 1\\n1 2\\n3 4","expectedOutput":"3"},{"input":"4 2\\n0 1\\n2 3","expectedOutput":"2"},{"input":"3 3\\n0 1\\n1 2\\n2 0","expectedOutput":"1"},{"input":"5 0","expectedOutput":"5"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (21, '单源最短路径', 'PROGRAMMING', 'MEDIUM', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <string.h>\n\n#define INF 0x3f3f3f3f\n\nint adj[1000][1000];\nint weight[1000][1000];\nint deg[1000];\nint dist[1000];\nint visited[1000];\n\nint main() {\n    int n, m, s;\n    scanf("%d %d %d", &n, &m, &s);\n    memset(deg, 0, sizeof(deg));\n    for (int i = 0; i < m; i++) {\n        int u, v, w;\n        scanf("%d %d %d", &u, &v, &w);\n        adj[u][deg[u]] = v;\n        weight[u][deg[u]] = w;\n        deg[u]++;\n        adj[v][deg[v]] = u;\n        weight[v][deg[v]] = w;\n        deg[v]++;\n    }\n    memset(visited, 0, sizeof(visited));\n    memset(dist, 0x3f, sizeof(dist));\n    dist[s] = 0;\n    for (int i = 0; i < n; i++) {\n        int u = -1, minD = INF;\n        for (int j = 0; j < n; j++) {\n            if (!visited[j] && dist[j] < minD) {\n                minD = dist[j];\n                u = j;\n            }\n        }\n        if (u == -1) break;\n        visited[u] = 1;\n        for (int j = 0; j < deg[u]; j++) {\n            int v = adj[u][j];\n            int w = weight[u][j];\n            if (!visited[v] && dist[u] + w < dist[v])\n                dist[v] = dist[u] + w;\n        }\n    }\n    for (int i = 0; i < n; i++) {\n        if (i) printf(" ");\n        if (dist[i] >= INF / 2) printf("-1");\n        else printf("%d", dist[i]);\n    }\n    printf("\\n");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nconst int INF = 0x3f3f3f3f;\n\nint main() {\n    int n, m, s;\n    cin >> n >> m >> s;\n    vector<vector<pair<int, int>>> adj(n);\n    for (int i = 0; i < m; i++) {\n        int u, v, w;\n        cin >> u >> v >> w;\n        adj[u].push_back({v, w});\n        adj[v].push_back({u, w});\n    }\n    vector<int> dist(n, INF);\n    dist[s] = 0;\n    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<>> pq;\n    pq.push({0, s});\n    while (!pq.empty()) {\n        auto [d, u] = pq.top(); pq.pop();\n        if (d > dist[u]) continue;\n        for (auto [v, w] : adj[u]) {\n            if (dist[u] + w < dist[v]) {\n                dist[v] = dist[u] + w;\n                pq.push({dist[v], v});\n            }\n        }\n    }\n    for (int i = 0; i < n; i++) {\n        if (i) cout << " ";\n        if (dist[i] >= INF / 2) cout << -1;\n        else cout << dist[i];\n    }\n    cout << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nimport heapq\n\nn, m, s = map(int, input().split())\nadj = [[] for _ in range(n)]\nfor _ in range(m):\n    u, v, w = map(int, input().split())\n    adj[u].append((v, w))\n    adj[v].append((u, w))\n\nINF = 10 ** 18\ndist = [INF] * n\ndist[s] = 0\npq = [(0, s)]\nwhile pq:\n    d, u = heapq.heappop(pq)\n    if d > dist[u]:\n        continue\n    for v, w in adj[u]:\n        if dist[u] + w < dist[v]:\n            dist[v] = dist[u] + w\n            heapq.heappush(pq, (dist[v], v))\n\nans = []\nfor i in range(n):\n    ans.append(str(dist[i] if dist[i] != INF else -1))\nprint(\' \'.join(ans))\n```', 'Dijkstra 算法求解非负权图单源最短路径。每次从距离源点最近的未确定顶点开始松弛邻接点，使用优先队列优化可将选最小距离的操作降为 O(log n)。C 语言版本使用朴素 O(n²) 实现，C++ 和 Python 使用优先队列优化。', 3600, 3, '给定一个 n 个顶点的带权无向图，求从源点 s 出发到所有顶点的最短距离。\n\n输入说明:\n第一行输入三个整数 n、m 和 s，分别表示顶点数、边数和源点编号。\n接下来 m 行，每行三个整数 u v w，表示顶点 u 和 v 之间有一条权值为 w 的边。\n\n输出说明:\n输出一行 n 个整数，分别表示从源点 s 到顶点 0 至 n-1 的最短距离。若不可达则输出 -1。\n\n样例输入:\n5 6 0\n0 1 4\n0 2 2\n1 2 1\n1 3 5\n2 3 8\n2 4 10\n\n样例输出:\n0 3 2 8 12\n\n备注:\n1 ≤ n ≤ 1000，0 ≤ m ≤ 10000，0 ≤ w ≤ 1000。保证边权非负。', '[{"input":"5 6 0\\n0 1 4\\n0 2 2\\n1 2 1\\n1 3 5\\n2 3 8\\n2 4 10","expectedOutput":"0 3 2 8 12"},{"input":"4 4 0\\n0 1 1\\n1 2 2\\n2 3 3\\n0 3 10","expectedOutput":"0 1 3 6"},{"input":"3 1 0\\n0 2 5","expectedOutput":"0 -1 5"},{"input":"4 3 2\\n0 1 1\\n1 2 2\\n2 3 4","expectedOutput":"3 2 0 4"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (22, '最小生成树权值和', 'PROGRAMMING', 'MEDIUM', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n\ntypedef struct {\n    int u, v, w;\n} Edge;\n\nEdge edges[100005];\nint parent[1005];\n\nint cmp(const void* a, const void* b) {\n    return ((Edge*)a)->w - ((Edge*)b)->w;\n}\n\nint find(int x) {\n    if (parent[x] != x)\n        parent[x] = find(parent[x]);\n    return parent[x];\n}\n\nint unite(int x, int y) {\n    int rx = find(x), ry = find(y);\n    if (rx == ry) return 0;\n    parent[rx] = ry;\n    return 1;\n}\n\nint main() {\n    int n, m;\n    scanf("%d %d", &n, &m);\n    for (int i = 0; i < m; i++)\n        scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].w);\n    qsort(edges, m, sizeof(Edge), cmp);\n    for (int i = 0; i < n; i++) parent[i] = i;\n    int sum = 0, cnt = 0;\n    for (int i = 0; i < m && cnt < n - 1; i++) {\n        if (unite(edges[i].u, edges[i].v)) {\n            sum += edges[i].w;\n            cnt++;\n        }\n    }\n    printf("%d\\n", cnt == n - 1 ? sum : -1);\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Edge {\n    int u, v, w;\n    bool operator<(const Edge& other) const {\n        return w < other.w;\n    }\n};\n\nclass UnionFind {\n    vector<int> parent;\npublic:\n    UnionFind(int n) : parent(n) {\n        for (int i = 0; i < n; i++) parent[i] = i;\n    }\n    int find(int x) {\n        if (parent[x] != x)\n            parent[x] = find(parent[x]);\n        return parent[x];\n    }\n    bool unite(int x, int y) {\n        int rx = find(x), ry = find(y);\n        if (rx == ry) return false;\n        parent[rx] = ry;\n        return true;\n    }\n};\n\nint main() {\n    int n, m;\n    cin >> n >> m;\n    vector<Edge> edges(m);\n    for (int i = 0; i < m; i++)\n        cin >> edges[i].u >> edges[i].v >> edges[i].w;\n    sort(edges.begin(), edges.end());\n    UnionFind uf(n);\n    int sum = 0, cnt = 0;\n    for (const auto& e : edges) {\n        if (uf.unite(e.u, e.v)) {\n            sum += e.w;\n            if (++cnt == n - 1) break;\n        }\n    }\n    cout << (cnt == n - 1 ? sum : -1) << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nclass UnionFind:\n    def __init__(self, n):\n        self.parent = list(range(n))\n    \n    def find(self, x):\n        if self.parent[x] != x:\n            self.parent[x] = self.find(self.parent[x])\n        return self.parent[x]\n    \n    def unite(self, x, y):\n        rx, ry = self.find(x), self.find(y)\n        if rx == ry:\n            return False\n        self.parent[rx] = ry\n        return True\n\nn, m = map(int, input().split())\nedges = []\nfor _ in range(m):\n    u, v, w = map(int, input().split())\n    edges.append((w, u, v))\n\nedges.sort()\nuf = UnionFind(n)\ntotal = cnt = 0\nfor w, u, v in edges:\n    if uf.unite(u, v):\n        total += w\n        cnt += 1\n        if cnt == n - 1:\n            break\n\nprint(total if cnt == n - 1 else -1)\n```', 'Kruskal 算法按边权从小到大排序，用并查集维护连通分量。依次选择边，若两端不在同一连通分量则加入生成树。选取 n-1 条边即得最小生成树。若无法选够 n-1 条边则图不连通。', 3600, 4, '给定一个 n 个顶点的带权无向连通图，求其最小生成树（MST）的权值和。\n\n输入说明:\n第一行输入两个整数 n 和 m，分别表示顶点数和边数。\n接下来 m 行，每行三个整数 u v w，表示顶点 u 和 v 之间有一条权值为 w 的边。\n\n输出说明:\n输出一个整数，表示最小生成树的权值和。若图不连通，输出 -1。\n\n样例输入:\n5 7\n0 1 2\n0 3 6\n0 4 4\n1 2 3\n1 3 8\n2 3 7\n3 4 5\n\n样例输出:\n14\n\n备注:\n1 ≤ n ≤ 1000，0 ≤ m ≤ 100000，边权为 int 范围内正整数。', '[{"input":"5 7\\n0 1 2\\n0 3 6\\n0 4 4\\n1 2 3\\n1 3 8\\n2 3 7\\n3 4 5","expectedOutput":"14"},{"input":"3 3\\n0 1 1\\n1 2 2\\n0 2 3","expectedOutput":"3"},{"input":"4 3\\n0 1 1\\n1 2 2\\n3 0 3","expectedOutput":"-1"},{"input":"2 1\\n0 1 10","expectedOutput":"10"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (19, '对于具有 n 个顶点的无向图，其邻接矩阵的大小为？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. n×n", "B. n×e", "C. e×e", "D. (n-1)×(n-1)"]', 'A', '邻接矩阵用二维数组表示顶点间的关系，n 个顶点需要 n×n 的矩阵存储。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (19, '邻接表适合存储哪种类型的图？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 稠密图", "B. 稀疏图", "C. 完全图", "D. 有向图"]', 'B', '邻接表的空间复杂度为 O(n+e)，适合边数远小于顶点数平方的稀疏图。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (19, '关于邻接矩阵和邻接表的比较，下列说法正确的是？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 邻接矩阵判断边是否存在的时间复杂度为 O(1)", "B. 邻接表的空间复杂度与边数无关", "C. 邻接矩阵适合稠密图", "D. 邻接表获取顶点度的效率更高"]', 'A,C', '邻接矩阵判断边存在性为 O(1)，适合稠密图；邻接表空间复杂度为 O(n+e)，与边数相关。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (19, '图的存储结构主要有___和___两种。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '邻接矩阵，邻接表', '邻接矩阵用二维数组存储，邻接表用链表数组存储，是最常用的两种图存储方式。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (19, '对于无向图的邻接矩阵，若 matrix[i][j]=1，则 matrix[j][i]=___；对于有向图，若存在从 i 到 j 的弧，则 matrix[i][j]=___，matrix[j][i]=___。', 'FILL_BLANK', 'MEDIUM', 'POSTGRADUATE', NULL, '1,1,0', '无向图的邻接矩阵是对称的，有向图的邻接矩阵不一定对称。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (20, '深度优先搜索（DFS）通常使用哪种数据结构实现？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 队列", "B. 栈", "C. 堆", "D. 树"]', 'B', 'DFS 可以用递归（系统栈）或显式栈实现，遵循后进先出的原则。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (20, '广度优先搜索（BFS）通常使用哪种数据结构实现？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 栈", "B. 队列", "C. 优先队列", "D. 链表"]', 'B', 'BFS 使用队列实现，遵循先进先出的原则，按层次遍历图的顶点。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (20, '关于 DFS 和 BFS 的复杂度，下列说法正确的是？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 邻接矩阵存储时，时间复杂度为 O(n²)", "B. 邻接表存储时，时间复杂度为 O(n+e)", "C. DFS 的空间复杂度为 O(n)", "D. BFS 的空间复杂度为 O(e)"]', 'A,B,C', 'DFS 和 BFS 时间复杂度相同，空间复杂度均为 O(n)，用于存储访问标记和栈/队列。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (20, '图的遍历序列不唯一，取决于哪些因素？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 起始顶点的选择", "B. 邻接点的访问顺序", "C. 存储结构", "D. 顶点的编号"]', 'A,B', '遍历序列取决于从哪个顶点开始以及访问邻接点的先后顺序。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (20, 'DFS 遍历图时，需要使用___记录已访问的顶点，避免重复访问。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '访问标记数组', '通常用布尔数组 visited[]标记顶点是否已访问，确保每个顶点只访问一次。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (20, '对于具有 n 个顶点、e 条边的图，使用邻接表存储时，DFS 和 BFS 的时间复杂度均为___，空间复杂度均为___。', 'FILL_BLANK', 'MEDIUM', 'POSTGRADUATE', NULL, 'O(n+e),O(n)', '每个顶点和每条边各访问一次，空间主要用于存储访问标记和栈/队列。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (21, 'Dijkstra 算法要求图中边的权值必须满足什么条件？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 所有权值相等", "B. 权值为整数", "C. 权值非负", "D. 权值为正"]', 'C', 'Dijkstra 算法基于贪心策略，要求边权非负，否则无法保证正确性。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (21, 'Floyd 算法的时间复杂度为？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. O(n)", "B. O(n²)", "C. O(n³)", "D. O(ne)"]', 'C', 'Floyd 算法使用三重循环，时间复杂度为 O(n³)，适合小规模图。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (21, '关于 Dijkstra 算法和 Floyd 算法的比较，下列说法正确的是？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. Dijkstra 求解单源最短路径", "B. Floyd 求解所有顶点对最短路径", "C. Dijkstra 可以处理负权边", "D. Floyd 可以处理负权边"]', 'A,B,D', 'Dijkstra 用于单源最短路径，不能处理负权边；Floyd 用于所有顶点对最短路径，可处理负权边（但不能处理负权回路）。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (21, '使用优先队列优化 Dijkstra 算法后，下列说法正确的是？', 'MULTIPLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 时间复杂度为 O((n+e)log n)", "B. 适合稀疏图", "C. 空间复杂度为 O(n)", "D. 可以处理负权边"]', 'A,B,C', '优先队列优化后时间复杂度为 O((n+e)log n)，适合稀疏图，但仍不能处理负权边。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (21, 'Dijkstra 算法采用的算法设计策略是___，Floyd 算法采用的算法设计策略是___。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '贪心，动态规划', 'Dijkstra 每次选择距离最近的顶点扩展，Floyd 通过逐步考虑中间顶点更新最短距离。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (21, 'Dijkstra 算法中，若使用邻接矩阵存储且不使用优先队列优化，时间复杂度为___；若使用邻接表和优先队列优化，时间复杂度为___。', 'FILL_BLANK', 'MEDIUM', 'POSTGRADUATE', NULL, 'O(n²),O((n+e)log n)', '朴素实现需要 O(n)找最小距离顶点，优化后用优先队列可将此操作降为 O(log n)。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (22, 'Prim 算法适合存储哪种类型的图？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 稀疏图", "B. 稠密图", "C. 有向图", "D. 无权图"]', 'B', 'Prim 算法使用邻接矩阵存储时时间复杂度为 O(n²)，适合边数较多的稠密图。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (22, 'Kruskal 算法中，判断两个顶点是否在同一连通分量使用什么数据结构？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 队列", "B. 栈", "C. 并查集", "D. 堆"]', 'C', '并查集可以高效地判断和合并连通分量，是 Kruskal 算法的关键数据结构。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (22, '关于 Prim 算法和 Kruskal 算法的比较，下列说法正确的是？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 两种算法都能得到相同的最小生成树权值和", "B. Prim 算法从顶点开始扩展", "C. Kruskal 算法从边开始选择", "D. 两种算法得到的生成树形态一定相同"]', 'A,B,C', '两种算法得到的最小生成树权值和相同，但树的形态可能不同；Prim 从顶点扩展，Kruskal 从边选择。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (22, '关于最小生成树算法的复杂度，下列说法正确的是？', 'MULTIPLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. Kruskal 算法时间复杂度为 O(e log e)", "B. Prim 算法朴素实现时间复杂度为 O(n²)", "C. Kruskal 算法空间复杂度为 O(n)", "D. Prim 算法适合稀疏图"]', 'A,B,C', 'Kruskal 主要消耗在边排序 O(e log e)，空间为并查集 O(n)；Prim 朴素实现 O(n²)，适合稠密图。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (22, '对于具有 n 个顶点的连通图，其最小生成树包含___条边。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, 'n-1', '生成树是包含所有顶点的极小连通子图，n 个顶点的树恰好有 n-1 条边。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (22, 'Kruskal 算法的核心思想是___，每次选择权值___的边，若该边连接的两个顶点不在同一___，则加入生成树。', 'FILL_BLANK', 'MEDIUM', 'POSTGRADUATE', NULL, '贪心，最小，连通分量', 'Kruskal 按边权从小到大排序，贪心地选择最小边，用并查集判断连通性。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (27, '直接插入排序', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n\nint main() {\n    int n, a[10005];\n    scanf("%d", &n);\n    for (int i = 0; i < n; i++) scanf("%d", &a[i]);\n\n    for (int i = 1; i < n; i++) {\n        int key = a[i];\n        int j = i - 1;\n        while (j >= 0 && a[j] > key) {\n            a[j + 1] = a[j];\n            j--;\n        }\n        a[j + 1] = key;\n    }\n\n    for (int i = 0; i < n; i++) {\n        if (i) printf(" ");\n        printf("%d", a[i]);\n    }\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n;\n    cin >> n;\n    vector<int> a(n);\n    for (int i = 0; i < n; i++) cin >> a[i];\n\n    for (int i = 1; i < n; i++) {\n        int key = a[i];\n        int j = i - 1;\n        while (j >= 0 && a[j] > key) {\n            a[j + 1] = a[j];\n            j--;\n        }\n        a[j + 1] = key;\n    }\n\n    for (int i = 0; i < n; i++) {\n        if (i) cout << \' \';\n        cout << a[i];\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\nn = int(input())\na = list(map(int, input().split()))\n\nfor i in range(1, n):\n    key = a[i]\n    j = i - 1\n    while j >= 0 and a[j] > key:\n        a[j + 1] = a[j]\n        j -= 1\n    a[j + 1] = key\n\nprint(\' \'.join(map(str, a)))\n```', '从第二个元素开始，将每个元素与前面已排序的部分从后向前比较，找到合适位置插入。插入排序对近乎有序的数组效率很高，最好情况 O(n)，最坏和平均 O(n^2)，且是稳定排序。', 3600, 1, '给定 n 个整数，请使用直接插入排序算法将其升序排列，并输出排序后的结果。\n\n输入说明:\n第一行输入一个整数 n，表示元素个数。\n第二行输入 n 个整数。\n\n输出说明:\n输出一行，为排序后的 n 个整数，用空格分隔。\n\n样例输入:\n5\n3 1 4 1 5\n\n样例输出:\n1 1 3 4 5\n\n备注:\n1 <= n <= 10000，所有元素均为 int 范围内的整数。', '[{"input":"5\\n3 1 4 1 5","expectedOutput":"1 1 3 4 5"},{"input":"1\\n42","expectedOutput":"42"},{"input":"6\\n9 8 7 6 5 4","expectedOutput":"4 5 6 7 8 9"},{"input":"4\\n2 2 2 2","expectedOutput":"2 2 2 2"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (28, '快速排序', 'PROGRAMMING', 'MEDIUM', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n\nvoid quickSort(int a[], int left, int right) {\n    if (left >= right) return;\n    int pivot = a[(left + right) / 2];\n    int i = left, j = right;\n    while (i <= j) {\n        while (a[i] < pivot) i++;\n        while (a[j] > pivot) j--;\n        if (i <= j) {\n            int t = a[i]; a[i] = a[j]; a[j] = t;\n            i++; j--;\n        }\n    }\n    quickSort(a, left, j);\n    quickSort(a, i, right);\n}\n\nint main() {\n    int n, a[100005];\n    scanf("%d", &n);\n    for (int i = 0; i < n; i++) scanf("%d", &a[i]);\n\n    quickSort(a, 0, n - 1);\n\n    for (int i = 0; i < n; i++) {\n        if (i) printf(" ");\n        printf("%d", a[i]);\n    }\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nvoid quickSort(vector<int>& a, int left, int right) {\n    if (left >= right) return;\n    int pivot = a[(left + right) / 2];\n    int i = left, j = right;\n    while (i <= j) {\n        while (a[i] < pivot) i++;\n        while (a[j] > pivot) j--;\n        if (i <= j) {\n            swap(a[i], a[j]);\n            i++; j--;\n        }\n    }\n    quickSort(a, left, j);\n    quickSort(a, i, right);\n}\n\nint main() {\n    int n;\n    cin >> n;\n    vector<int> a(n);\n    for (int i = 0; i < n; i++) cin >> a[i];\n\n    quickSort(a, 0, n - 1);\n\n    for (int i = 0; i < n; i++) {\n        if (i) cout << \' \';\n        cout << a[i];\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\ndef quick_sort(a, left, right):\n    if left >= right:\n        return\n    pivot = a[(left + right) // 2]\n    i, j = left, right\n    while i <= j:\n        while a[i] < pivot:\n            i += 1\n        while a[j] > pivot:\n            j -= 1\n        if i <= j:\n            a[i], a[j] = a[j], a[i]\n            i += 1\n            j -= 1\n    quick_sort(a, left, j)\n    quick_sort(a, i, right)\n\nn = int(input())\na = list(map(int, input().split()))\nquick_sort(a, 0, n - 1)\nprint(\' \'.join(map(str, a)))\n```', '快速排序采用分治思想，选取基准元素（pivot）将数组分为两部分，左侧均不大于 pivot，右侧均不小于 pivot，然后递归排序子数组。本题使用 Hoare 分区方案，取中间元素作为 pivot，平均时间复杂度 O(n log n)，最坏 O(n^2)。', 3600, 1, '给定 n 个整数，请使用快速排序算法将其升序排列，并输出排序后的结果。\n\n输入说明:\n第一行输入一个整数 n，表示元素个数。\n第二行输入 n 个整数。\n\n输出说明:\n输出一行，为排序后的 n 个整数，用空格分隔。\n\n样例输入:\n6\n5 2 8 1 9 3\n\n样例输出:\n1 2 3 5 8 9\n\n备注:\n1 <= n <= 100000，所有元素均为 int 范围内的整数。', '[{"input":"6\\n5 2 8 1 9 3","expectedOutput":"1 2 3 5 8 9"},{"input":"1\\n42","expectedOutput":"42"},{"input":"5\\n5 4 3 2 1","expectedOutput":"1 2 3 4 5"},{"input":"6\\n1 1 1 1 1 1","expectedOutput":"1 1 1 1 1 1"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (29, '第K小元素', 'PROGRAMMING', 'MEDIUM', 'INTERVIEW', NULL, '【C】\n```c\n#include <stdio.h>\n\nint selectKth(int a[], int left, int right, int k) {\n    if (left == right) return a[left];\n    int pivot = a[(left + right) / 2];\n    int i = left, j = right;\n    while (i <= j) {\n        while (a[i] < pivot) i++;\n        while (a[j] > pivot) j--;\n        if (i <= j) {\n            int t = a[i]; a[i] = a[j]; a[j] = t;\n            i++; j--;\n        }\n    }\n    if (k <= j) return selectKth(a, left, j, k);\n    if (k >= i) return selectKth(a, i, right, k);\n    return a[k];\n}\n\nint main() {\n    int n, k;\n    scanf("%d %d", &n, &k);\n    int a[100005];\n    for (int i = 0; i < n; i++) scanf("%d", &a[i]);\n\n    printf("%d", selectKth(a, 0, n - 1, k - 1));\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint selectKth(vector<int>& a, int left, int right, int k) {\n    if (left == right) return a[left];\n    int pivot = a[(left + right) / 2];\n    int i = left, j = right;\n    while (i <= j) {\n        while (a[i] < pivot) i++;\n        while (a[j] > pivot) j--;\n        if (i <= j) {\n            swap(a[i], a[j]);\n            i++; j--;\n        }\n    }\n    if (k <= j) return selectKth(a, left, j, k);\n    if (k >= i) return selectKth(a, i, right, k);\n    return a[k];\n}\n\nint main() {\n    int n, k;\n    cin >> n >> k;\n    vector<int> a(n);\n    for (int i = 0; i < n; i++) cin >> a[i];\n\n    cout << selectKth(a, 0, n - 1, k - 1);\n    return 0;\n}\n```\n\n【Python】\n```python\ndef select_kth(a, left, right, k):\n    if left == right:\n        return a[left]\n    pivot = a[(left + right) // 2]\n    i, j = left, right\n    while i <= j:\n        while a[i] < pivot:\n            i += 1\n        while a[j] > pivot:\n            j -= 1\n        if i <= j:\n            a[i], a[j] = a[j], a[i]\n            i += 1\n            j -= 1\n    if k <= j:\n        return select_kth(a, left, j, k)\n    if k >= i:\n        return select_kth(a, i, right, k)\n    return a[k]\n\nn, k = map(int, input().split())\na = list(map(int, input().split()))\nprint(select_kth(a, 0, n - 1, k - 1))\n```', '基于快速排序的分区思想（QuickSelect），每次分区后只需递归处理包含目标位置的一侧，平均时间复杂度 O(n)。选择排序的核心思想是每轮选出一个极值放到正确位置，QuickSelect 是这一思想的优化——通过分区一次排除一半元素，而不必每轮都扫描全部。', 3600, 1, '给定 n 个整数和一个正整数 k，请找出第 k 小的元素。要求时间复杂度优于 O(n log n)。\n\n输入说明:\n第一行输入两个整数 n 和 k。\n第二行输入 n 个整数。\n\n输出说明:\n输出第 k 小的元素。\n\n样例输入:\n5 3\n3 1 4 1 5\n\n样例输出:\n3\n\n备注:\n1 <= k <= n <= 100000，所有元素均为 int 范围内的整数。', '[{"input":"5 3\\n3 1 4 1 5","expectedOutput":"3"},{"input":"5 1\\n5 4 3 2 1","expectedOutput":"1"},{"input":"5 5\\n3 1 4 1 5","expectedOutput":"5"},{"input":"1 1\\n100","expectedOutput":"100"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (30, '逆序对计数', 'PROGRAMMING', 'HARD', 'INTERVIEW', NULL, '【C】\n```c\n#include <stdio.h>\n\nlong long merge(int a[], int tmp[], int left, int mid, int right) {\n    int i = left, j = mid + 1, k = left;\n    long long count = 0;\n    while (i <= mid && j <= right) {\n        if (a[i] <= a[j]) {\n            tmp[k++] = a[i++];\n        } else {\n            count += mid - i + 1;\n            tmp[k++] = a[j++];\n        }\n    }\n    while (i <= mid) tmp[k++] = a[i++];\n    while (j <= right) tmp[k++] = a[j++];\n    for (int p = left; p <= right; p++) a[p] = tmp[p];\n    return count;\n}\n\nlong long mergeSort(int a[], int tmp[], int left, int right) {\n    if (left >= right) return 0;\n    int mid = left + (right - left) / 2;\n    long long count = 0;\n    count += mergeSort(a, tmp, left, mid);\n    count += mergeSort(a, tmp, mid + 1, right);\n    count += merge(a, tmp, left, mid, right);\n    return count;\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    int a[100005], tmp[100005];\n    for (int i = 0; i < n; i++) scanf("%d", &a[i]);\n\n    printf("%lld", mergeSort(a, tmp, 0, n - 1));\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nlong long merge(vector<int>& a, vector<int>& tmp, int left, int mid, int right) {\n    int i = left, j = mid + 1, k = left;\n    long long count = 0;\n    while (i <= mid && j <= right) {\n        if (a[i] <= a[j]) {\n            tmp[k++] = a[i++];\n        } else {\n            count += mid - i + 1;\n            tmp[k++] = a[j++];\n        }\n    }\n    while (i <= mid) tmp[k++] = a[i++];\n    while (j <= right) tmp[k++] = a[j++];\n    for (int p = left; p <= right; p++) a[p] = tmp[p];\n    return count;\n}\n\nlong long mergeSort(vector<int>& a, vector<int>& tmp, int left, int right) {\n    if (left >= right) return 0;\n    int mid = left + (right - left) / 2;\n    long long count = 0;\n    count += mergeSort(a, tmp, left, mid);\n    count += mergeSort(a, tmp, mid + 1, right);\n    count += merge(a, tmp, left, mid, right);\n    return count;\n}\n\nint main() {\n    int n;\n    cin >> n;\n    vector<int> a(n), tmp(n);\n    for (int i = 0; i < n; i++) cin >> a[i];\n\n    cout << mergeSort(a, tmp, 0, n - 1);\n    return 0;\n}\n```\n\n【Python】\n```python\ndef merge_sort(a):\n    if len(a) <= 1:\n        return a, 0\n    mid = len(a) // 2\n    left, cnt_l = merge_sort(a[:mid])\n    right, cnt_r = merge_sort(a[mid:])\n    merged = []\n    i = j = 0\n    cnt = cnt_l + cnt_r\n    while i < len(left) and j < len(right):\n        if left[i] <= right[j]:\n            merged.append(left[i])\n            i += 1\n        else:\n            cnt += len(left) - i\n            merged.append(right[j])\n            j += 1\n    merged.extend(left[i:])\n    merged.extend(right[j:])\n    return merged, cnt\n\nn = int(input())\na = list(map(int, input().split()))\n_, ans = merge_sort(a)\nprint(ans)\n```', '在归并排序的合并阶段，当左半部分元素 a[i] 大于右半部分元素 a[j] 时，a[i] 到 a[mid] 之间的所有元素都与 a[j] 构成逆序对，因此累加 mid - i + 1。归并排序天然适合计数逆序对，时间复杂度 O(n log n)，空间复杂度 O(n)。', 3600, 1, '给定 n 个整数，请统计其中逆序对的数量。逆序对定义:若 i < j 且 a[i] > a[j]，则 (i, j) 为一个逆序对。\n\n输入说明:\n第一行输入一个整数 n，表示元素个数。\n第二行输入 n 个整数。\n\n输出说明:\n输出逆序对的数量。\n\n样例输入:\n5\n3 1 4 1 5\n\n样例输出:\n3\n\n备注:\n1 <= n <= 100000，所有元素均为 int 范围内的整数。', '[{"input":"5\\n3 1 4 1 5","expectedOutput":"3"},{"input":"4\\n1 2 3 4","expectedOutput":"0"},{"input":"4\\n4 3 2 1","expectedOutput":"6"},{"input":"6\\n2 4 1 3 5 6","expectedOutput":"3"}]');
