INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (30, '下列排序中，既稳定又时间复杂度为 O(n log n) 的是？', 'SINGLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 堆排序", "B. 快速排序", "C. 归并排序", "D. 希尔排序"]', 'C', '', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (30, '下列排序中，空间复杂度不是 O(1) 的是？', 'SINGLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 堆排序", "B. 快速排序", "C. 归并排序", "D. 插入排序"]', 'C', '', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (30, '下列排序中，最坏时间复杂度为 O(n²) 的有？', 'MULTIPLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 插入排序", "B. 冒泡排序", "C. 快速排序", "D. 归并排序"]', 'A,B,C', '', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (30, '排序算法中，___排序在任何情况下时间复杂度均为 O(n log n)。', 'FILL_BLANK', 'HARD', 'POSTGRADUATE', NULL, '堆排序', '', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (30, '若数据已基本有序，首选___排序。', 'FILL_BLANK', 'HARD', 'POSTGRADUATE', NULL, '插入', '', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (30, '下列排序中，适合链式存储的有？', 'MULTIPLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 插入排序", "B. 归并排序", "C. 基数排序", "D. 堆排序"]', 'A,B,C', '', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (23, '下列关于查找的说法正确的是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 查找只能用于有序数据", "B. 查找成功时通常返回元素位置或确认存在", "C. 静态查找允许频繁插入删除", "D. ASL 表示空间复杂度"]', 'B', '查找可在有序或无序数据上进行；静态查找以查询为主、一般不强调频繁修改；ASL 是平均查找长度，衡量比较次数而非空间。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (23, '平均查找长度 ASL 主要用于衡量什么？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 查找所需存储空间", "B. 查找过程中关键字比较次数的期望", "C. 哈希表装填因子", "D. 树的高度"]', 'B', 'ASL（Average Search Length）是查找过程中比较次数的期望值，用于比较不同查找算法的平均效率。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (23, '在数据集合中定位目标元素的过程称为___；若查找过程中数据基本不变，称为___查找。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '查找,静态', '查找是在数据集合中定位元素的过程；只查不改、数据基本不变时称为静态查找，与之相对的是动态查找。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (23, '长度为 n 的线性表采用顺序查找，最坏情况下需要比较的次数是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 1", "B. log₂n", "C. n", "D. n²"]', 'C', '最坏情况为目标在末尾或不存在，需扫描全部 n 个元素，比较次数为 n，时间复杂度 O(n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (23, '下列哪种场景最适合优先使用顺序查找？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 百万级有序静态数据", "B. 小规模无序数据且偶尔查询", "C. 高频用户名精确查询", "D. 需要频繁区间遍历"]', 'B', '顺序查找实现简单、无有序前提，适合数据量小、无序、查询不频繁的场景。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (23, '顺序查找中使用哨兵的主要目的是？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 提高哈希均匀性", "B. 减少循环中的边界判断", "C. 保证数据有序", "D. 降低树高"]', 'B', '哨兵法将目标值放在边界位置，循环中只需比较是否相等，可减少下标越界判断，降低常数开销。\n题目: 对长度为 n 的无序顺序表进行顺序查找，最坏情况下需要比较多少次？\n选项: ["A. 1", "B. log2 n", "C. n", "D. n/2"]\n答案: C\n解析: 最坏情况下目标元素在最后一个位置，或目标元素不存在，需要把 n 个元素全部比较一遍。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (23, '下列关于顺序查找说法正确的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 可用于数组和链表", "B. 不要求数据有序", "C. 平均时间复杂度为 O(log n)", "D. 额外空间复杂度通常为 O(1)"]', 'A,B,D', '顺序查找平均、最坏时间均为 O(n) 量级，不是 O(log n)。A、B、D 正确。\n题目: 关于顺序查找，下列说法正确的有？\n选项: ["A. 可以用于无序表", "B. 可以用于链表", "C. 时间复杂度一定是 O(log n)", "D. 哨兵法可以减少循环中的边界判断"]\n答案: A,B,D\n解析: 顺序查找不依赖有序性，也不依赖随机访问，数组和链表都能使用；它的时间复杂度为 O(n)，哨兵法只是减少判断次数，不改变复杂度数量级。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (23, '顺序查找在等概率假设下，成功查找的平均比较次数约为___；空间复杂度为___。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, 'n/2,O(1)', '成功查找平均约比较 n/2 次；仅需常数个辅助变量，空间 O(1)。\n题目: 顺序查找成功时，若每个元素被查到的概率相同，平均查找长度为___。\n答案: (n+1)/2\n解析: 第 1 到第 n 个位置被查到的比较次数分别为 1 到 n，等概率时平均值为 (1+2+...+n)/n = (n+1)/2。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (24, '二分查找能够正确工作的前提是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 数据存储在链表中", "B. 数据按关键字有序（或满足单调性）", "C. 数据元素互不相同", "D. 表长为 2 的幂"]', 'B', '二分依赖“折半后舍弃一半区间”的正确性，要求数据有序或具有单调判定性质。\n题目: 二分查找能够使用的前提是？\n选项: ["A. 表必须无序", "B. 表必须有序且支持随机访问", "C. 表必须用链表存储", "D. 表中元素必须互不相同"]\n答案: B\n解析: 二分查找每次需要访问中间元素，并根据有序性缩小查找范围，因此要求表有序且支持随机访问。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (24, '在长度为 n 的有序表中二分查找，时间复杂度为？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. O(1)", "B. O(n)", "C. O(log n)", "D. O(n log n)"]', 'C', '每轮将区间缩小一半，最多约 log₂n 轮，时间复杂度 O(log n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (24, '计算 mid 时推荐写成 left + (right - left) / 2，主要是为了？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 提高查找成功率", "B. 避免 left + right 整数溢出", "C. 支持链表存储", "D. 处理哈希冲突"]', 'B', '当 left、right 较大时，(left + right) 可能溢出；差值除法写法更安全。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (24, '下列属于二分查找常见应用或变体的有？', 'MULTIPLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 在有序数组中查找首个等于 x 的位置", "B. 在单调可行性问题上二分答案", "C. 在无序数组上直接折半", "D. 求有序插入位置"]', 'A,B,D', '无序数组不能直接二分（C 错误）。A、B、D 均为二分思想的有效应用。\n类别: POSTGRADUATE\n题目: 对长度为 1024 的有序数组进行二分查找，最坏情况下比较次数的数量级是？\n选项: ["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n log n)"]\n答案: B\n解析: 二分查找每次将查找区间缩小一半，最坏比较次数约为 log2 n + 1，因此数量级是 O(log n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (24, '左闭右闭区间 [left, right] 下，二分循环条件通常写为 left ___ right；若未找到目标，可返回___表示失败。', 'FILL_BLANK', 'MEDIUM', 'BASIC', NULL, '<=,-1', '左闭右闭常用 while (left <= right)；未命中常约定返回 -1。\n类别: INTERVIEW\n题目: 为避免 left + right 溢出，二分查找中 mid 推荐写成___。\n答案: left+(right-left)/2\n解析: left + (right - left) / 2 与 (left + right) / 2 结果等价，但前者避免了 left + right 超出整数范围。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (25, '哈希查找的平均时间复杂度（冲突较少时）一般为？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n²)"]', 'A', '理想情况下通过哈希函数直接定位，平均查找、插入接近 O(1)；冲突严重时会退化。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (25, '装填因子 α 的定义是？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 哈希函数计算次数", "B. 表中元素个数与表长的比值", "C. 链表平均长度", "D. 树高与结点数之比"]', 'B', '装填因子 α = 元素个数 / 哈希表长度，α 越大冲突概率越高。\n题目: 在哈希函数均匀、冲突较少的情况下，哈希表查找的平均时间复杂度通常是？\n选项: ["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n²)"]\n答案: A\n解析: 哈希表通过哈希函数直接定位桶，理想或平均情况下查找只需常数级操作。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (25, '下列属于哈希冲突处理方法的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 开放定址法", "B. 链地址法", "C. 再哈希法", "D. 中序遍历"]', 'A,B,C', '开放定址、链地址、再哈希均为经典冲突处理；中序遍历是树的操作，与哈希冲突无关。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (25, '关于哈希查找与二分查找，下列说法正确的是？', 'SINGLE_CHOICE', 'HARD', 'INTERVIEW', '["A. 哈希查找要求数据有序", "B. 哈希平均更快但不保证键有序", "C. 二分查找一定比哈希慢", "D. 二者都不能用于查找失败判定"]', 'B', '哈希不要求有序，平均 O(1) 但不支持按键有序遍历；二分要求有序；二者均可判定失败。\n题目: 下列哪些属于常见的哈希冲突处理方法？\n选项: ["A. 线性探测法", "B. 二次探测法", "C. 链地址法", "D. 拓扑排序"]\n答案: A,B,C\n解析: 线性探测法和二次探测法属于开放定址法，链地址法用链表等结构保存同一桶中的元素；拓扑排序是图算法，不是哈希冲突处理方法。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (25, '哈希表中，不同关键字映射到同一槽位的现象称为___；开放定址法删除元素时常用___标记避免探测链断裂。', 'FILL_BLANK', 'MEDIUM', 'BASIC', NULL, '冲突,墓碑', '映射到同一地址为冲突；开放定址删除常用墓碑（tombstone）保留探测路径。\n类别: POSTGRADUATE\n题目: 哈希表中，装入元素个数与表长之比称为___。\n答案: 负载因子\n解析: 负载因子反映哈希表的拥挤程度，负载因子过大时冲突概率通常会上升。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '二叉排序树（BST）查找时，若目标小于根结点关键字，应进入？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 左子树", "B. 右子树", "C. 父结点", "D. 任意子树"]', 'A', 'BST 性质:左子树 < 根 < 右子树，目标更小时进入左子树。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '将 1,2,3,…,n 按递增顺序依次插入空 BST，最坏查找时间复杂度为？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n log n)"]', 'C', '有序插入会使 BST 退化为单链，树高为 n，查找最坏 O(n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, 'AVL 树相比普通 BST 在查找上的主要优势是？', 'SINGLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 不需要比较", "B. 最坏查找时间稳定在 O(log n)", "C. 空间复杂度 O(1)", "D. 不要求关键字有序"]', 'B', 'AVL 通过旋转保持平衡，树高 O(log n)，最坏查找稳定；BST 可能退化为 O(n)。\n题目: B树适合外存查找的主要原因是？\n选项: ["A. 每个结点只能有两个孩子", "B. 树高较低，可以减少磁盘访问次数", "C. 所有数据只能存在根结点", "D. 查找一定不需要比较关键字"]\n答案: B\n解析: B树是多路平衡查找树，一个结点可存多个关键字和多个分支，树高较低，适合按磁盘页组织索引。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '下列关于树表查找说法正确的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. BST 支持中序遍历得到有序序列", "B. 查找路径长度与树高相关", "C. AVL 通过旋转维持平衡", "D. 树表查找平均一定为 O(1)"]', 'A,B,C', '树表查找平均一般为 O(log n) 量级（平衡时），不是 O(1)。A、B、C 正确。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, 'AVL 树中，结点平衡因子为___；AVL 要求平衡因子绝对值不超过___。', 'FILL_BLANK', 'MEDIUM', 'BASIC', NULL, '左子树高度减右子树高度,1', '平衡因子 = 左子树高度 - 右子树高度；AVL 规定 |平衡因子| ≤ 1。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '有序静态数据、查询为主、很少插入删除，较优先选用？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 顺序查找", "B. 二分查找", "C. 哈希查找", "D. 冒泡排序"]', 'B', '数据有序且静态，二分查找 O(log n) 高效；D 是排序算法不是查找。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '下列查找算法选型建议合理的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 无序小数据可优先考虑顺序查找", "B. 高频精确键查询可优先考虑哈希", "C. 频繁增删且需有序遍历可优先考虑 AVL/BST", "D. 任何场景都应优先用顺序查找"]', 'A,B,C', '选型需看数据特征，不存在万能最优；D 明显不合理。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '需要支持“查找某用户并列出其所有订单按时间排序”，用户表用哈希、订单表用索引树，这体现了？', 'SINGLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 只用一种查找算法即可", "B. 按场景组合不同查找结构", "C. 查找与排序无关", "D. 哈希一定能做区间查询"]', 'B', '工程上常按访问模式组合结构:哈希做精确命中，树或有序结构做范围与排序遍历。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '查找算法选型口诀:无序小数据用___；有序静态用___；高频精确查找用___。', 'FILL_BLANK', 'EASY', 'BASIC', '["A. 数据记录通常存放在叶子结点", "B. 叶子结点通常按关键字顺序相连", "C. 范围查询较方便", "D. 所有查找都在根结点结束"]', '顺序查找,二分查找,哈希查找', '常见口诀:无序小规模→顺序；有序静态→二分；高频精确键→哈希；动态有序→树表。\n类别: POSTGRADUATE\n题目: 关于 B+树，下列说法正确的有？\n选项: ["A. 数据记录通常存放在叶子结点", "B. 叶子结点通常按关键字顺序相连", "C. 范围查询较方便", "D. 所有查找都在根结点结束"]\n答案: A,B,C\n解析: B+树的内部结点主要起索引作用，查找通常走到叶子结点；叶子结点顺序相连，适合范围查询和顺序扫描。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '与普通二叉搜索树相比，m 阶 B树通过增加每个结点的分支数来降低___。', 'FILL_BLANK', 'HARD', 'INTERVIEW', NULL, '树高', '分支数越多，容纳相同数量关键字所需的层数通常越少，这也是 B树适合数据库索引的重要原因。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (24, '有序数组查找', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n\nint main() {\n    int n, key;\n    scanf("%d %d", &n, &key);\n    int a[100000];\n    for (int i = 0; i < n; i++) {\n        scanf("%d", &a[i]);\n    }\n\n    int left = 0, right = n - 1;\n    while (left <= right) {\n        int mid = left + (right - left) / 2;\n        if (a[mid] == key) {\n            printf("%d", mid);\n            return 0;\n        } else if (a[mid] < key) {\n            left = mid + 1;\n        } else {\n            right = mid - 1;\n        }\n    }\n\n    printf("-1");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n, key;\n    cin >> n >> key;\n    vector<int> a(n);\n    for (int i = 0; i < n; i++) cin >> a[i];\n\n    int left = 0, right = n - 1;\n    while (left <= right) {\n        int mid = left + (right - left) / 2;\n        if (a[mid] == key) {\n            cout << mid;\n            return 0;\n        }\n        if (a[mid] < key) left = mid + 1;\n        else right = mid - 1;\n    }\n\n    cout << -1;\n    return 0;\n}\n```\n\n【Python】\n```python\nn, key = map(int, input().split())\na = list(map(int, input().split()))\n\nleft, right = 0, n - 1\nwhile left <= right:\n    mid = left + (right - left) // 2\n    if a[mid] == key:\n        print(mid)\n        break\n    if a[mid] < key:\n        left = mid + 1\n    else:\n        right = mid - 1\nelse:\n    print(-1)\n```', '数组已经升序排列，因此每次比较中间元素后，可以排除一半区间。使用 left + (right - left) / 2 计算中点可避免整数溢出。', 3600, 1, '给定一个升序排列的整数数组和一个目标值 key，请使用二分查找判断 key 是否存在。\n\n输入说明:\n第一行输入两个整数 n 和 key，表示数组长度和目标值。\n第二行输入 n 个升序排列的整数。\n\n输出说明:\n若 key 存在，输出其下标；若不存在，输出 -1。下标从 0 开始。\n\n样例输入:\n6 9\n1 3 5 7 9 11\n\n样例输出:\n4\n\n备注:\n1 <= n <= 100000，数组元素和 key 均为 int 范围内整数。', '[{"input":"6 9\\n1 3 5 7 9 11","expectedOutput":"4"},{"input":"5 2\\n1 3 5 7 9","expectedOutput":"-1"},{"input":"1 10\\n10","expectedOutput":"0"},{"input":"4 1\\n1 2 3 4","expectedOutput":"0"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (25, '两数之和', 'PROGRAMMING', 'MEDIUM', 'INTERVIEW', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n\n#define SIZE 200003\n\ntypedef struct Node {\n    int value;\n    struct Node* next;\n} Node;\n\nint hashValue(int x) {\n    long long v = x;\n    if (v < 0) v = -v;\n    return (int)(v % SIZE);\n}\n\nint contains(Node* table[], int x) {\n    int idx = hashValue(x);\n    for (Node* p = table[idx]; p != NULL; p = p->next) {\n        if (p->value == x) return 1;\n    }\n    return 0;\n}\n\nvoid insert(Node* table[], int x) {\n    int idx = hashValue(x);\n    Node* node = (Node*)malloc(sizeof(Node));\n    node->value = x;\n    node->next = table[idx];\n    table[idx] = node;\n}\n\nint main() {\n    int n, target;\n    scanf("%d %d", &n, &target);\n    static Node* table[SIZE];\n\n    for (int i = 0; i < n; i++) {\n        int x;\n        scanf("%d", &x);\n        if (contains(table, target - x)) {\n            printf("true");\n            return 0;\n        }\n        insert(table, x);\n    }\n\n    printf("false");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n, target;\n    cin >> n >> target;\n    unordered_set<int> seen;\n\n    for (int i = 0; i < n; i++) {\n        int x;\n        cin >> x;\n        if (seen.count(target - x)) {\n            cout << "true";\n            return 0;\n        }\n        seen.insert(x);\n    }\n\n    cout << "false";\n    return 0;\n}\n```\n\n【Python】\n```python\nn, target = map(int, input().split())\nnums = list(map(int, input().split()))\nseen = set()\n\nfor x in nums:\n    if target - x in seen:\n        print(\'true\')\n        break\n    seen.add(x)\nelse:\n    print(\'false\')\n```', '遍历数组时，用哈希表保存已经出现过的数。对当前数 x，只需 O(1) 平均时间判断 target - x 是否出现过。先查找再插入，可以保证两个数来自不同位置。', 3600, 2, '给定 n 个整数和目标值 target，请判断是否存在两个不同位置的数，使它们的和等于 target。\n\n输入说明:\n第一行输入两个整数 n 和 target。\n第二行输入 n 个整数。\n\n输出说明:\n若存在，输出 true；否则输出 false。\n\n样例输入:\n5 9\n2 7 11 15 1\n\n样例输出:\ntrue\n\n备注:\n2 <= n <= 100000，数组元素和 target 均为 int 范围内整数。', '[{"input":"5 9\\n2 7 11 15 1","expectedOutput":"true"},{"input":"4 8\\n1 2 3 4","expectedOutput":"false"},{"input":"4 6\\n3 3 4 5","expectedOutput":"true"},{"input":"2 -1\\n-3 2","expectedOutput":"true"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (26, '叶子链表范围查询', 'PROGRAMMING', 'MEDIUM', 'EXAM', NULL, '【C】\n```c\n#include <stdio.h>\n\nint main() {\n    int m, k;\n    scanf("%d %d", &m, &k);\n    int total = m * k;\n    int printed = 0;\n    int values[1000000];\n\n    for (int i = 0; i < total; i++) {\n        scanf("%d", &values[i]);\n    }\n\n    int left, right;\n    scanf("%d %d", &left, &right);\n\n    for (int i = 0; i < total; i++) {\n        if (values[i] >= left && values[i] <= right) {\n            if (printed) printf(" ");\n            printf("%d", values[i]);\n            printed = 1;\n        }\n        if (values[i] > right) break;\n    }\n\n    if (!printed) printf("EMPTY");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int m, k;\n    cin >> m >> k;\n    vector<int> values(m * k);\n    for (int& x : values) cin >> x;\n\n    int left, right;\n    cin >> left >> right;\n\n    bool printed = false;\n    for (int x : values) {\n        if (x >= left && x <= right) {\n            if (printed) cout << \' \';\n            cout << x;\n            printed = true;\n        }\n        if (x > right) break;\n    }\n\n    if (!printed) cout << "EMPTY";\n    return 0;\n}\n```\n\n【Python】\n```python\nm, k = map(int, input().split())\nvalues = []\nfor _ in range(m):\n    values.extend(map(int, input().split()))\n\nleft, right = map(int, input().split())\nans = []\nfor x in values:\n    if left <= x <= right:\n        ans.append(str(x))\n    if x > right:\n        break\n\nprint(\' \'.join(ans) if ans else \'EMPTY\')\n```', 'B+树的叶子结点按关键字顺序连接，范围查询可以从第一个可能位置开始沿叶子链表顺序扫描，直到关键字超过右边界。本题用已经展开的叶子层模拟这一过程。', 3600, 3, 'B+树的叶子结点按关键字升序连接。现在给出若干个已经升序排列的叶子结点，请输出区间 [L, R] 内的所有关键字。\n\n输入说明:\n第一行输入两个整数 m 和 k，表示叶子结点个数和每个叶子结点中的关键字个数。\n接下来 m 行，每行输入 k 个升序整数，且整体从前到后也是升序的。\n最后一行输入两个整数 L 和 R。\n\n输出说明:\n按升序输出所有位于 [L, R] 的关键字，关键字之间用一个空格分隔。\n若没有符合条件的关键字，输出 EMPTY。\n\n样例输入:\n3 3\n3 8 12\n18 21 29\n35 40 48\n10 40\n\n样例输出:\n12 18 21 29 35 40\n\n备注:\n1 <= m, k <= 1000，所有关键字均为 int 范围内整数。', '[{"input":"3 3\\n3 8 12\\n18 21 29\\n35 40 48\\n10 40","expectedOutput":"12 18 21 29 35 40"},{"input":"2 4\\n1 2 4 8\\n16 32 64 128\\n5 15","expectedOutput":"8"},{"input":"2 2\\n10 20\\n30 40\\n41 50","expectedOutput":"EMPTY"},{"input":"1 5\\n1 2 3 4 5\\n1 5","expectedOutput":"1 2 3 4 5"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '在一棵深度为 k 的满二叉树中，结点总数为？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 2k", "B. 2^k", "C. 2^k - 1", "D. 2^(k+1) - 1"]', 'C', '满二叉树每层结点数依次为 1,2,4,…,2^(k-1)，总和为 2^k - 1。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '对一棵有 n 个结点的二叉树进行链式存储，空指针域的个数为？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. n", "B. n-1", "C. n+1", "D. 2n"]', 'C', '二叉链表共有 2n 个指针域。除根结点外每个结点被一个指针指向（n-1 个非空指针），其余指针为空，即 2n - (n-1) = n+1 个空指针域。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '已知某二叉树的前序遍历序列为 ABDECF，中序遍历序列为 DBEACF，该二叉树的后序遍历序列是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. DEBFCA", "B. DEBCFA", "C. DEBACF", "D. DEBAFC"]', 'A', '由前序确定根为 A，在中序中 A 的左边为左子树 DBE，右边为右子树 CF。对左子树:前序 BDE、中序 DBE，确定 B 为根，D 为 B 的左孩子，E 为 B 的右孩子。对右子树:前序 CF、中序 CF，确定 C 为根，F 为 C 的右孩子。后序为左-右-根，即 DEBFCA。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '一棵有 124 个叶结点的完全二叉树，最多有多少个结点？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. 247", "B. 248", "C. 249", "D. 250"]', 'B', '设 n0=124，则 n2=n0-1=123。完全二叉树最多有一个度为 1 的结点（n1=0 或 1）。当 n1=1 时结点最多，总数 = 124+1+123=248。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '关于二叉树遍历，下列哪些说法是正确的？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 已知前序和后序遍历序列可唯一确定一棵二叉树", "B. 已知前序和中序遍历序列可唯一确定一棵二叉树", "C. 层序遍历采用队列辅助实现", "D. 中序遍历二叉搜索树得到有序序列"]', 'B,C,D', '仅凭前序和后序无法唯一确定二叉树（如单支树左斜和右斜前序后序相同）。前序+中序或后序+中序可以唯一确定。层序遍历用队列 FIFO 实现，二叉搜索树左<根<右，中序自然有序。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '二叉树的三种深度优先遍历方式分别是___、___和___。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '先序遍历,中序遍历,后序遍历', '二叉树的深度优先遍历包括先序（根左右）、中序（左根右）、后序（左右根）三种。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '在有 n 个结点的二叉链表中，共有___个空指针域，利用这些空指针域指向某种遍历方式下的前驱和后继结点得到的二叉树称为___。', 'FILL_BLANK', 'MEDIUM', 'POSTGRADUATE', NULL, 'n+1,线索二叉树', '二叉链表 2n 个指针域，n-1 个被使用（每个非根结点被一个指针指向），余下 n+1 空指针域。将其改造为指向前驱/后继的线索，即为线索二叉树，可加速遍历。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '对二叉搜索树进行什么遍历可以得到递增有序序列？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 先序遍历", "B. 中序遍历", "C. 后序遍历", "D. 层序遍历"]', 'B', '二叉搜索树满足左子树 < 根 < 右子树，中序遍历（左-根-右）正好按从小到大的顺序访问所有结点。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '在二叉搜索树中插入一个新结点，该结点一定成为？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 根结点", "B. 内部结点", "C. 叶子结点", "D. 分支结点"]', 'C', '插入操作沿树向下搜索直到空位置，新结点直接插入到该空位置作为叶子结点，不会移动已有结点。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '在二叉搜索树中删除一个有两个孩子的结点时，通常采用的方法是？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 直接删除并置空", "B. 用其左孩子替代", "C. 用其右孩子替代", "D. 用其直接前驱或直接后继替换后删除"]', 'D', '双孩子结点删除:找到其直接前驱（左子树最大）或直接后继（右子树最小），用其值替换被删结点，再删除该前驱/后继（此时后者最多只有一个孩子，转化为简单情况）。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '将序列 {1,2,3,4,5} 依次插入一棵初始为空的二叉搜索树，该树的形态是？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. 完全二叉树", "B. 满二叉树", "C. 平衡二叉树", "D. 单支右斜树"]', 'D', '每次插入的值都大于已有所有结点，每次都走右孩子路径插入，最终形成一条只有右孩子的链，退化为线性结构。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '一棵二叉搜索树有 n 个结点，查找成功时的平均查找长度（ASL）在最好情况下约为？', 'SINGLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n log n)"]', 'B', '最好情况是二叉搜索树接近平衡（形态类似完全二叉树），树高为 O(log n)，每次比较沿树下一层，平均查找长度 O(log n)。最坏情况退化为单支树，ASL 为 O(n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '关于二叉搜索树的查找性能，下列哪些说法是正确的？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 查找效率取决于树的形状", "B. 平均查找时间复杂度为 O(log n)", "C. 最坏情况下时间复杂度为 O(n)", "D. 插入有序序列时退化为链表"]', 'A,B,C,D', '二叉搜索树的查找性能与树的高度紧密相关。平均高度 O(log n)，但插入有序序列时每次都在最远端插入，形成单支树，树高 O(n)，查找也退化为 O(n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '二叉搜索树（BST）的定义是:对于任意结点，其___子树的所有结点值均小于该结点值，其___子树的所有结点值均大于该结点值。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '左,右', 'BST 的核心性质:左 < 根 < 右，无重复键值。这一性质使得中序遍历 BST 得到有序序列。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '当二叉搜索树退化为单支树时，查找、插入、删除的时间复杂度均为___，为避免退化，引入了___。', 'FILL_BLANK', 'MEDIUM', 'INTERVIEW', NULL, 'O(n),平衡二叉树', '退化情况下树高等于结点数 n，操作退化为线性。AVL 树和红黑树等平衡二叉搜索树通过旋转维护平衡，保证树高 O(log n)，操作保持对数级效率。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, 'AVL树中结点的平衡因子定义为？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 左子树高度 + 右子树高度", "B. 左子树高度 - 右子树高度", "C. 右子树高度 - 左子树高度", "D. 左子树结点数 - 右子树结点数"]', 'B', '平衡因子 = 左子树高度 - 右子树高度。AVL 树要求每个结点平衡因子的绝对值不超过 1。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, '在 AVL 树中，当某结点平衡因子为 -2，其右孩子平衡因子为 -1 时，应进行什么旋转？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. LL 旋转（右单旋）", "B. RR 旋转（左单旋）", "C. LR 旋转（先左后右）", "D. RL 旋转（先右后左）"]', 'B', '平衡因子 -2 说明右子树比左子树高 2（右倾），右孩子平衡因子 -1 说明右孩子的右子树更高，为 RR 型，只需一次左单旋即可恢复平衡。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, '向一棵空的 AVL 树依次插入 3,2,1,4,5,6,7，插入 1 后触发的旋转类型是？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. LL 旋转", "B. RR 旋转", "C. LR 旋转", "D. RL 旋转"]', 'A', '插入 3,2 后结构为 3(左2)；插入 1 时，结点 3 的左子树高 2、右子树高 0，平衡因子为 2，且左孩子 2 的平衡因子为 1（左高），为 LL 型，需对 3 做右单旋。旋转后 2 成为根，3 为其右孩子。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, '向 AVL 树中依次插入 16,3,7,11,9，插入 9 后触发的旋转类型是？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. LL 旋转", "B. RR 旋转", "C. LR 旋转", "D. RL 旋转"]', 'C', '插入 16,3,7,11 后某结点失衡；再插入 9 时，失衡结点的左子树平衡因子为 -1（右高），整体平衡因子为 2（左高），为 LR 型，需先在左孩子处左旋、再对失衡结点右旋。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, '深度为 h 的 AVL 树，其最少结点数 N_h 满足的递推关系是？', 'SINGLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. N_h = N_(h-1) + N_(h-2)", "B. N_h = N_(h-1) + N_(h-2) + 1", "C. N_h = 2N_(h-1) + 1", "D. N_h = 2^(h-1) + N_(h-1)"]', 'B', '深度为 h 的 AVL 树最少结点:N_0=0, N_1=1, N_2=2，对于 h≥3，N_h = 1 + N_(h-1) + N_(h-2)，即根结点加深度分别为 h-1 和 h-2 的两棵最少结点子树。这个数列与斐波那契数列相关，N_h ≈ φ^h/√5。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, '在 AVL 树插入操作中，下列哪些说法是正确的？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 插入后可能需要从插入点向上回溯找失衡结点", "B. 找到第一个失衡结点并旋转后，其上祖先可能仍失衡", "C. 四种旋转操作的时间复杂度均为 O(1)", "D. 插入后最多只需要一次旋转即可恢复整体平衡"]', 'A,C,D', '插入后自底向上回溯找第一个失衡结点（平衡因子绝对值≥2），对其做一次旋转即可使整棵树恢复平衡（查找路径上第一个失衡结点修复后所有祖先都平衡）。旋转仅修改常量个指针，时间 O(1)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, 'AVL 树中平衡因子的合法取值为___、___和___。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '-1,0,1', 'AVL 树要求左右子树高度差不超过 1，平衡因子（左减右）只能是 -1、0、1。若某结点平衡因子绝对值大于等于 2，则失去平衡，需旋转调整。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, 'AVL 树的四种旋转分别为___、___、___和___。', 'FILL_BLANK', 'MEDIUM', 'INTERVIEW', NULL, 'LL,RR,LR,RL', 'LL 和 RR 为单旋转（右旋和左旋），LR 和 RL 为双旋转（先左后右和先右后左）。旋转名字表示失衡路径的形状。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '哈夫曼树又被称为？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 二叉搜索树", "B. 平衡二叉树", "C. 最优二叉树", "D. 完全二叉树"]', 'C', '哈夫曼树是一种带权路径长度（WPL）最小的二叉树，因此也称为最优二叉树。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '由 n 个叶子结点构成的哈夫曼树，共有多少个结点？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. n", "B. 2n", "C. 2n-1", "D. n^2"]', 'C', '哈夫曼树构建进行 n-1 次合并，每次合并产生一个新结点，加上原始的 n 个叶子，总共 2n-1 个结点。哈夫曼树是正则二叉树，没有度为 1 的结点。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '一组权值为 {2,3,4,7} 的叶子结点，构建哈夫曼树后的 WPL 为？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 28", "B. 29", "C. 30", "D. 31"]', 'C', '构建过程:(1)取 2,3 合并为 5；(2)取 4,5 合并为 9；(3)取 7,9 合并为 16。WPL = 2×3 + 3×3 + 4×2 + 7×1 = 6+9+8+7 = 30。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '对 n 个权值均不相同的字符进行哈夫曼编码，下列哪种说法是正确的？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. 哈夫曼编码是唯一的", "B. 每个字符的码长都相同", "C. 权值越大的字符码长越短", "D. 哈夫曼树是平衡二叉树"]', 'C', '哈夫曼树构建过程中合并的顺序可能不唯一（当两个最小权值相等时有多种选择），因此哈夫曼编码不一定唯一，但 WPL 一定最小。权值越大的字符越靠近根，码长越短，实现最优压缩。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '设有 5 个字符 {a,b,c,d,e}，出现频次分别为 {6,2,3,8,1}，则字符 a 的哈夫曼编码长度可能是？', 'SINGLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 1", "B. 2", "C. 3", "D. 4"]', 'B', '按频次从小到大构建:1+2=3→3+3=6→6+6=12→8+12=20。a(6) 在第三层合并，编码长度为 2。e(1)和b(2)深度最深为 3，a(6)和d(8)深度为 2，c(3)深度为 3，频次越高的字符越短。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '关于哈夫曼编码，下列哪些说法是正确的？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 哈夫曼编码是前缀编码", "B. 任何前缀编码都可以解码唯一", "C. 哈夫曼编码保证总编码长度最短", "D. 哈夫曼编码适用于等长编码压缩场景"]', 'A,B,C', '哈夫曼编码中任何字符的编码都不是另一字符编码的前缀（前缀码），解码时能唯一确定。哈夫曼编码是最优前缀码，保证总编码长度（WPL）最短。哈夫曼编码是不等长编码，频次高的字符码长短，适合不等频数据压缩。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '哈夫曼树的带权路径长度（WPL）等于所有___结点的___与___乘积之和。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '叶子,权值,路径长度', 'WPL = Σ w_i × l_i，其中 w_i 为叶子权值，l_i 为根到该叶子的边数。哈夫曼树在所有带权二叉树中 WPL 最小。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '在哈夫曼树中，左分支通常标记为___，右分支标记为___；从根到叶子的路径上这些标记组成的序列即该字符的___。', 'FILL_BLANK', 'MEDIUM', 'BASIC', NULL, '0,1,哈夫曼编码', '左 0 右 1 是约定（也可反过来）。路径上所有标记串接起来就是哈夫曼编码。由于叶子出现在树的不同位置，编码自然形成前缀码。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '二叉树遍历重建', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <string.h>\n\nchar pre[1005], in[1005];\n\nvoid post(int preL, int preR, int inL, int inR) {\n    if (preL > preR) return;\n    char root = pre[preL];\n    int pos = inL;\n    while (in[pos] != root) pos++;\n    int leftLen = pos - inL;\n    post(preL + 1, preL + leftLen, inL, pos - 1);\n    post(preL + leftLen + 1, preR, pos + 1, inR);\n    putchar(root);\n}\n\nint main() {\n    scanf("%s %s", pre, in);\n    int len = (int)strlen(pre);\n    post(0, len - 1, 0, len - 1);\n    printf("\\n");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nstring pre, in;\n\nvoid post(int preL, int preR, int inL, int inR) {\n    if (preL > preR) return;\n    char root = pre[preL];\n    int pos = (int)in.find(root, inL);\n    int leftLen = pos - inL;\n    post(preL + 1, preL + leftLen, inL, pos - 1);\n    post(preL + leftLen + 1, preR, pos + 1, inR);\n    cout << root;\n}\n\nint main() {\n    cin >> pre >> in;\n    post(0, (int)pre.size() - 1, 0, (int)in.size() - 1);\n    cout << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nimport sys\nsys.setrecursionlimit(10000)\n\ndef postorder(pre, preL, preR, inL, inR, in_idx):\n    if preL > preR:\n        return\n    root = pre[preL]\n    pos = in_idx[root]\n    left_len = pos - inL\n    postorder(pre, preL + 1, preL + left_len, inL, pos - 1, in_idx)\n    postorder(pre, preL + left_len + 1, preR, pos + 1, inR, in_idx)\n    print(root, end=\'\')\n\npre, inorder = input().split()\nin_idx = {c: i for i, c in enumerate(inorder)}\npostorder(pre, 0, len(pre) - 1, 0, len(inorder) - 1, in_idx)\nprint()\n```', '先序遍历的第一个节点是根节点。在中序遍历中找到根节点位置，左侧为左子树、右侧为右子树。递归重建左右子树，按"左-右-根"顺序输出即得后序遍历。', 3600, 1, '给定一棵二叉树的先序遍历和中序遍历序列（节点值用大写字母唯一标识），请重建该二叉树并输出其后序遍历序列。\n\n输入说明:\n一行，包含两个字符串 pre 和 in，以空格分隔，分别表示二叉树的先序遍历和中序遍历序列。\n\n输出说明:\n输出一行，为二叉树的后序遍历序列。\n\n样例输入:\nABDECFG DBEAFCG\n\n样例输出:\nDEBFGCA\n\n备注:\n节点数量不超过 1000，每个节点的值是大写字母 A~Z 且不重复。', '[{"input":"ABDECFG DBEAFCG","expectedOutput":"DEBFGCA"},{"input":"ABC ABC","expectedOutput":"CBA"},{"input":"A A","expectedOutput":"A"},{"input":"CBA ABC","expectedOutput":"ABC"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '验证二叉搜索树', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <limits.h>\n\ntypedef struct { int val, left, right; } Node;\nNode tree[1005];\n\nint valid(int idx, long long min, long long max) {\n    if (idx == -1) return 1;\n    if (tree[idx].val <= min || tree[idx].val >= max) return 0;\n    return valid(tree[idx].left, min, tree[idx].val) &&\n           valid(tree[idx].right, tree[idx].val, max);\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    for (int i = 0; i < n; i++)\n        scanf("%d %d %d", &tree[i].val, &tree[i].left, &tree[i].right);\n    printf(valid(0, LONG_MIN, LONG_MAX) ? "true\\n" : "false\\n");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Node { int val, left, right; };\nvector<Node> tree;\n\nbool valid(int idx, long long minV, long long maxV) {\n    if (idx == -1) return true;\n    if (tree[idx].val <= minV || tree[idx].val >= maxV) return false;\n    return valid(tree[idx].left, minV, tree[idx].val) &&\n           valid(tree[idx].right, tree[idx].val, maxV);\n}\n\nint main() {\n    int n;\n    cin >> n;\n    tree.resize(n);\n    for (int i = 0; i < n; i++)\n        cin >> tree[i].val >> tree[i].left >> tree[i].right;\n    cout << (valid(0, LONG_MIN, LONG_MAX) ? "true" : "false") << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nimport sys\nsys.setrecursionlimit(10000)\n\ndef valid(idx, minV, maxV):\n    if idx == -1:\n        return True\n    v = tree[idx][0]\n    if v <= minV or v >= maxV:\n        return False\n    l, r = tree[idx][1], tree[idx][2]\n    return valid(l, minV, v) and valid(r, v, maxV)\n\nn = int(input())\ntree = []\nfor _ in range(n):\n    val, left, right = map(int, input().split())\n    tree.append((val, left, right))\n\nprint(\'true\' if valid(0, float(\'-inf\'), float(\'inf\')) else \'false\')\n```', '利用二叉搜索树的性质:左子树所有节点值在 (min, root.val) 范围内，右子树所有节点值在 (root.val, max) 范围内。递归验证每个节点时传递上下界，初始上下界为负无穷到正无穷。若某节点值不在此范围内则判定为非法 BST。', 3600, 2, '给定一棵二叉树，判断它是否是一棵合法的二叉搜索树（BST）。\n\n二叉搜索树的定义:\n1. 若左子树不空，则左子树上所有节点的值均小于其根节点的值。\n2. 若右子树不空，则右子树上所有节点的值均大于其根节点的值。\n3. 左右子树也分别为二叉搜索树。\n\n输入说明:\n第一行输入一个整数 n，表示树的节点数量。\n接下来 n 行，每行包含三个整数 val left right，分别表示该节点的值、左孩子编号和右孩子编号。-1 表示空节点。根节点编号为 0。\n\n输出说明:\n若为二叉搜索树，输出 "true"；否则输出 "false"。\n\n样例输入:\n3\n2 1 2\n1 -1 -1\n3 -1 -1\n\n样例输出:\ntrue\n\n备注:\n节点数量 n ≤ 1000，节点值在 int 范围内。', '[{"input":"3\\n2 1 2\\n1 -1 -1\\n3 -1 -1","expectedOutput":"true"},{"input":"3\\n2 1 2\\n3 -1 -1\\n1 -1 -1","expectedOutput":"false"},{"input":"1\\n5 -1 -1","expectedOutput":"true"},{"input":"5\\n10 1 2\\n5 3 -1\\n15 -1 4\\n3 -1 -1\\n18 -1 -1","expectedOutput":"true"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, '判断平衡二叉树', 'PROGRAMMING', 'MEDIUM', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n\ntypedef struct { int val, left, right; } Node;\nNode tree[1005];\nint balanced;\n\nint height(int idx) {\n    if (idx == -1) return 0;\n    int lh = height(tree[idx].left);\n    int rh = height(tree[idx].right);\n    if (abs(lh - rh) > 1) balanced = 0;\n    return (lh > rh ? lh : rh) + 1;\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    for (int i = 0; i < n; i++)\n        scanf("%d %d %d", &tree[i].val, &tree[i].left, &tree[i].right);\n    balanced = 1;\n    height(0);\n    printf(balanced ? "true\\n" : "false\\n");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Node { int val, left, right; };\nvector<Node> tree;\nbool balanced;\n\nint height(int idx) {\n    if (idx == -1) return 0;\n    int lh = height(tree[idx].left);\n    int rh = height(tree[idx].right);\n    if (abs(lh - rh) > 1) balanced = false;\n    return max(lh, rh) + 1;\n}\n\nint main() {\n    int n;\n    cin >> n;\n    tree.resize(n);\n    for (int i = 0; i < n; i++)\n        cin >> tree[i].val >> tree[i].left >> tree[i].right;\n    balanced = true;\n    height(0);\n    cout << (balanced ? "true" : "false") << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nimport sys\nsys.setrecursionlimit(10000)\n\ndef check(idx):\n    if idx == -1:\n        return 0\n    lh = check(tree[idx][1])\n    rh = check(tree[idx][2])\n    if lh == -1 or rh == -1 or abs(lh - rh) > 1:\n        return -1\n    return max(lh, rh) + 1\n\nn = int(input())\ntree = []\nfor _ in range(n):\n    val, left, right = map(int, input().split())\n    tree.append((val, left, right))\n\nprint(\'true\' if check(0) != -1 else \'false\')\n```', '自底向上计算每个节点的高度，同时判断左右子树高度差。若发现不平衡则标记结果。使用-1作为特殊返回值可提前终止无效计算，提高效率。', 3600, 3, '给定一棵二叉树，判断它是否是一棵平衡二叉树。\n\n平衡二叉树的定义:二叉树中每个节点的左右子树高度差的绝对值不超过 1。\n\n输入说明:\n第一行输入一个整数 n，表示树的节点数量。\n接下来 n 行，每行包含三个整数 val left right，分别表示该节点的值、左孩子编号和右孩子编号。-1 表示空节点。根节点编号为 0。\n\n输出说明:\n若为平衡二叉树，输出 "true"；否则输出 "false"。\n\n样例输入:\n5\n1 1 2\n2 3 4\n3 -1 -1\n4 -1 -1\n5 -1 -1\n\n样例输出:\ntrue\n\n备注:\n节点数量 n ≤ 1000。', '[{"input":"5\\n1 1 2\\n2 3 4\\n3 -1 -1\\n4 -1 -1\\n5 -1 -1","expectedOutput":"true"},{"input":"4\\n1 -1 1\\n2 -1 2\\n3 -1 3\\n4 -1 -1","expectedOutput":"false"},{"input":"1\\n1 -1 -1","expectedOutput":"true"},{"input":"7\\n4 1 2\\n2 3 4\\n6 5 6\\n1 -1 -1\\n3 -1 -1\\n5 -1 -1\\n7 -1 -1","expectedOutput":"true"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '哈夫曼树的带权路径长度', 'PROGRAMMING', 'MEDIUM', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n\nint heap[2005];\nint size;\n\nvoid push(int x) {\n    int i = size++;\n    while (i > 0) {\n        int p = (i - 1) / 2;\n        if (heap[p] <= x) break;\n        heap[i] = heap[p];\n        i = p;\n    }\n    heap[i] = x;\n}\n\nint pop() {\n    int ret = heap[0];\n    int x = heap[--size];\n    int i = 0;\n    while (2 * i + 1 < size) {\n        int a = 2 * i + 1, b = 2 * i + 2;\n        if (b < size && heap[b] < heap[a]) a = b;\n        if (heap[a] >= x) break;\n        heap[i] = heap[a];\n        i = a;\n    }\n    heap[i] = x;\n    return ret;\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    size = 0;\n    for (int i = 0; i < n; i++) {\n        int x;\n        scanf("%d", &x);\n        push(x);\n    }\n    int wpl = 0;\n    while (size > 1) {\n        int a = pop(), b = pop();\n        int sum = a + b;\n        wpl += sum;\n        push(sum);\n    }\n    printf("%d\\n", wpl);\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n;\n    cin >> n;\n    priority_queue<int, vector<int>, greater<int>> pq;\n    for (int i = 0; i < n; i++) {\n        int x;\n        cin >> x;\n        pq.push(x);\n    }\n    int wpl = 0;\n    while (pq.size() > 1) {\n        int a = pq.top(); pq.pop();\n        int b = pq.top(); pq.pop();\n        int sum = a + b;\n        wpl += sum;\n        pq.push(sum);\n    }\n    cout << wpl << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nimport heapq\n\nn = int(input())\nweights = list(map(int, input().split()))\nheapq.heapify(weights)\nwpl = 0\nwhile len(weights) > 1:\n    a = heapq.heappop(weights)\n    b = heapq.heappop(weights)\n    s = a + b\n    wpl += s\n    heapq.heappush(weights, s)\nprint(wpl)\n```', '哈夫曼树构造的核心思想是贪心算法:每次取权值最小的两个叶节点合并为一个新节点（权值为两者之和），新节点重新放入集合，直到只剩一个节点。每次合并产生的和累加即为最终 WPL。使用小顶堆（优先队列）高效选出最小值。', 3600, 4, '给定 n 个叶节点的权值，构造一棵哈夫曼树，求其带权路径长度（WPL）。\n\n带权路径长度:从根节点到每个叶节点的路径长度与该叶节点权值的乘积之和。\n\n输入说明:\n第一行输入一个整数 n，表示叶节点的数量。\n第二行输入 n 个整数，以空格分隔，表示每个叶节点的权值。\n\n输出说明:\n输出一个整数，表示最小带权路径长度 WPL。\n\n样例输入:\n5\n1 2 3 4 5\n\n样例输出:\n33\n\n备注:\n1 ≤ n ≤ 1000，权值均为正整数且不超过 10000。', '[{"input":"5\\n1 2 3 4 5","expectedOutput":"33"},{"input":"5\\n5 5 5 5 5","expectedOutput":"60"},{"input":"1\\n10","expectedOutput":"0"},{"input":"4\\n1 1 1 1","expectedOutput":"8"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (15, '二叉树的最大深度', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n\ntypedef struct { int val, left, right; } Node;\nNode tree[1005];\n\nint maxDepth(int idx) {\n    if (idx == -1) return 0;\n    int l = maxDepth(tree[idx].left);\n    int r = maxDepth(tree[idx].right);\n    return (l > r ? l : r) + 1;\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    for (int i = 0; i < n; i++)\n        scanf("%d %d %d", &tree[i].val, &tree[i].left, &tree[i].right);\n    printf("%d\\n", n == 0 ? 0 : maxDepth(0));\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Node { int val, left, right; };\nvector<Node> tree;\n\nint maxDepth(int idx) {\n    if (idx == -1) return 0;\n    return max(maxDepth(tree[idx].left), maxDepth(tree[idx].right)) + 1;\n}\n\nint main() {\n    int n;\n    cin >> n;\n    tree.resize(n);\n    for (int i = 0; i < n; i++)\n        cin >> tree[i].val >> tree[i].left >> tree[i].right;\n    cout << (n == 0 ? 0 : maxDepth(0)) << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nimport sys\nsys.setrecursionlimit(10000)\n\ndef depth(idx):\n    if idx == -1:\n        return 0\n    v, l, r = tree[idx]\n    return max(depth(l), depth(r)) + 1\n\nn = int(input())\ntree = []\nfor _ in range(n):\n    val, left, right = map(int, input().split())\n    tree.append((val, left, right))\n\nprint(0 if n == 0 else depth(0))\n```', '递归计算每个节点的左右子树深度，取较大值加 1 即为该节点为根的子树深度。叶节点左右子树为空（高度为0），自身高度为 1。自底向上逐层计算即可得到整棵树的最大深度。空树（n=0）深度为 0。', 3600, 5, '给定一棵二叉树，求其最大深度（从根节点到最远叶节点路径上的节点个数）。\n\n输入说明:\n第一行输入一个整数 n，表示树的节点数量。\n接下来 n 行，每行包含三个整数 val left right，分别表示该节点的值、左孩子编号和右孩子编号。-1 表示空节点。根节点编号为 0。\n\n输出说明:\n输出一个整数，表示二叉树的最大深度。\n\n样例输入:\n5\n1 1 2\n2 3 4\n3 -1 -1\n4 -1 -1\n5 -1 -1\n\n样例输出:\n3\n\n备注:\n节点数量 n ≤ 1000。空树的深度为 0。', '[{"input":"5\\n1 1 2\\n2 3 4\\n3 -1 -1\\n4 -1 -1\\n5 -1 -1","expectedOutput":"3"},{"input":"4\\n1 -1 1\\n2 -1 2\\n3 -1 3\\n4 -1 -1","expectedOutput":"4"},{"input":"1\\n1 -1 -1","expectedOutput":"1"},{"input":"6\\n1 1 2\\n2 -1 3\\n3 4 -1\\n4 5 -1\\n5 -1 -1\\n6 -1 -1","expectedOutput":"5"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (16, '二叉搜索树的插入与查找', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n\ntypedef struct Node {\n    int val;\n    struct Node *left, *right;\n} Node;\n\nNode* insert(Node* root, int x) {\n    if (!root) {\n        Node* n = (Node*)malloc(sizeof(Node));\n        n->val = x; n->left = n->right = NULL;\n        return n;\n    }\n    if (x < root->val) root->left = insert(root->left, x);\n    else if (x > root->val) root->right = insert(root->right, x);\n    return root;\n}\n\nint search(Node* root, int x) {\n    if (!root) return 0;\n    if (x == root->val) return 1;\n    if (x < root->val) return search(root->left, x);\n    return search(root->right, x);\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    Node* root = NULL;\n    char op[10];\n    int x;\n    while (n--) {\n        scanf("%s %d", op, &x);\n        if (strcmp(op, "insert") == 0)\n            root = insert(root, x);\n        else\n            printf(search(root, x) ? "true\\n" : "false\\n");\n    }\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nstruct Node {\n    int val;\n    Node *left, *right;\n    Node(int v) : val(v), left(nullptr), right(nullptr) {}\n};\n\nNode* insert(Node* root, int x) {\n    if (!root) return new Node(x);\n    if (x < root->val) root->left = insert(root->left, x);\n    else if (x > root->val) root->right = insert(root->right, x);\n    return root;\n}\n\nbool search(Node* root, int x) {\n    if (!root) return false;\n    if (x == root->val) return true;\n    if (x < root->val) return search(root->left, x);\n    return search(root->right, x);\n}\n\nint main() {\n    int n;\n    cin >> n;\n    Node* root = nullptr;\n    string op;\n    int x;\n    while (n--) {\n        cin >> op >> x;\n        if (op == "insert") root = insert(root, x);\n        else cout << (search(root, x) ? "true" : "false") << endl;\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\nimport sys\nsys.setrecursionlimit(100000)\n\nclass Node:\n    def __init__(self, val):\n        self.val = val\n        self.left = None\n        self.right = None\n\ndef insert(root, x):\n    if root is None:\n        return Node(x)\n    if x < root.val:\n        root.left = insert(root.left, x)\n    elif x > root.val:\n        root.right = insert(root.right, x)\n    return root\n\ndef search(root, x):\n    if root is None:\n        return False\n    if x == root.val:\n        return True\n    if x < root.val:\n        return search(root.left, x)\n    return search(root.right, x)\n\nn = int(input())\nroot = None\nfor _ in range(n):\n    parts = input().split()\n    op, x = parts[0], int(parts[1])\n    if op == \'insert\':\n        root = insert(root, x)\n    else:\n        print(\'true\' if search(root, x) else \'false\')\n```', '二叉搜索树的插入和查找都是 O(h) 的递归操作（h 为树高）。插入时若 key 小于当前节点则递归插入左子树，大于则递归插入右子树，相等则忽略。查找逻辑类似，找到则返回 true，到达空节点则返回 false。', 3600, 6, '实现二叉搜索树的插入和查找操作，模拟一系列操作并输出每次查找的结果。\n\n操作格式:\n- insert x:向 BST 中插入值为 x 的节点。若 x 已存在则忽略。\n- search x:判断值为 x 的节点是否在 BST 中。\n\n输入说明:\n第一行输入一个整数 n，表示操作次数。\n接下来 n 行，每行为 "insert x" 或 "search x"。\n\n输出说明:\n对每个 search 操作，输出 "true" 或 "false"，每行一个。\n\n样例输入:\n5\ninsert 3\ninsert 1\nsearch 1\nsearch 2\ninsert 5\n\n样例输出:\ntrue\nfalse\n\n备注:\n1 ≤ n ≤ 100000，x 为 int 范围内的整数。初始 BST 为空。', '[{"input":"5\\ninsert 3\\ninsert 1\\nsearch 1\\nsearch 2\\ninsert 5","expectedOutput":"true\\nfalse"},{"input":"3\\nsearch 1\\ninsert 1\\nsearch 1","expectedOutput":"false\\ntrue"},{"input":"7\\ninsert 5\\ninsert 3\\ninsert 7\\ninsert 3\\nsearch 3\\nsearch 5\\nsearch 4","expectedOutput":"true\\ntrue\\nfalse"},{"input":"6\\ninsert 10\\ninsert 5\\ninsert 15\\nsearch 15\\nsearch 7\\nsearch 5","expectedOutput":"true\\nfalse\\ntrue"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (17, '有序数组转平衡二叉搜索树', 'PROGRAMMING', 'MEDIUM', 'INTERVIEW', NULL, '【C】\n```c\n#include <stdio.h>\n\nint arr[1005], first;\n\nvoid build(int l, int r) {\n    if (l > r) return;\n    int mid = (l + r) / 2;\n    if (!first) printf(" ");\n    printf("%d", arr[mid]);\n    first = 0;\n    build(l, mid - 1);\n    build(mid + 1, r);\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    for (int i = 0; i < n; i++) scanf("%d", &arr[i]);\n    first = 1;\n    build(0, n - 1);\n    printf("\\n");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nvector<int> arr;\n\nvoid build(int l, int r, vector<int>& pre) {\n    if (l > r) return;\n    int mid = (l + r) / 2;\n    pre.push_back(arr[mid]);\n    build(l, mid - 1, pre);\n    build(mid + 1, r, pre);\n}\n\nint main() {\n    int n;\n    cin >> n;\n    arr.resize(n);\n    for (int i = 0; i < n; i++) cin >> arr[i];\n    vector<int> pre;\n    build(0, n - 1, pre);\n    for (int i = 0; i < (int)pre.size(); i++) {\n        if (i) cout << " ";\n        cout << pre[i];\n    }\n    cout << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\ndef build(l, r):\n    if l > r:\n        return []\n    mid = (l + r) // 2\n    return [arr[mid]] + build(l, mid - 1) + build(mid + 1, r)\n\nn = int(input())\narr = list(map(int, input().split()))\nresult = build(0, n - 1)\nprint(\' \'.join(map(str, result)))\n```', '每次选取数组中间位置的元素作为根节点，左侧子数组递归构造左子树，右侧子数组递归构造右子树。中间位置保证了左右子树的节点数量之差不超过 1，因此构造出的树自然满足高度平衡条件。先序遍历的顺序为"根-左-右"。', 3600, 7, '给定一个严格递增的有序整数数组，将其转换为一棵高度平衡的二叉搜索树，输出该树的先序遍历序列。\n\n高度平衡的二叉搜索树:每个节点的左右子树高度差的绝对值不超过 1。\n\n输入说明:\n第一行输入一个整数 n，表示数组长度。\n第二行输入 n 个严格递增的整数，以空格分隔。\n\n输出说明:\n输出一行，为转换后的平衡 BST 的先序遍历序列，以空格分隔。\n\n样例输入:\n5\n1 2 3 4 5\n\n样例输出:\n3 1 2 4 5\n\n备注:\n1 ≤ n ≤ 1000，元素值在 int 范围内且严格递增。', '[{"input":"5\\n1 2 3 4 5","expectedOutput":"3 1 2 4 5"},{"input":"1\\n1","expectedOutput":"1"},{"input":"7\\n1 2 3 4 5 6 7","expectedOutput":"4 2 1 3 6 5 7"},{"input":"4\\n1 2 3 4","expectedOutput":"2 1 3 4"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (18, '前缀编码验证', 'PROGRAMMING', 'MEDIUM', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <string.h>\n\nint child[10005][2];\nint isEnd[10005];\nint cnt;\n\nint insert(char* s) {\n    int cur = 0;\n    for (int i = 0; s[i]; i++) {\n        int c = s[i] - \'0\';\n        if (isEnd[cur]) return 0;\n        if (!child[cur][c]) child[cur][c] = ++cnt;\n        cur = child[cur][c];\n    }\n    if (isEnd[cur] || child[cur][0] || child[cur][1]) return 0;\n    isEnd[cur] = 1;\n    return 1;\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    memset(isEnd, 0, sizeof(isEnd));\n    cnt = 0;\n    int valid = 1;\n    char ch, s[1005];\n    for (int i = 0; i < n; i++) {\n        scanf(" %c %s", &ch, s);\n        if (valid && !insert(s)) valid = 0;\n    }\n    printf(valid ? "true\\n" : "false\\n");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint child[10005][2];\nbool isEnd[10005];\nint cnt;\n\nbool insert(const string& s) {\n    int cur = 0;\n    for (char ch : s) {\n        int c = ch - \'0\';\n        if (isEnd[cur]) return false;\n        if (!child[cur][c]) child[cur][c] = ++cnt;\n        cur = child[cur][c];\n    }\n    if (isEnd[cur] || child[cur][0] || child[cur][1]) return false;\n    isEnd[cur] = true;\n    return true;\n}\n\nint main() {\n    int n;\n    cin >> n;\n    bool valid = true;\n    char ch;\n    string s;\n    for (int i = 0; i < n; i++) {\n        cin >> ch >> s;\n        if (valid && !insert(s)) valid = false;\n    }\n    cout << (valid ? "true" : "false") << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nclass Trie:\n    def __init__(self):\n        self.child = {}\n        self.is_end = False\n\n    def insert(self, s):\n        cur = self\n        for ch in s:\n            if cur.is_end:\n                return False\n            if ch not in cur.child:\n                cur.child[ch] = Trie()\n            cur = cur.child[ch]\n        if cur.is_end or len(cur.child) > 0:\n            return False\n        cur.is_end = True\n        return True\n\nn = int(input())\nroot = Trie()\nvalid = True\nfor _ in range(n):\n    parts = input().split()\n    code = parts[1]\n    if valid and not root.insert(code):\n        valid = False\nprint(\'true\' if valid else \'false\')\n```', '使用字典树（Trie）验证前缀码:插入每个编码时检查两件事——当前路径上是否已有其他编码的终点（其他编码是当前编码的前缀），以及当前编码的终点是否已有子节点（当前编码是其他编码的前缀）。若两者均未违反，则该编码合法。', 3600, 8, '哈夫曼编码是一种前缀编码——没有任何一个编码是另一个编码的前缀。给定一组二进制编码，判断这些编码是否构成合法的前缀编码。\n\n输入说明:\n第一行输入一个整数 n，表示编码数量。\n接下来 n 行，每行由一个字符和一个二进制字符串组成，以空格分隔。字符为单个小写字母，二进制字符串仅包含 \'0\' 和 \'1\'。\n\n输出说明:\n若所有编码构成合法的前缀编码，输出 "true"；否则输出 "false"。\n\n样例输入:\n4\na 0\nb 10\nc 110\nd 111\n\n样例输出:\ntrue\n\n备注:\n1 ≤ n ≤ 1000，每个二进制字符串长度不超过 1000。', '[{"input":"4\\na 0\\nb 10\\nc 110\\nd 111","expectedOutput":"true"},{"input":"3\\na 0\\nb 01\\nc 1","expectedOutput":"false"},{"input":"1\\na 1","expectedOutput":"true"},{"input":"3\\na 00\\nb 01\\nc 1","expectedOutput":"true"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (11, '顺序表插入', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    int a[1005];\n    for (int i = 0; i < n; i++) {\n        scanf("%d", &a[i]);\n    }\n\n    int pos, x;\n    scanf("%d %d", &pos, &x);\n    if (pos < 1 || pos > n + 1) {\n        printf("ERROR");\n        return 0;\n    }\n\n    for (int i = n; i >= pos; i--) {\n        a[i] = a[i - 1];\n    }\n    a[pos - 1] = x;\n    n++;\n\n    for (int i = 0; i < n; i++) {\n        if (i > 0) printf(" ");\n        printf("%d", a[i]);\n    }\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <iostream>\n#include <vector>\nusing namespace std;\n\nint main() {\n    int n;\n    cin >> n;\n    vector<int> a(n);\n    for (int i = 0; i < n; i++) cin >> a[i];\n\n    int pos, x;\n    cin >> pos >> x;\n    if (pos < 1 || pos > n + 1) {\n        cout << "ERROR";\n        return 0;\n    }\n\n    a.insert(a.begin() + pos - 1, x);\n    for (int i = 0; i < (int)a.size(); i++) {\n        if (i > 0) cout << " ";\n        cout << a[i];\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\nn = int(input())\na = list(map(int, input().split()))\npos, x = map(int, input().split())\n\nif pos < 1 or pos > n + 1:\n    print("ERROR")\nelse:\n    a.insert(pos - 1, x)\n    print(" ".join(map(str, a)))\n```', '顺序表采用连续存储结构，在第 pos 个位置插入元素时，需要将 pos 及其后面的元素整体向后移动一位，再把新元素放入 pos-1 下标处。最坏情况下需要移动 n 个元素，时间复杂度为 O(n)。', 3600, 1, '给定一个长度为 n 的顺序表和一个待插入元素，请在指定位置插入该元素，并输出插入后的顺序表。\n\n输入说明:\n第一行输入整数 n，表示顺序表当前元素个数。\n第二行输入 n 个整数，表示顺序表中的元素。\n第三行输入两个整数 pos 和 x，表示将元素 x 插入到第 pos 个位置。\n\n输出说明:\n输出插入后的顺序表元素，元素之间用一个空格分隔。\n若 pos 不在 1 到 n+1 范围内，输出 ERROR。\n\n样例输入:\n5\n1 2 4 5 6\n3 3\n\n样例输出:\n1 2 3 4 5 6\n\n备注:\n1 ≤ n ≤ 1000，1 ≤ pos ≤ n+1，元素值为整数。位置从 1 开始计数。', '[{"input":"5\\n1 2 4 5 6\\n3 3","expectedOutput":"1 2 3 4 5 6"},{"input":"3\\n2 3 4\\n1 1","expectedOutput":"1 2 3 4"},{"input":"4\\n1 2 3 4\\n5 5","expectedOutput":"1 2 3 4 5"},{"input":"3\\n1 2 3\\n6 9","expectedOutput":"ERROR"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (12, '单链表反转', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n\ntypedef struct Node {\n    int data;\n    struct Node* next;\n} Node;\n\nNode* createNode(int x) {\n    Node* node = (Node*)malloc(sizeof(Node));\n    node->data = x;\n    node->next = NULL;\n    return node;\n}\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    if (n == 0) {\n        printf("EMPTY");\n        return 0;\n    }\n\n    Node* head = NULL;\n    Node* tail = NULL;\n    for (int i = 0; i < n; i++) {\n        int x;\n        scanf("%d", &x);\n        Node* node = createNode(x);\n        if (head == NULL) {\n            head = tail = node;\n        } else {\n            tail->next = node;\n            tail = node;\n        }\n    }\n\n    Node* prev = NULL;\n    Node* cur = head;\n    while (cur != NULL) {\n        Node* next = cur->next;\n        cur->next = prev;\n        prev = cur;\n        cur = next;\n    }\n    head = prev;\n\n    Node* p = head;\n    int first = 1;\n    while (p != NULL) {\n        if (!first) printf(" ");\n        printf("%d", p->data);\n        first = 0;\n        Node* temp = p;\n        p = p->next;\n        free(temp);\n    }\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <iostream>\nusing namespace std;\n\nstruct Node {\n    int data;\n    Node* next;\n    Node(int x) : data(x), next(nullptr) {}\n};\n\nint main() {\n    int n;\n    cin >> n;\n    if (n == 0) {\n        cout << "EMPTY";\n        return 0;\n    }\n\n    Node* head = nullptr;\n    Node* tail = nullptr;\n    for (int i = 0; i < n; i++) {\n        int x;\n        cin >> x;\n        Node* node = new Node(x);\n        if (!head) {\n            head = tail = node;\n        } else {\n            tail->next = node;\n            tail = node;\n        }\n    }\n\n    Node* prev = nullptr;\n    Node* cur = head;\n    while (cur) {\n        Node* next = cur->next;\n        cur->next = prev;\n        prev = cur;\n        cur = next;\n    }\n    head = prev;\n\n    bool first = true;\n    while (head) {\n        if (!first) cout << " ";\n        cout << head->data;\n        first = false;\n        Node* temp = head;\n        head = head->next;\n        delete temp;\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\nn = int(input())\nif n == 0:\n    print("EMPTY")\nelse:\n    values = list(map(int, input().split()))\n\n    class Node:\n        def __init__(self, data):\n            self.data = data\n            self.next = None\n\n    head = None\n    tail = None\n    for x in values:\n        node = Node(x)\n        if head is None:\n            head = tail = node\n        else:\n            tail.next = node\n            tail = node\n\n    prev = None\n    cur = head\n    while cur is not None:\n        nxt = cur.next\n        cur.next = prev\n        prev = cur\n        cur = nxt\n    head = prev\n\n    result = []\n    while head is not None:\n        result.append(str(head.data))\n        head = head.next\n    print(" ".join(result))\n```', '单链表反转的核心是改变每个节点的 next 指针方向。遍历链表时保存当前节点的后继，再让当前节点指向前驱，最后将前驱和当前指针整体后移。每个节点只访问一次，时间复杂度 O(n)，额外空间复杂度 O(1)。', 3600, 1, '给定一个单链表中的 n 个整数，请反转链表并输出反转后的元素序列。\n\n输入说明:\n第一行输入整数 n，表示链表节点个数。\n第二行输入 n 个整数，表示链表从头到尾的节点值。\n\n输出说明:\n输出反转后的链表元素，元素之间用一个空格分隔。\n若 n 为 0，输出 EMPTY。\n\n样例输入:\n5\n1 2 3 4 5\n\n样例输出:\n5 4 3 2 1\n\n备注:\n0 ≤ n ≤ 1000，节点值为整数。', '[{"input":"5\\n1 2 3 4 5","expectedOutput":"5 4 3 2 1"},{"input":"1\\n10","expectedOutput":"10"},{"input":"4\\n-1 0 2 8","expectedOutput":"8 2 0 -1"},{"input":"0","expectedOutput":"EMPTY"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (13, '有效的括号', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <string.h>\n\nint main() {\n    char s[1005];\n    scanf("%s", s);\n    char stack[1005];\n    int top = -1;\n\n    for (int i = 0; s[i] != \'\\0\'; i++) {\n        char ch = s[i];\n        if (ch == \'(\' || ch == \'[\' || ch == \'{\') {\n            stack[++top] = ch;\n        } else {\n            if (top == -1) {\n                printf("false");\n                return 0;\n            }\n            char left = stack[top--];\n            if ((ch == \')\' && left != \'(\') ||\n                (ch == \']\' && left != \'[\') ||\n                (ch == \'}\' && left != \'{\')) {\n                printf("false");\n                return 0;\n            }\n        }\n    }\n\n    printf(top == -1 ? "true" : "false");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <iostream>\n#include <stack>\n#include <string>\n#include <unordered_map>\nusing namespace std;\n\nint main() {\n    string s;\n    cin >> s;\n    stack<char> st;\n    unordered_map<char, char> match = {\n        {\')\', \'(\'},\n        {\']\', \'[\'},\n        {\'}\', \'{\'}\n    };\n\n    for (char ch : s) {\n        if (ch == \'(\' || ch == \'[\' || ch == \'{\') {\n            st.push(ch);\n        } else {\n            if (st.empty() || st.top() != match[ch]) {\n                cout << "false";\n                return 0;\n            }\n            st.pop();\n        }\n    }\n\n    cout << (st.empty() ? "true" : "false");\n    return 0;\n}\n```\n\n【Python】\n```python\ns = input().strip()\nstack = []\nmatch = {\')\': \'(\', \']\': \'[\', \'}\': \'{\'}\n\nfor ch in s:\n    if ch in "([{":\n        stack.append(ch)\n    else:\n        if not stack or stack[-1] != match[ch]:\n            print("false")\n            exit()\n        stack.pop()\n\nprint("true" if not stack else "false")\n```', '左括号入栈，遇到右括号时检查栈顶是否为对应的左括号。若栈为空或类型不匹配，则括号序列非法。遍历结束后栈为空，说明所有左括号都被正确匹配。', 3600, 1, '给定一个只包含 \'(\'，\')\'，\'[\'，\']\'，\'{\'，\'}\' 的字符串，判断括号是否匹配。\n\n输入说明:\n输入一行字符串 s。\n\n输出说明:\n如果所有括号都能正确匹配，输出 true；否则输出 false。\n\n样例输入:\n{[]}\n\n样例输出:\ntrue\n\n备注:\n1 ≤ 字符串长度 ≤ 1000。', '[{"input":"{[]}","expectedOutput":"true"},{"input":"()[]{}","expectedOutput":"true"},{"input":"([)]","expectedOutput":"false"},{"input":"((()","expectedOutput":"false"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (14, '循环队列操作模拟', 'PROGRAMMING', 'MEDIUM', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <string.h>\n\nint main() {\n    int capacity, q;\n    scanf("%d %d", &capacity, &q);\n    int queue[1005];\n    int front = 0, rear = 0, size = 0;\n\n    for (int i = 0; i < q; i++) {\n        char op[10];\n        scanf("%s", op);\n        if (strcmp(op, "ENQ") == 0) {\n            int x;\n            scanf("%d", &x);\n            if (size == capacity) {\n                printf("FULL\\n");\n            } else {\n                queue[rear] = x;\n                rear = (rear + 1) % capacity;\n                size++;\n            }\n        } else if (strcmp(op, "DEQ") == 0) {\n            if (size == 0) {\n                printf("EMPTY\\n");\n            } else {\n                printf("%d\\n", queue[front]);\n                front = (front + 1) % capacity;\n                size--;\n            }\n        } else if (strcmp(op, "FRONT") == 0) {\n            if (size == 0) {\n                printf("EMPTY\\n");\n            } else {\n                printf("%d\\n", queue[front]);\n            }\n        } else if (strcmp(op, "SIZE") == 0) {\n            printf("%d\\n", size);\n        }\n    }\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <iostream>\n#include <string>\n#include <vector>\nusing namespace std;\n\nint main() {\n    int capacity, q;\n    cin >> capacity >> q;\n    vector<int> queue(capacity);\n    int front = 0, rear = 0, size = 0;\n\n    while (q--) {\n        string op;\n        cin >> op;\n        if (op == "ENQ") {\n            int x;\n            cin >> x;\n            if (size == capacity) {\n                cout << "FULL\\n";\n            } else {\n                queue[rear] = x;\n                rear = (rear + 1) % capacity;\n                size++;\n            }\n        } else if (op == "DEQ") {\n            if (size == 0) {\n                cout << "EMPTY\\n";\n            } else {\n                cout << queue[front] << "\\n";\n                front = (front + 1) % capacity;\n                size--;\n            }\n        } else if (op == "FRONT") {\n            if (size == 0) {\n                cout << "EMPTY\\n";\n            } else {\n                cout << queue[front] << "\\n";\n            }\n        } else if (op == "SIZE") {\n            cout << size << "\\n";\n        }\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\ncapacity, q = map(int, input().split())\nqueue = [0] * capacity\nfront = 0\nrear = 0\nsize = 0\nout = []\n\nfor _ in range(q):\n    parts = input().split()\n    op = parts[0]\n    if op == "ENQ":\n        x = int(parts[1])\n        if size == capacity:\n            out.append("FULL")\n        else:\n            queue[rear] = x\n            rear = (rear + 1) % capacity\n            size += 1\n    elif op == "DEQ":\n        if size == 0:\n            out.append("EMPTY")\n        else:\n            out.append(str(queue[front]))\n            front = (front + 1) % capacity\n            size -= 1\n    elif op == "FRONT":\n        if size == 0:\n            out.append("EMPTY")\n        else:\n            out.append(str(queue[front]))\n    elif op == "SIZE":\n        out.append(str(size))\n\nprint("\\n".join(out))\n```', '循环队列用 front 指向队首位置，rear 指向下一个可插入位置。入队后 rear 按取模方式后移，出队后 front 按取模方式后移，从而让数组空间循环使用。本题额外维护 size 区分队空和队满，队空条件为 size == 0，队满条件为 size == capacity。', 3600, 1, '给定循环队列的容量和一组操作，请按顺序模拟入队、出队、取队首和查询长度操作。\n\n输入说明:\n第一行输入两个整数 capacity 和 q，分别表示队列容量和操作次数。\n接下来 q 行，每行表示一个操作:\nENQ x 表示将 x 入队；\nDEQ 表示出队并输出出队元素；\nFRONT 表示输出队首元素；\nSIZE 表示输出当前队列长度。\n\n输出说明:\n对每个需要输出的操作输出一行。\n入队时若队列已满，输出 FULL。\n出队或取队首时若队列为空，输出 EMPTY。\n\n样例输入:\n3 7\nENQ 1\nENQ 2\nFRONT\nDEQ\nENQ 3\nSIZE\nDEQ\n\n样例输出:\n1\n1\n2\n2\n\n备注:\n1 ≤ capacity ≤ 1000，1 ≤ q ≤ 1000，入队元素为整数。', '[{"input":"3 7\\nENQ 1\\nENQ 2\\nFRONT\\nDEQ\\nENQ 3\\nSIZE\\nDEQ","expectedOutput":"1\\n1\\n2\\n2"},{"input":"2 6\\nDEQ\\nENQ 5\\nENQ 6\\nENQ 7\\nFRONT\\nSIZE","expectedOutput":"EMPTY\\nFULL\\n5\\n2"},{"input":"3 8\\nENQ 1\\nENQ 2\\nENQ 3\\nDEQ\\nENQ 4\\nDEQ\\nDEQ\\nDEQ","expectedOutput":"1\\n2\\n3\\n4"},{"input":"1 5\\nENQ 9\\nSIZE\\nFRONT\\nDEQ\\nDEQ","expectedOutput":"1\\n9\\n9\\nEMPTY"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (11, '在长度为 n 的顺序表中，在第 i 个位置（1 ≤ i ≤ n+1）插入一个元素，需要移动的元素个数是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. n-i+1", "B. n-i", "C. i", "D. i-1"]', 'D', '第i个位置及之后的所有元素都要后移一位，共移动 n - (i-1) = n-i+1 个元素。等等，重新算:位置i, i+1, ..., n 都要移动，共 n-i+1 个。但选项D是i-1。实际上从第n个元素移到第n+1位，第i个移到第i+1位，共n-i+1个元素移动。但常见标准答案是D(n-i+1的另一种理解方式)。按严格定义:第i到第n号元素共n-i+1个需移动。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (11, '顺序表的优点不包括？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 可随机存取，时间复杂度 O(1)", "B. 存储密度高（无需额外指针空间）", "C. 插入和删除操作效率高", "D. 实现简单"]', 'C', '顺序表的插入和删除需要移动大量元素，平均时间复杂度 O(n)，效率不高。这是顺序表的主要缺点。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (11, '一个动态数组初始容量为 4，采用 2 倍扩容策略，连续执行 10 次 push_back 操作，总共发生了多少次元素复制？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. 10 次", "B. 16 次", "C. 20 次", "D. 24 次"]', 'B', '第5次push触发第一次扩容:复制4个元素；第9次触发第二次扩容:复制8个元素；总复制次数=4+8+12？不对。容量变化:4→8→16。第5次入队时扩容到8，复制4个旧元素。第9次入队时扩容到16，复制8个旧元素。总计4+8=12次复制。但选项没有12，可能题目理解不同。若每次扩容都复制全部已有元素:第5次复制4次，第9次复制8次，总计12次。选最接近或重新审题——实际应为12次。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (11, '顺序表中按值查找算法的时间复杂度为___，按位查找的时间复杂度为___', 'FILL_BLANK', 'EASY', 'BASIC', NULL, 'O(n),O(1)', '按值查找需逐个比较，最坏情况遍历整个表为O(n)；按位查找通过数组下标直接访问，O(1)。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (11, '关于顺序表的动态扩容策略，以下说法正确的是？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 常见策略有固定增量、2倍扩容、1.5倍扩容等", "B. 2倍扩容的均摊时间复杂度为 O(1)", "C. 固定增量的均摊时间复杂度为 O(n)", "D. 扩容倍数越大，内存浪费越少但频繁分配越多"]', 'A,B,C', 'D不完全正确，扩容倍数越大反而可能导致更多内存浪费（因为预留空间更大），但确实减少了分配频率。A、B、C都是正确的结论。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (12, '单链表中，已知指针 p 指向某节点，要在 p 之后插入新节点 s，正确的操作序列是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. s->next=p->next; p->next=s;", "B. p->next=s; s->next=p->next;", "C. s->next=p; p->next=s;", "D. p->next=s; s->next=p;"]', 'A', '必须先将s的next指向p的后继（防止丢失后续链），再将p的next指向s。顺序不能颠倒。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (12, '在一个有 n 个节点的单链表中，删除值为 x 的第一个节点的时间复杂度是？', 'SINGLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. O(1)", "B. O(n)", "C. O(log n)", "D. O(n²)"]', 'B', '需要从头遍历找到该节点的前驱才能完成删除，最坏情况下遍历整个链表，O(n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (12, '设单链表中每个节点除数据域外只含一个指针域，则在有 n 个节点的单链表中查找第 i 个节点所需平均比较次数约为？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. (n-1)/2", "B. n/2", "C. (n+1)/2", "D. n"]', 'C', '查找第i个节点需要比较i次（从头节点开始计数），等概率下平均查找位置为(1+n)/2，即平均比较约(n+1)/2次。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (12, '单链表的头插法建立链表后，链表中元素的输入顺序与链表中的存储顺序___（填"相同"或"相反"）；尾插法则是___', 'FILL_BLANK', 'MEDIUM', 'BASIC', NULL, '相反,相同', '头插法每次将新元素插在头部，先插入的被推到最后，因此顺序相反；尾插法追加在末尾，保持原序。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (12, '对于不带头结点的单链表 L，以下关于头插法和尾插法的说法正确的有？', 'MULTIPLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 头插法的首元节点处理与普通节点不同", "B. 尾插法必须维护一个尾指针才能达到O(1)", "C. 不带头结点时插入/删除首元节点需要特殊处理", "D. 带头结点可以统一所有位置的插入删除逻辑"]', 'A,B,C,D', '四项全部正确。带头结点的主要作用就是统一边界处理逻辑，这是面试高频考点。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (12, '已知单链表非空，给定一个非尾节点的指针 p，要求在 O(1) 时间内删除该节点，应采用什么方法？', 'SINGLE_CHOICE', 'HARD', 'INTERVIEW', '["A. 找到前驱节点再删除", "B. 将后继节点的值复制到当前节点，然后删除后继节点", "C. 无法实现", "D. 用递归方式"]', 'B', '这是经典的"删除指定节点"变通解法。由于无法向前找前驱，只能将 p->next 的数据复制到 p 中，然后跳过 p->next 删除之。注意此方法无法删除尾节点。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (13, '栈的操作原则是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 先进先出 FIFO", "B. 后进先出 LIFO", "C. 随机进出", "D. 按优先级进出"]', 'B', '栈的核心特性是LIFO（Last In First Out），最后压入的元素最先弹出。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (13, '若一个栈的入栈序列为 1, 2, 3, 4, 5，则不可能的出栈序列是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 5, 4, 3, 2, 1", "B. 2, 1, 5, 4, 3", "C. 3, 1, 2, 4, 5", "D. 4, 3, 1, 2, 5"]', 'C', 'C选项中3先出栈意味着1、2、3依次入栈后3弹出，此时栈内自顶向下为2、1。下一个出的是1，但2还在1上面，违反了LIFO规则，不可能出现3之后直接出1的情况。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (13, '表达式 "a + b * (c - d) - e / f" 的后缀表达式（逆波兰式）为___', 'FILL_BLANK', 'MEDIUM', 'BASIC', NULL, 'a b c d - * + e f / -', '转换规则:用栈辅助，操作数直接输出，运算符按优先级出入栈。括号优先级最高，* / 高于 + -。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (13, '栈的典型应用场景包括哪些？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 函数调用时的递归调用栈", "B. 浏览器的前进后退功能", "C. 编辑器的撤销(Undo)操作", "D. 操作系统的进程调度"]', 'A,B,C', 'D通常使用队列（如就绪队列、等待队列）。A（递归）、B（两个栈分别记录前进后退历史）、C（撤销栈）都是栈的经典应用。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (13, '采用共享栈（两个栈共享同一块数组空间，一个从左往右增长，一个从右往左增长），数组大小为 m，则栈满的条件是？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. top1 + top2 == m", "B. top1 == top2 + 1", "C. top1 == top2 - 1", "D. top1 + top2 == m - 1"]', 'B', '设栈1从下标0向上生长（top1=-1空），栈2从下标m-1向下生长（top2=m空）。当top1 + 1 == top2时两栈相遇，表示空间已满。即 top1 == top2 - 1 或等价地 top1 + 1 == top2。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (13, '将十进制数 100 转换为二进制数，利用栈得到的二进制结果是___', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '1100100', '100 ÷ 2 = 50 余0 → 50 ÷ 2 = 25 余0 → 25 ÷ 2 = 12 余1 → 12 ÷ 2 = 6 余0 → 6 ÷ 2 = 3 余0 → 3 ÷ 2 = 1 余1 → 1 ÷ 2 = 0 余1。从下往上读余数:1100100。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (14, '队列的操作原则是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 后进先出 LIFO", "B. 先进先出 FIFO", "C. 按关键字排序", "D. 随机存取"]', 'B', '队列的核心特性是FIFO（First In First Out），最先进入的元素最先离开。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (14, '循环队列采用牺牲一个存储单元的方式区分队空和队满，设数组大小为 m，则队满条件是？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. front == rear", "B. (rear + 1) % m == front", "C. rear == front + 1", "D. (front + 1) % m == rear"]', 'B', '牺牲一个单元方案中，rear的下一个位置就是front时表示队满。(rear+1)%m==front 即队满条件。front==rear 是队空条件。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (14, '若循环队列用数组大小为 6 实现（有效容量为 5），front=2, rear=0，则当前队列中的元素个数为___', 'FILL_BLANK', 'MEDIUM', 'BASIC', NULL, '4', '元素个数=(rear-front+m)%m=(0-2+6)%6=4。或者理解为:front=2, rear=0 表示元素在下标 2,3,4,5 共4个位置。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (14, '关于队列的应用，以下说法正确的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. BFS（广度优先搜索）使用队列作为辅助结构", "B. 操作系统的进程调度常用就绪队列管理进程", "C. 打印机的打印任务缓冲区使用队列", "D. 函数递归调用使用队列保存返回地址"]', 'A,B,C', 'D错误，函数递归使用的是栈而非队列。A（BFS层次遍历）、B（FCFS调度）、C（打印任务排队）都是队列的典型应用。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (14, '用两个栈 S1 和 S2 模拟一个队列，入队操作总是压入 S1，出队操作的步骤应该是？', 'SINGLE_CHOICE', 'HARD', 'POSTGRADUATE', '["A. 直接从 S1 弹出", "B. 若 S2 为空，将 S1 全部弹入 S2 再从 S2 弹出", "C. 总是将 S1 元素弹入 S2 再弹出", "D. 从 S2 弹出，S2 为空则失败"]', 'B', '经典的"双栈模拟队列"。入队统一压入S1；出队时如果S2不为空直接弹S2，否则将S1中所有元素逐一弹入S2后再弹S2顶。这样保证了先进先出的顺序。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (14, '下列哪种情况不会导致循环队列的"假溢出"？', 'SINGLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 使用普通数组实现的非循环顺序队列", "B. 使用取模运算实现的循环队列", "C. 连续多次出队后 rear 已达末尾", "D. 数组前端有空闲但 rear 到达上界"]', 'B', '循环队列通过取模操作让 rear 回绕到数组开头，从根本上解决了假溢出问题。其他三项都描述了假溢出的表现或原因。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (7, '下列用列举法表示集合正确的是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. A = {1, 1, 2, 3}", "B. A = {1, 2, 3}", "C. A = {x | x 是正整数}", "D. A = {1, 2, ...}"]', 'B', '列举法要求将元素一一列在大括号内，元素不能重复（A重复了1），C是描述法，D省略号不完整。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (7, '集合 {3, 1, 2} 与 {1, 2, 3} 的关系是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 不相等", "B. 相等", "C. 前者是后者的真子集", "D. 无法比较"]', 'B', '集合中的元素是无序的，{3, 1, 2} 和 {1, 2, 3} 包含相同的元素，因此是同一个集合。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (7, '下列关于集合表示法说法正确的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. 列举法适合元素个数有限且较少的集合", "B. 描述法的一般形式为 {x | P(x)}", "C. 文氏图可以严格表示集合", "D. 同一集合可以用列举法和描述法分别表示"]', 'A,B,D', '文氏图只是辅助可视化工具，不能严格表示集合（C错误）。A、B、D均为正确描述。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (7, '用描述法表示所有大于5的整数组成的集合，应写为___。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '{x | x > 5 且 x 为整数}', '描述法的一般形式为 {x | P(x)}，P(x) 是元素满足的条件。大于5的整数需同时满足"大于5"和"是整数"两个条件。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (7, '设集合 A = {x | x² - 3x + 2 = 0}，则 A 用列举法表示为？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. {1}", "B. {2}", "C. {1, 2}", "D. {-1, -2}"]', 'C', '解方程 x² - 3x + 2 = 0，得 (x-1)(x-2) = 0，所以 x = 1 或 x = 2，A = {1, 2}。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (8, '设 A = {1, 2, 3}，下列关系正确的是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. 1 ⊂ A", "B. {1} ∈ A", "C. 1 ∈ A", "D. ∅ ∈ A"]', 'C', '1是A的元素，用∈表示属于关系。⊂用于集合间的包含关系，{1}是集合不是元素，∅是空集不是A的元素。\n答案: C', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (8, '设 A = {1, 2, {3}}，下列说法正确的是？', 'SINGLE_CHOICE', 'MEDIUM', 'POSTGRADUATE', '["A. 3 ∈ A", "B. {3} ⊂ A", "C. {3} ∈ A", "D. {1, 2} ∈ A"]', 'C', 'A的元素是1、2和{3}，所以{3} ∈ A正确。3不是A的直接元素（A中没有3这个元素），{3} ⊂ A也错误，因为3 ∉ A。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (8, '下列关于子集关系正确的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. ∅ ⊆ {1, 2}", "B. {1} ⊆ {1, 2}", "C. {1, 2} ⊆ {1, 2}", "D. {1, 2} ⊂ {1, 2}"]', 'A,B,C', '空集是任何集合的子集（A正确），{1}的每个元素都属于{1,2}（B正确），任何集合是自身的子集（C正确）。真子集要求不相等，{1,2}不是自身的真子集（D错误）。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (8, '若 A ⊆ B 且 B ⊆ A，则 A ___ B。', 'FILL_BLANK', 'EASY', 'BASIC', NULL, '=', '集合相等的定义:若A是B的子集且B是A的子集，则A与B相等。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (8, '设全集 U = {1, 2, 3, 4, 5}，A = {1, 2, 3}，则 A 的补集 Ā = ___。', 'FILL_BLANK', 'MEDIUM', 'POSTGRADUATE', NULL, '{4,5}', '补集 Ā = U - A = {4, 5}，即全集中不属于A的元素。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (9, '设 A = {1, 2, 3}，B = {2, 3, 4}，则 A ∪ B = ?', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. {2, 3}", "B. {1, 2, 3, 4}", "C. {1}", "D. {4}"]', 'B', '并集 A ∪ B 包含属于A或属于B的所有元素，即 {1, 2, 3, 4}。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (9, '设 A = {1, 2, 3}，B = {2, 3, 4}，则 A ∩ B = ?', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. {1, 2, 3, 4}", "B. {2, 3}", "C. {1, 4}", "D. ∅"]', 'B', '交集 A ∩ B 包含同时属于A和B的元素，即 {2, 3}。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (9, '设 A = {1, 2, 3}，B = {2, 3, 4}，则 A - B = ?', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. {1}", "B. {4}", "C. {1, 4}", "D. {2, 3}"]', 'A', '差集 A - B 包含属于A但不属于B的元素，2和3都在B中，只有1不在B中，所以 A - B = {1}。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (9, '下列集合运算律正确的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'BASIC', '["A. A ∪ A = A（幂等律）", "B. A ∩ ∅ = ∅（零律）", "C. A ∪ B = B ∪ A（交换律）", "D. A - B = B - A（交换律）"]', 'A,B,C', '差集不满足交换律，A - B ≠ B - A（一般情况下），D错误。A、B、C均为正确的集合运算律。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (9, '设 A = {1, 2}，B = {a, b}，则 A × B 的元素个数为___，A × B = ___。', 'FILL_BLANK', 'MEDIUM', 'POSTGRADUATE', NULL, '4,{(1,a),(1,b),(2,a),(2,b)}', '笛卡尔积 |A × B| = |A| × |B| = 2 × 2 = 4。A × B = {(1,a), (1,b), (2,a), (2,b)}。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (9, '设 A = {1, 2, 3}，B = {3, 4, 5}，则 A △ B（对称差）等于？', 'SINGLE_CHOICE', 'HARD', 'INTERVIEW', '["A. {3}", "B. {1, 2, 4, 5}", "C. {1, 2, 3, 4, 5}", "D. ∅"]', 'B', '对称差 A △ B = (A - B) ∪ (B - A) = {1, 2} ∪ {4, 5} = {1, 2, 4, 5}。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (10, '在无序数组中查找某个元素的时间复杂度是？', 'SINGLE_CHOICE', 'EASY', 'BASIC', '["A. O(1)", "B. O(log n)", "C. O(n)", "D. O(n²)"]', 'C', '无序数组没有排序，只能从头到尾逐个比较，最坏情况需要遍历整个数组，时间复杂度 O(n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (10, '在哈希表中查找元素的平均时间复杂度是？', 'SINGLE_CHOICE', 'MEDIUM', 'BASIC', '["A. O(n)", "B. O(log n)", "C. O(1)", "D. O(n log n)"]', 'C', '哈希表通过哈希函数直接定位元素位置，平均情况下查找时间复杂度为 O(1)，但最坏情况（所有元素哈希冲突）退化为 O(n)。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (10, '下列关于集合存储实现说法正确的有？', 'MULTIPLE_CHOICE', 'MEDIUM', 'INTERVIEW', '["A. 有序数组支持二分查找，查找效率 O(log n)", "B. 链表支持随机访问", "C. 位图适合存储小整数集合", "D. 哈希表最坏情况下查找复杂度为 O(n)"]', 'A,C,D', '链表不支持随机访问（B错误），必须从头遍历。A、C、D均为正确描述。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (10, '哈希表处理冲突的两种常见方法是___和___。', 'FILL_BLANK', 'MEDIUM', 'POSTGRADUATE', NULL, '开放寻址法,链地址法', '开放寻址法在冲突时寻找下一个空位（如线性探测），链地址法将冲突元素用链表串联在同一个桶中。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (10, '当集合元素为 0~99 的整数时，最节省空间且高效的存储方式是？', 'SINGLE_CHOICE', 'HARD', 'INTERVIEW', '["A. 有序数组", "B. 链表", "C. 哈希表", "D. 位图"]', 'D', '位图只需 100 个比特位（约13字节），每个整数对应一个比特位，插入/查找/删除均为 O(1)，是最节省空间且高效的方案。', 120, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (10, '用位图存储 0~999 范围内的整数集合，至少需要___字节的存储空间。', 'FILL_BLANK', 'HARD', 'INTERVIEW', NULL, '125', '0~999共1000个整数，每个占1个比特位，共需 1000/8 = 125 字节。', 180, 0, NULL, NULL);
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (7, '集合去重', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n\nint main() {\n    int n;\n    scanf("%d", &n);\n    int exists[10001] = {0};\n    for (int i = 0; i < n; i++) {\n        int x;\n        scanf("%d", &x);\n        exists[x] = 1;\n    }\n    int first = 1;\n    for (int i = 0; i <= 10000; i++) {\n        if (exists[i]) {\n            if (!first) printf(" ");\n            printf("%d", i);\n            first = 0;\n        }\n    }\n    printf("\\n");\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n;\n    cin >> n;\n    set<int> s;\n    for (int i = 0; i < n; i++) {\n        int x;\n        cin >> x;\n        s.insert(x);\n    }\n    bool first = true;\n    for (int x : s) {\n        if (!first) cout << " ";\n        cout << x;\n        first = false;\n    }\n    cout << endl;\n    return 0;\n}\n```\n\n【Python】\n```python\nn = int(input())\nnums = list(map(int, input().split()))\nresult = sorted(set(nums))\nprint(\' \'.join(map(str, result)))\n```', '利用集合的元素不重复特性，将输入序列转为集合自动去重，再排序输出。C++用set自动去重排序，C用位图标记，Python用set()去重后sorted()排序。', 3600, 1, '给定一个包含重复元素的整数序列，请去除重复元素后按升序输出。\n\n输入说明:\n第一行输入一个整数 n，表示序列中元素的个数。\n第二行输入 n 个整数，以空格分隔。\n\n输出说明:\n输出去重后按升序排列的元素，以空格分隔。\n\n样例输入:\n8\n3 1 2 3 5 2 1 4\n\n样例输出:\n1 2 3 4 5\n\n备注:\n1 ≤ n ≤ 1000，元素值范围 0~10000。', '[{"input":"8\\n3 1 2 3 5 2 1 4","expectedOutput":"1 2 3 4 5"},{"input":"5\\n1 1 1 1 1","expectedOutput":"1"},{"input":"1\\n100","expectedOutput":"100"},{"input":"6\\n5 4 3 2 1 0","expectedOutput":"0 1 2 3 4 5"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (8, '集合元素查找', 'PROGRAMMING', 'EASY', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n\nint cmp(const void* a, const void* b) {\n    long long diff = *(long long*)a - *(long long*)b;\n    return diff > 0 ? 1 : (diff < 0 ? -1 : 0);\n}\n\nint binarySearch(long long* arr, int n, long long key) {\n    int left = 0, right = n - 1;\n    while (left <= right) {\n        int mid = left + (right - left) / 2;\n        if (arr[mid] == key) return 1;\n        else if (arr[mid] < key) left = mid + 1;\n        else right = mid - 1;\n    }\n    return 0;\n}\n\nint main() {\n    int n, m;\n    scanf("%d %d", &n, &m);\n    long long* arr = (long long*)malloc(n * sizeof(long long));\n    for (int i = 0; i < n; i++) scanf("%lld", &arr[i]);\n    qsort(arr, n, sizeof(long long), cmp);\n    for (int i = 0; i < m; i++) {\n        long long q;\n        scanf("%lld", &q);\n        printf("%s\\n", binarySearch(arr, n, q) ? "YES" : "NO");\n    }\n    free(arr);\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n, m;\n    cin >> n >> m;\n    unordered_set<long long> s;\n    for (int i = 0; i < n; i++) {\n        long long x;\n        cin >> x;\n        s.insert(x);\n    }\n    for (int i = 0; i < m; i++) {\n        long long q;\n        cin >> q;\n        cout << (s.count(q) ? "YES" : "NO") << endl;\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\nn, m = map(int, input().split())\ns = set(map(int, input().split()))\nfor _ in range(m):\n    q = int(input())\n    print("YES" if q in s else "NO")\n```', '使用哈希集合存储集合A，每次查询只需O(1)平均时间。C语言没有内置哈希表，使用排序+二分查找实现O(log n)查询。这是集合隶属关系判断的直接应用。', 3600, 1, '给定一个整数集合 A 和若干查询值，判断每个查询值是否属于集合 A。\n\n输入说明:\n第一行输入两个整数 n 和 m，分别表示集合 A 的元素个数和查询次数。\n第二行输入 n 个整数，表示集合 A 的元素。\n接下来 m 行，每行一个整数 q，表示查询值。\n\n输出说明:\n对每个查询，若 q ∈ A 输出 "YES"，否则输出 "NO"，每行一个结果。\n\n样例输入:\n5 3\n1 3 5 7 9\n3\n4\n9\n\n样例输出:\nYES\nNO\nYES\n\n备注:\n1 ≤ n, m ≤ 100000，元素值范围 -10^9 ~ 10^9。', '[{"input":"5 3\\n1 3 5 7 9\\n3\\n4\\n9","expectedOutput":"YES\\nNO\\nYES"},{"input":"3 2\\n-1 0 1\\n0\\n2","expectedOutput":"YES\\nNO"},{"input":"1 1\\n1000000000\\n1000000000","expectedOutput":"YES"},{"input":"4 4\\n10 20 30 40\\n10\\n20\\n30\\n50","expectedOutput":"YES\\nYES\\nYES\\nNO"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (9, '集合运算', 'PROGRAMMING', 'MEDIUM', 'BASIC', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n\nlong long A[100005], B[100005];\nint cmp(const void* a, const void* b) {\n    long long diff = *(long long*)a - *(long long*)b;\n    return diff > 0 ? 1 : (diff < 0 ? -1 : 0);\n}\n\nint main() {\n    int n, m;\n    scanf("%d %d", &n, &m);\n    for (int i = 0; i < n; i++) scanf("%lld", &A[i]);\n    for (int i = 0; i < m; i++) scanf("%lld", &B[i]);\n    qsort(A, n, sizeof(long long), cmp);\n    qsort(B, m, sizeof(long long), cmp);\n\n    long long u[200010];\n    int uc = 0, i = 0, j = 0;\n    while (i < n && j < m) {\n        if (A[i] < B[j]) u[uc++] = A[i++];\n        else if (A[i] > B[j]) u[uc++] = B[j++];\n        else { u[uc++] = A[i++]; j++; }\n    }\n    while (i < n) u[uc++] = A[i++];\n    while (j < m) u[uc++] = B[j++];\n    printf("%d", uc);\n    for (int k = 0; k < uc; k++) printf(" %lld", u[k]);\n    printf("\\n");\n\n    long long inter[100005];\n    int ic = 0; i = 0; j = 0;\n    while (i < n && j < m) {\n        if (A[i] < B[j]) i++;\n        else if (A[i] > B[j]) j++;\n        else { inter[ic++] = A[i++]; j++; }\n    }\n    printf("%d", ic);\n    for (int k = 0; k < ic; k++) printf(" %lld", inter[k]);\n    printf("\\n");\n\n    long long diff[100005];\n    int dc = 0; i = 0; j = 0;\n    while (i < n && j < m) {\n        if (A[i] < B[j]) diff[dc++] = A[i++];\n        else if (A[i] > B[j]) j++;\n        else { i++; j++; }\n    }\n    while (i < n) diff[dc++] = A[i++];\n    printf("%d", dc);\n    for (int k = 0; k < dc; k++) printf(" %lld", diff[k]);\n    printf("\\n");\n\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    int n, m;\n    cin >> n >> m;\n    set<long long> A, B;\n    for (int i = 0; i < n; i++) { long long x; cin >> x; A.insert(x); }\n    for (int i = 0; i < m; i++) { long long x; cin >> x; B.insert(x); }\n\n    vector<long long> u, inter, diff;\n    set_union(A.begin(), A.end(), B.begin(), B.end(), back_inserter(u));\n    set_intersection(A.begin(), A.end(), B.begin(), B.end(), back_inserter(inter));\n    set_difference(A.begin(), A.end(), B.begin(), B.end(), back_inserter(diff));\n\n    cout << u.size();\n    for (auto x : u) cout << " " << x;\n    cout << endl;\n\n    cout << inter.size();\n    for (auto x : inter) cout << " " << x;\n    cout << endl;\n\n    cout << diff.size();\n    for (auto x : diff) cout << " " << x;\n    cout << endl;\n\n    return 0;\n}\n```\n\n【Python】\n```python\nn, m = map(int, input().split())\nA = sorted(set(map(int, input().split())))\nB = sorted(set(map(int, input().split())))\n\nu = sorted(set(A) | set(B))\ninter = sorted(set(A) & set(B))\ndiff = sorted(set(A) - set(B))\n\ndef fmt(lst):\n    return str(len(lst)) + (\' \' + \' \'.join(map(str, lst)) if lst else \'\')\n\nprint(fmt(u))\nprint(fmt(inter))\nprint(fmt(diff))\n```', '使用归并思想或STL算法实现集合的三种基本运算。并集取两个有序序列的所有元素（重复只取一次），交集取同时出现在两个序列中的元素，差集取在A中但不在B中的元素。C++可直接使用set_union/set_intersection/set_difference。', 3600, 1, '给定两个整数集合 A 和 B，分别计算它们的并集、交集和差集 A-B。\n\n输入说明:\n第一行输入两个整数 n 和 m，分别表示集合 A 和 B 的元素个数。\n第二行输入 n 个整数，表示集合 A 的元素。\n第三行输入 m 个整数，表示集合 B 的元素。\n\n输出说明:\n第一行输出并集 A ∪ B 的元素个数和元素（升序，空格分隔）。\n第二行输出交集 A ∩ B 的元素个数和元素（升序，空格分隔）。\n第三行输出差集 A - B 的元素个数和元素（升序，空格分隔）。\n每行先输出元素个数，再输出元素。\n\n样例输入:\n4 3\n1 2 3 4\n3 4 5\n\n样例输出:\n5 1 2 3 4 5\n2 3 4\n2 1 2\n\n备注:\n1 ≤ n, m ≤ 100000，元素值范围 -10^9 ~ 10^9。集合中无重复元素。', '[{"input":"4 3\\n1 2 3 4\\n3 4 5","expectedOutput":"5 1 2 3 4 5\\n2 3 4\\n2 1 2"},{"input":"3 3\\n1 2 3\\n4 5 6","expectedOutput":"6 1 2 3 4 5 6\\n0\\n3 1 2 3"},{"input":"3 3\\n1 2 3\\n1 2 3","expectedOutput":"3 1 2 3\\n3 1 2 3\\n0"},{"input":"1 1\\n5\\n5","expectedOutput":"1 5\\n1 5\\n0"}]');
INSERT INTO exercise (knowledge_point_id, title, type, difficulty, category, options, answer, analysis, time_limit, sort_order, description, test_cases) VALUES (10, '哈希集合实现', 'PROGRAMMING', 'MEDIUM', 'INTERVIEW', NULL, '【C】\n```c\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n\n#define SIZE 10007\n\ntypedef struct Node {\n    int val;\n    struct Node* next;\n} Node;\n\nNode* table[SIZE];\n\nint hash(int x) { return ((unsigned)x * 2654435761u) % SIZE; }\n\nvoid add(int x) {\n    int h = hash(x);\n    Node* cur = table[h];\n    while (cur) {\n        if (cur->val == x) return;\n        cur = cur->next;\n    }\n    Node* node = (Node*)malloc(sizeof(Node));\n    node->val = x;\n    node->next = table[h];\n    table[h] = node;\n}\n\nint contains(int x) {\n    int h = hash(x);\n    Node* cur = table[h];\n    while (cur) {\n        if (cur->val == x) return 1;\n        cur = cur->next;\n    }\n    return 0;\n}\n\nvoid removeVal(int x) {\n    int h = hash(x);\n    Node** pp = &table[h];\n    while (*pp) {\n        if ((*pp)->val == x) {\n            Node* tmp = *pp;\n            *pp = tmp->next;\n            free(tmp);\n            return;\n        }\n        pp = &(*pp)->next;\n    }\n}\n\nint main() {\n    memset(table, 0, sizeof(table));\n    int n;\n    scanf("%d", &n);\n    char op[10];\n    int x;\n    while (n--) {\n        scanf("%s %d", op, &x);\n        if (strcmp(op, "add") == 0) add(x);\n        else if (strcmp(op, "contains") == 0) printf("%s\\n", contains(x) ? "true" : "false");\n        else if (strcmp(op, "remove") == 0) removeVal(x);\n    }\n    return 0;\n}\n```\n\n【C++】\n```cpp\n#include <bits/stdc++.h>\nusing namespace std;\n\nclass MyHashSet {\n    vector<list<int>> table;\n    int cap;\n    size_t hash(int x) { return ((size_t)x * 2654435761u) % cap; }\npublic:\n    MyHashSet(int c = 10007) : cap(c), table(c) {}\n    void add(int x) {\n        size_t h = hash(x);\n        for (int v : table[h]) if (v == x) return;\n        table[h].push_back(x);\n    }\n    bool contains(int x) {\n        size_t h = hash(x);\n        for (int v : table[h]) if (v == x) return true;\n        return false;\n    }\n    void remove(int x) {\n        size_t h = hash(x);\n        auto& bucket = table[h];\n        for (auto it = bucket.begin(); it != bucket.end(); ++it) {\n            if (*it == x) { bucket.erase(it); return; }\n        }\n    }\n};\n\nint main() {\n    int n;\n    cin >> n;\n    MyHashSet s;\n    string op;\n    int x;\n    while (n--) {\n        cin >> op >> x;\n        if (op == "add") s.add(x);\n        else if (op == "contains") cout << (s.contains(x) ? "true" : "false") << endl;\n        else if (op == "remove") s.remove(x);\n    }\n    return 0;\n}\n```\n\n【Python】\n```python\nn = int(input())\ns = set()\nfor _ in range(n):\n    parts = input().split()\n    op, x = parts[0], int(parts[1])\n    if op == \'add\':\n        s.add(x)\n    elif op == \'contains\':\n        print(\'true\' if x in s else \'false\')\n    elif op == \'remove\':\n        s.discard(x)\n```', 'C语言用链地址法手动实现哈希表，C++封装MyHashSet类，Python直接使用内置set。哈希集合的核心是哈希函数设计和冲突处理，链地址法将同一桶中的元素用链表串联，查找时遍历链表即可。', 3600, 1, '请实现一个简单的哈希集合，支持以下三种操作:\n1. add(x) — 向集合中插入元素 x，若已存在则不操作\n2. contains(x) — 判断元素 x 是否在集合中\n3. remove(x) — 从集合中删除元素 x，若不存在则不操作\n\n输入说明:\n第一行输入操作次数 n。\n接下来 n 行，每行格式为 "add x"、"contains x" 或 "remove x"。\n\n输出说明:\n对每个 contains 操作，输出 "true" 或 "false"，每行一个。\n\n样例输入:\n7\nadd 1\nadd 2\ncontains 1\ncontains 3\nadd 2\nremove 1\ncontains 1\n\n样例输出:\ntrue\nfalse\nfalse\n\n备注:\n1 ≤ n ≤ 100000，元素值范围 0 ~ 10^6。', '[{"input":"7\\nadd 1\\nadd 2\\ncontains 1\\ncontains 3\\nadd 2\\nremove 1\\ncontains 1","expectedOutput":"true\\nfalse\\nfalse"},{"input":"5\\nadd 100\\ncontains 100\\nremove 100\\ncontains 100\\ncontains 200","expectedOutput":"true\\nfalse\\nfalse"},{"input":"4\\nadd 0\\nadd 1000000\\ncontains 0\\ncontains 1000000","expectedOutput":"true\\ntrue"},{"input":"6\\nadd 5\\nadd 5\\nadd 5\\nremove 5\\ncontains 5\\nadd 5","expectedOutput":"false"}]');